/**
 * CapEnforcer — manages presentation cap and cooldown state.
 *
 * Isomorphic: works with any RevTurbineStorage backend (InMemoryStorage,
 * BrowserStorage, or a custom RevTurbineStorage).
 *
 * Extracted from customer-side.ts applyPlacementCapsIfNeeded /
 * extractPlacementCapPolicies / presentationCapsByKey.
 */

import type { PlacementOutput } from '../types';
import type { RevTurbineStorage } from './storage';
import type {
  CapEnforcementResult,
  CapPeriod,
  PlacementCapPolicy,
  PlacementCapRule,
  PresentationCapState,
} from './types';

const STORAGE_PREFIX = 'revturbine:presentation-caps';

export interface CapEnforcerOptions {
  storage: RevTurbineStorage;
  tenantId: string;
  userId: string;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function parseCapRule(input: unknown): PlacementCapRule | null {
  if (!isRecord(input)) return null;

  const count = Number(input.count);
  const period = typeof input.period === 'string' ? input.period : '';

  if (!Number.isFinite(count) || count <= 0) return null;
  if (
    period !== 'session' &&
    period !== 'day' &&
    period !== 'week' &&
    period !== 'month' &&
    period !== 'lifetime'
  ) {
    return null;
  }

  return { count, period: period as CapPeriod };
}

function periodWindowStart(period: CapPeriod, nowMs: number): number {
  if (period === 'session' || period === 'lifetime') return 0;
  if (period === 'day') return nowMs - 24 * 60 * 60 * 1000;
  if (period === 'week') return nowMs - 7 * 24 * 60 * 60 * 1000;
  return nowMs - 30 * 24 * 60 * 60 * 1000; // month
}

export class CapEnforcer {
  private readonly storage: RevTurbineStorage;
  private readonly tenantId: string;
  private readonly userId: string;
  private readonly capsByKey = new Map<string, PresentationCapState>();

  constructor(options: CapEnforcerOptions) {
    this.storage = options.storage;
    this.tenantId = options.tenantId;
    this.userId = options.userId;
    this.hydrate();
  }

  /* ---- Public API ---- */

  /**
   * Check whether a placement output is allowed by its cap policies.
   *
   * If allowed, records the presentation (adds seenAt + sets cooldown).
   * If denied, returns the suppression reason.
   */
  enforce(output: PlacementOutput): CapEnforcementResult {
    const policies = this.extractPolicies(output);
    if (policies.length === 0) return { allowed: true };

    const key = this.capKey(output);
    const now = Date.now();
    const existing = this.capsByKey.get(key) ?? { seenAt: [] };
    const state: PresentationCapState = {
      ...existing,
      seenAt: existing.seenAt.filter(ts => Number.isFinite(ts) && ts > 0),
    };

    // Check active cooldown
    if (Number.isFinite(state.cooldownUntil) && (state.cooldownUntil as number) > now) {
      this.capsByKey.set(key, state);
      return { allowed: false, reason: 'suppressed_by_payload_cooldown' };
    }

    // Check cap rules
    for (const policy of policies) {
      for (const rule of policy.rules) {
        const windowStart = periodWindowStart(rule.period, now);
        const withinWindow = state.seenAt.filter(ts => ts >= windowStart && ts <= now);

        if (withinWindow.length >= rule.count) {
          this.capsByKey.set(key, { ...state, seenAt: withinWindow });
          return { allowed: false, reason: `suppressed_by_payload_cap_${rule.period}` };
        }
      }
    }

    // Allowed — record this presentation
    state.seenAt.push(now);

    const cooldowns = policies
      .map(p => p.cooldownMs)
      .filter((v): v is number => typeof v === 'number' && Number.isFinite(v) && v > 0);

    if (cooldowns.length > 0) {
      state.cooldownUntil = now + Math.max(...cooldowns);
    } else {
      delete state.cooldownUntil;
    }

    this.capsByKey.set(key, state);
    this.persist();
    return { allowed: true };
  }

  /* ---- Serialization ---- */

  hydrate(): void {
    const raw = this.storage.getItem(this.storageKey());
    if (!raw) return;

    try {
      const parsed = JSON.parse(raw) as Record<string, PresentationCapState>;
      for (const [key, value] of Object.entries(parsed)) {
        if (!value || typeof value !== 'object') continue;

        const seenAt = Array.isArray(value.seenAt)
          ? value.seenAt.filter((ts): ts is number => Number.isFinite(ts) && ts > 0)
          : [];

        const cooldownUntil = Number.isFinite(value.cooldownUntil)
          ? value.cooldownUntil
          : undefined;

        this.capsByKey.set(key, { seenAt, cooldownUntil });
      }
    } catch {
      this.storage.removeItem(this.storageKey());
    }
  }

  persist(): void {
    try {
      const payload = Object.fromEntries(this.capsByKey.entries());
      this.storage.setItem(this.storageKey(), JSON.stringify(payload));
    } catch {
      // Best-effort persistence
    }
  }

  /* ---- Internal ---- */

  private storageKey(): string {
    return `${STORAGE_PREFIX}:${this.tenantId}:${this.userId}`;
  }

  private capKey(output: PlacementOutput): string {
    return [this.tenantId, this.userId, output.surface.type, output.output_id].join(':');
  }

  private extractPolicies(output: PlacementOutput): PlacementCapPolicy[] {
    const policies: PlacementCapPolicy[] = [];
    const roots: unknown[] = [
      output,
      output.content,
      isRecord(output.content) ? (output.content as Record<string, unknown>).payload : undefined,
      isRecord(output.content) ? (output.content as Record<string, unknown>).placement : undefined,
      isRecord(output.content) ? (output.content as Record<string, unknown>).surface : undefined,
    ];

    for (const root of roots) {
      if (!isRecord(root)) continue;
      const caps = isRecord(root.caps) ? root.caps : undefined;
      if (!caps) continue;

      const rules: PlacementCapRule[] = [];
      const rule = parseCapRule(caps.max_per_period);
      if (rule) rules.push(rule);

      const cooldownDays = Number(caps.cooldown_days);
      const cooldownMs =
        Number.isFinite(cooldownDays) && cooldownDays > 0
          ? cooldownDays * 24 * 60 * 60 * 1000
          : undefined;

      policies.push({
        rules,
        ...(cooldownMs !== undefined ? { cooldownMs } : {}),
      });
    }

    return policies;
  }
}
