/**
 * Experiment schemas — A/B tests, optimization suggestions.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, NameField, HandleField, MetadataField, NullableDatetimeField, SeveritySchema } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Experiment status ────────────────────────────────────────────────────────

export const ExperimentStatusSchema =
  z.enum(['draft', 'ramping', 'winning', 'neutral', 'needs_attention', 'paused', 'complete'])
    .meta({ id: 'ExperimentStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const ExperimentTypeSchema =
  z.enum(['placement_ab', 'entitlement_ab', 'plan_ab', 'pricing_ab', 'custom'])
    .meta({ id: 'ExperimentType', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Experiment variant ───────────────────────────────────────────────────────

export const ExperimentVariantSchema =
  z.object({
    variant_id: z.string().min(1),
    name: NameField,
    weight: z.number().min(0).max(1).default(0.5),
    is_control: z.boolean().default(false),
    config: z.record(z.string(), z.unknown()).default({}),
  })
    .meta({ id: 'ExperimentVariant', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Experiment ───────────────────────────────────────────────────────────────

export const ExperimentSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    description: (z.string().max(1000).optional()).meta(Unrestricted),
    experiment_type: (ExperimentTypeSchema).meta(Unrestricted),
    status: (ExperimentStatusSchema.default('draft')).meta(Unrestricted),
    target_resource_id: (z.string().optional()).meta(Unrestricted),
    target_segment_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    variants: (z.array(ExperimentVariantSchema).min(2)).meta(Unrestricted),
    primary_metric: (z.string().min(1)).meta(Unrestricted),
    secondary_metrics: (z.array(z.string()).default([])).meta(Unrestricted),
    traffic_allocation: (z.number().min(0).max(1).default(1)).meta(Unrestricted),
    started_at: (NullableDatetimeField).meta(Unrestricted),
    ended_at: (NullableDatetimeField).meta(Unrestricted),
    confidence_threshold: (z.number().min(0).max(1).default(0.95)).meta(Unrestricted),
    winning_variant_id: (z.string().nullable().default(null)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Experiment', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Optimization suggestion ──────────────────────────────────────────────────

// SuggestionSeverity re-uses the canonical SeveritySchema from core/common.
export const SuggestionSeveritySchema = SeveritySchema;

export const OptimizationSuggestionSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    experiment_id: (z.string().optional()).meta(Unrestricted),
    resource_type: (z.string().min(1)).meta(Unrestricted),
    resource_id: (z.string().min(1)).meta(Unrestricted),
    severity: (SuggestionSeveritySchema.default('info')).meta(Unrestricted),
    title: (z.string().min(1).max(300)).meta(Unrestricted),
    description: (z.string().max(2000)).meta(Unrestricted),
    suggested_action: (z.string().max(1000).optional()).meta(Unrestricted),
    estimated_impact: (z.number().optional()).meta(Unrestricted),
    is_dismissed: (z.boolean().default(false)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'OptimizationSuggestion', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const experimentPaths: ZodOpenApiPathsObject = {
  '/api/experiments': {
    get: operation({
      operationId: 'listExperiments',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List experiments',
      tags: ['experiments'],
      responses: { '200': { description: 'Experiment list', content: { 'application/json': { schema: ListEnvelope(ExperimentSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createExperiment',
      summary: 'Create experiment',
      tags: ['experiments'],
      requestBody: { required: true, content: { 'application/json': { schema: ExperimentSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'create' } },
    }),
  },
  '/api/experiments/{experimentId}': {
    get: operation({
      operationId: 'getExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Get experiment',
      tags: ['experiments'],
      responses: { '200': { description: 'Experiment', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updateExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Update experiment',
      tags: ['experiments'],
      requestBody: { required: true, content: { 'application/json': { schema: ExperimentSchema.partial() } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deleteExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Delete experiment',
      tags: ['experiments'],
      responses: { '204': { description: 'Deleted' } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'delete' } },
    }),
  },
  '/api/experiments/{experimentId}/start': {
    post: operation({
      operationId: 'startExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Start experiment (begin traffic allocation)',
      tags: ['experiments'],
      responses: { '200': { description: 'Started', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'update' } },
    }),
  },
  '/api/experiments/{experimentId}/pause': {
    post: operation({
      operationId: 'pauseExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Pause running experiment',
      tags: ['experiments'],
      responses: { '200': { description: 'Paused', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'update' } },
    }),
  },
  '/api/experiments/{experimentId}/complete': {
    post: operation({
      operationId: 'completeExperiment',
      requestParams: { path: z.object({ experimentId: z.string() }) },
      summary: 'Complete experiment and declare winner',
      tags: ['experiments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ winning_variant_id: z.string() }) } } },
      responses: { '200': { description: 'Completed', content: { 'application/json': { schema: ExperimentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'experiments', persistence: { table: 'experiments', mode: 'update' } },
    }),
  },
  '/api/optimization-suggestions': {
    get: operation({
      operationId: 'listOptimizationSuggestions',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List optimization suggestions',
      tags: ['experiments'],
      responses: { '200': { description: 'Suggestion list', content: { 'application/json': { schema: ListEnvelope(OptimizationSuggestionSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'optimization-suggestions', persistence: { table: 'optimizationSuggestions', mode: 'list' } },
    }),
  },
  '/api/optimization-suggestions/{suggestionId}/dismiss': {
    post: operation({
      operationId: 'dismissOptimizationSuggestion',
      requestParams: { path: z.object({ suggestionId: z.string() }) },
      summary: 'Dismiss an optimization suggestion',
      tags: ['experiments'],
      responses: { '200': { description: 'Dismissed', content: { 'application/json': { schema: OptimizationSuggestionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'optimization-suggestions', persistence: { table: 'optimizationSuggestions', mode: 'update' } },
    }),
  },
};
