/**
 * User context lifecycle — pure functions for building, merging,
 * and deriving targeting state from user context + ExportedConfig.
 */

import type {
  ExportedConfig,
  UserUsageEntry,
  UserPlanContext,
} from '@revt-eng/schema';
import {
  isRecord,
  usageAmountsFromEntries,
  configuredPlanNameFromExportedConfig,
  type JsonValue,
} from '../../core/helpers';

// ── Types ───────────────────────────────────────────────────────────

/** SDK-facing user context (widened for customer convenience). */
export interface UserContextSnapshot {
  id?: string;
  plan?: string | UserPlanContext;
  custom?: Record<string, JsonValue>;
  entitlements?: Record<string, boolean>;
  usage?: Record<string, UserUsageEntry>;
  personalization?: Record<string, JsonValue>;
}

/** Computed targeting state for segment evaluation and placement resolution. */
export interface TargetingState {
  effectivePlan: string | undefined;
  traits: Record<string, JsonValue>;
  usage: Record<string, number>;
  segmentTraits: Record<string, string | number | boolean>;
}

// ── Pure functions ──────────────────────────────────────────────────

/** Default empty user context. */
export function inferUserContext(): UserContextSnapshot {
  return {
    id: undefined,
    custom: {},
    entitlements: {},
    usage: {},
    personalization: {},
  };
}

/**
 * Deep-merge two user contexts.
 *
 * Sub-objects (custom, entitlements, usage, personalization) are shallowly
 * merged (next wins). Top-level scalars from `next` override `current`.
 */
export function mergeUserContext(
  current: UserContextSnapshot,
  next: Partial<UserContextSnapshot>,
): UserContextSnapshot {
  return {
    ...current,
    ...next,
    custom: {
      ...(current.custom || {}),
      ...(next.custom || {}),
    },
    entitlements: {
      ...(current.entitlements || {}),
      ...(next.entitlements || {}),
    },
    usage: {
      ...(current.usage || {}),
      ...(next.usage || {}),
    },
    personalization: {
      ...(current.personalization || {}),
      ...(next.personalization || {}),
    },
  };
}

/**
 * Narrow trait values to the primitive subset accepted by segment evaluation
 * (string | number | boolean). Non-primitive values are dropped.
 */
export function toSegmentEvaluationTraits(
  traits: Record<string, JsonValue>,
  effectivePlan: string | undefined,
  usage: Record<string, number>,
): Record<string, string | number | boolean> {
  const segmentTraits: Record<string, string | number | boolean> = {};
  for (const [key, value] of Object.entries(traits)) {
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      segmentTraits[key] = value;
    }
  }

  if (effectivePlan && segmentTraits.plan === undefined) {
    segmentTraits.plan = effectivePlan;
  }

  for (const [key, value] of Object.entries(usage)) {
    if (segmentTraits[key] === undefined) {
      segmentTraits[key] = value;
    }
  }

  return segmentTraits;
}

/**
 * Build the full targeting state from a user context snapshot and
 * (optional) ExportedConfig.
 *
 * Derives: effectivePlan, merged traits, usage amounts, and segment
 * evaluation traits — all as a single pure computation.
 */
export function buildTargetingState(
  context: UserContextSnapshot,
  exportedConfig?: ExportedConfig,
  usageOverrides?: Record<string, number>,
): TargetingState {
  const configuredPlanName = configuredPlanNameFromExportedConfig(
    exportedConfig,
    context.plan,
  );
  const effectivePlan = configuredPlanName
    ?? (typeof context.plan === 'object' && context.plan?.id ? context.plan.id : undefined);

  const traits: Record<string, JsonValue> = {
    ...(context.custom ?? {}),
  };

  for (const [key, value] of Object.entries(context.entitlements ?? {})) {
    if (traits[key] === undefined) {
      traits[key] = value;
    }
  }

  if (configuredPlanName && traits.plan_name === undefined) {
    traits.plan_name = configuredPlanName;
  }
  if (effectivePlan && traits.plan === undefined) {
    traits.plan = effectivePlan;
  }

  const usage: Record<string, number> = {
    ...usageAmountsFromEntries(context.usage),
    ...(usageOverrides ?? {}),
  };

  for (const [key, value] of Object.entries(usage)) {
    if (traits[key] === undefined) {
      traits[key] = value;
    }
  }

  return {
    effectivePlan,
    traits,
    usage,
    segmentTraits: toSegmentEvaluationTraits(traits, effectivePlan, usage),
  };
}
