// ── Config versioning fields ─────────────────────────────────────────────────
// Merged into every persisted configuration entity to enable
// environment branching, change-set grouping, and append-only versioning.
//
// id          — unique row identifier (each version is its own row)
// canonical_id — stable identifier for the logical entity across versions
// sequence    — incrementing version counter per (canonical_id, environment_id)
// base_sequence — sequence this change was forked from (enables conflict detection,
//                 analogous to a git parent commit hash)
// is_current  — only one row per (canonical_id, environment_id) may be current
// change_set_id — groups this version into a ChangeSet (null = direct commit)

export const ConfigVersionFields =
  z.object({
    environment_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    canonical_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    change_set_id: (z.string().nullable().default(null)).meta(Unrestricted),
    is_current: (z.boolean().default(true)).meta({ ...Unrestricted, readOnly: true }),
    sequence: (z.number().int().min(1).default(1)).meta({ ...Unrestricted, readOnly: true }),
    base_sequence: (z.number().int().min(0).nullable().default(null)).meta(Unrestricted),
  })
    .meta({
      id: 'null',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

