// ── Reusable field patterns ──────────────────────────────────────────────────
// Extracted from repeated inline definitions across domain schemas.
// Use these instead of writing the raw Zod expression inline.

/** Entity display name: `z.string().min(1).max(200)` */
export const NameField = z.string().min(1).max(200);

/** Unique handle / slug: `z.string().min(1).max(100)` */
export const HandleField = z.string().min(1).max(100);

/** Optional description: `z.string().max(500).optional()` */
export const DescriptionField = z.string().max(500).optional();

/** Extensible metadata bag: `z.record(z.string(), z.unknown()).default({})` */
export const MetadataField = z.record(z.string(), z.unknown()).default({});

/** Nullable datetime with null default: `z.string().datetime().nullable().default(null)` */
export const NullableDatetimeField = z.string().datetime().nullable().default(null);

/** Severity level for alerts, drift reports, and suggestions. */
