/**
 * Entitlement rule evaluation — matches rules against plan + segment context.
 *
 * Extracted from customer-side.ts for isomorphic use.
 */

import type { EntitlementRuleSnapshot, PlanRuleSnapshot, RuleProviderState } from '../../core/providers/types';

export interface RuleEvaluationContext {
  /** Current plan ID (not handle). */
  currentPlanId?: string;
  /** Matched segment IDs for the user. */
  segmentIds: string[];
}

export interface EntitlementRuleEvaluation {
  rule: EntitlementRuleSnapshot;
  matchesPlan: boolean;
  matchesSegment: boolean;
  matched: boolean;
}

/**
 * Evaluate entitlement rules for a given entitlement against plan and segment context.
 *
 * A rule matches when:
 * - planIds is empty (applies to all plans) OR currentPlanId is in planIds
 * - segmentId is undefined (applies to all segments) OR segmentId is in the user's segments
 */
export function evaluateEntitlementRules(
  rules: EntitlementRuleSnapshot[],
  context: RuleEvaluationContext,
): EntitlementRuleEvaluation[] {
  return rules.map(rule => {
    const matchesPlan =
      rule.planIds.length === 0 ||
      (context.currentPlanId != null && rule.planIds.includes(context.currentPlanId));

    const matchesSegment =
      rule.segmentId == null ||
      context.segmentIds.includes(rule.segmentId);

    return {
      rule,
      matchesPlan,
      matchesSegment,
      matched: matchesPlan && matchesSegment,
    };
  });
}

/**
 * Evaluate plan rules for a specific plan.
 *
 * Returns the active rules matching the given segment context.
 */
export function evaluatePlanRules(
  rules: PlanRuleSnapshot[],
  context: RuleEvaluationContext,
): PlanRuleSnapshot[] {
  return rules.filter(rule => {
    if (rule.status !== 'active') return false;
    if (rule.segmentId == null) return true;
    return context.segmentIds.includes(rule.segmentId);
  });
}

/**
 * Find the best matching entitlement rule for a given entitlement handle.
 *
 * Returns the first matched rule for the entitlement, or undefined if no rules match.
 */
export function findMatchingEntitlementRule(
  ruleState: RuleProviderState,
  entitlementId: string,
  context: RuleEvaluationContext,
): EntitlementRuleSnapshot | undefined {
  const rules = ruleState.entitlementRules[entitlementId];
  if (!rules || rules.length === 0) return undefined;

  const evaluations = evaluateEntitlementRules(rules, context);
  const matched = evaluations.find(e => e.matched);
  return matched?.rule;
}
