/**
 * Static adapter — creates domain providers from an ExportedConfig snapshot.
 *
 * Works everywhere: edge, server, client. No network calls, no database access.
 * Ideal for:
 * - Edge functions receiving config from a KV store
 * - Server-side rendering with a pre-fetched config
 * - Client-side after hydration from server
 * - Local development / testing
 */

import type { ExportedConfig, ExportedConfigSegmentsItem, MessageBlock } from '@revt-eng/schema';
import type {
  AnyDomainProvider,
  ContentProviderState,
  EntitlementProviderState,
  PlanProviderState,
  RuleProviderState,
  SegmentProviderState,
  ThemeProviderState,
  EntitlementRuleSnapshot,
} from '../providers/types';
import type { EntitlementResult } from '../types';
import type { AdapterBaseOptions } from './types';

export interface StaticAdapterOptions extends AdapterBaseOptions {
  /** The ExportedConfig snapshot to build providers from. */
  config: ExportedConfig;
  /** Current plan handle for the user. */
  planHandle?: string;
  /** Current plan name for the user. */
  planName?: string;
  /** Usage overrides by entitlement handle. */
  usage?: Record<string, { used: number; limit: number }>;
  /** Default entitlement policy. Default: 'allow'. */
  defaultEntitlementPolicy?: 'allow' | 'deny';
}

/**
 * Create domain providers from a static ExportedConfig snapshot.
 *
 * Returns providers for: plan, entitlements, segments, rules, content, theme.
 */
export function createStaticProviders(options: StaticAdapterOptions): AnyDomainProvider[] {
  const { config, cacheTtlMs } = options;
  const providers: AnyDomainProvider[] = [];

  // Plan provider
  if (options.planHandle) {
    const planProvider: AnyDomainProvider = {
      domain: 'plan' as const,
      cacheTtlMs,
      resolve: (): PlanProviderState => ({
        currentPlanHandle: options.planHandle!,
        currentPlanName: options.planName ?? options.planHandle,
      }),
    };
    providers.push(planProvider);
  }

  // Entitlements provider
  if (config.entitlements?.length) {
    const policy = options.defaultEntitlementPolicy ?? 'allow';
    const entitlementProvider: AnyDomainProvider = {
      domain: 'entitlements' as const,
      cacheTtlMs,
      resolve: (): EntitlementProviderState => {
        const entries: Record<string, EntitlementResult> = {};
        const usage: Record<string, { used: number; limit: number; remaining: number; unit?: string }> = {};

        for (const ent of config.entitlements ?? []) {
          entries[ent.unique_handle] = {
            status: policy === 'allow' ? 'allowed' : 'denied',
            allowed: policy === 'allow',
            reason: `static_config_default_${policy}`,
          } as EntitlementResult;

          const usageOverride = options.usage?.[ent.unique_handle];
          if (usageOverride) {
            usage[ent.unique_handle] = {
              used: usageOverride.used,
              limit: usageOverride.limit,
              remaining: Math.max(0, usageOverride.limit - usageOverride.used),
              unit: ent.unit,
            };
          }
        }

        return { entries, usage };
      },
    };
    providers.push(entitlementProvider);
  }

  // Segments provider
  if (config.segments?.length) {
    const segmentProvider: AnyDomainProvider = {
      domain: 'segments' as const,
      cacheTtlMs,
      resolve: (): SegmentProviderState => ({
        segmentIds: (config.segments ?? []).map((s: ExportedConfigSegmentsItem) => s.id),
        segmentSlugs: (config.segments ?? []).map((s: ExportedConfigSegmentsItem) => s.slug),
      }),
    };
    providers.push(segmentProvider);
  }

  // Rules provider
  if (config.entitlement_rules?.length) {
    const ruleProvider: AnyDomainProvider = {
      domain: 'rules' as const,
      cacheTtlMs,
      resolve: (): RuleProviderState => {
        const entitlementRules: Record<string, EntitlementRuleSnapshot[]> = {};

        for (const rule of config.entitlement_rules ?? []) {
          const entId = rule.entitlement_id;
          if (!entitlementRules[entId]) entitlementRules[entId] = [];
          entitlementRules[entId].push({
            ruleId: rule.id,
            entitlementId: entId,
            planIds: rule.plan_ids ?? [],
            segmentId: rule.segment_id ?? undefined,
            kind: (rule.type_fields as Record<string, unknown>)?.kind as EntitlementRuleSnapshot['kind'] ?? 'feature',
            fields: (rule.type_fields as Record<string, unknown>) ?? {},
          });
        }

        return {
          entitlementRules,
          configVersion: config.version,
        };
      },
    };
    providers.push(ruleProvider);
  }

  // Content provider
  if (config.message_blocks?.length || config.personalization_tokens?.length) {
    const contentProvider: AnyDomainProvider = {
      domain: 'content' as const,
      cacheTtlMs,
      resolve: (): ContentProviderState => {
        const messageBlocks: ContentProviderState['messageBlocks'] = {};
        for (const block of config.message_blocks ?? []) {
          messageBlocks[block.block_id] = {
            blockId: block.block_id,
            name: block.name,
            defaultContent: block.default_content,
            segmentOverrides: block.segment_overrides?.map((o: NonNullable<MessageBlock['segment_overrides']>[number]) => ({
              segmentId: o.segment_value_id,
              content: o.content,
            })),
            status: block.status as 'draft' | 'active' | 'archived',
          };
        }

        return {
          messageBlocks,
          personalization: {},
        };
      },
    };
    providers.push(contentProvider);
  }

  // Theme provider
  if (config.theme && Object.keys(config.theme).length > 0) {
    const themeProvider: AnyDomainProvider = {
      domain: 'theme' as const,
      cacheTtlMs,
      resolve: (): ThemeProviderState => ({
        overrides: config.theme as Record<string, unknown>,
      }),
    };
    providers.push(themeProvider);
  }

  return providers;
}
