/**
 * Runtime environment detection for the RevTurbine SDK core.
 *
 * These helpers allow the SDK to adapt behavior based on whether
 * it is running in a browser or server (Node.js / edge / SSR) context.
 */

/** Returns `true` when running in a server-side environment (Node.js, edge, SSR, etc.). */
export function isServer(): boolean {
  return typeof window === 'undefined' || typeof document === 'undefined';
}

/** Returns `true` when running in a browser environment. */
export function isBrowser(): boolean {
  return !isServer();
}
