/**
 * Segment evaluation — predicate-based segment membership resolution.
 *
 * Segments are composed of predicates that target traits on a user
 * context/profile. A segment matches when ALL of its predicates are
 * satisfied (AND logic).
 *
 * Supported predicate operators:
 *   - `eq`       — string equality
 *   - `neq`      — string inequality
 *   - `gt/lt/gte/lte` — numeric comparison
 *   - `contains` — substring / list-item match
 *   - `in`       — trait value appears in comma-separated accepted list
 */

import type {
  ExportedConfigSegmentsItem,
  ExportedConfigSegmentsItemPredicatesItem,
} from '@revt-eng/schema';

export type { ExportedConfigSegmentsItem, ExportedConfigSegmentsItemPredicatesItem };

/**
 * Flat key-value traits record used for segment predicate evaluation.
 */
export type Trait = Record<string, string | number | boolean>;

function evaluatePredicate(
  predicate: ExportedConfigSegmentsItemPredicatesItem,
  traits: Trait,
): boolean {
  const rawValue = traits[predicate.field];
  if (rawValue === undefined) return false;

  const traitStr = String(rawValue);
  const targetStr = predicate.value;

  switch (predicate.operator) {
    case 'eq':
      return traitStr === targetStr;
    case 'neq':
      return traitStr !== targetStr;
    case 'gt':
      return Number(traitStr) > Number(targetStr);
    case 'lt':
      return Number(traitStr) < Number(targetStr);
    case 'gte':
      return Number(traitStr) >= Number(targetStr);
    case 'lte':
      return Number(traitStr) <= Number(targetStr);
    case 'contains':
      return traitStr.includes(targetStr);
    case 'in': {
      const accepted = targetStr.split(',').map((s: string) => s.trim());
      return accepted.includes(traitStr);
    }
    default:
      return false;
  }
}

/**
 * Evaluate segment definitions against a user's traits.
 *
 * Returns the IDs of every segment whose predicates ALL match (AND logic).
 * Segments with no predicates are skipped.
 */
export function evaluateSegments(
  segments: ExportedConfigSegmentsItem[],
  traits: Trait,
): string[] {
  return segments
    .filter(segment => {
      if (!segment.predicates || segment.predicates.length === 0) return false;
      return segment.predicates.every((p: ExportedConfigSegmentsItemPredicatesItem) => evaluatePredicate(p, traits));
    })
    .map(segment => segment.id);
}

// ── Verbose / diagnostic evaluation ──────────────────────────────────────────

/**
 * Result of evaluating a single segment predicate with diagnostic detail.
 */
export interface PredicateEvaluationResult {
  field: string;
  operator: string;
  expected: string;
  actual: string | number | boolean | null;
  matched: boolean;
}

/**
 * Evaluate a single predicate and return diagnostic detail (field, operator,
 * expected/actual values, and match result).
 *
 * This is the verbose counterpart of the internal `evaluatePredicate()`.
 * Used by SDKs for segment evaluation explainability.
 */
export function evaluatePredicateVerbose(
  predicate: ExportedConfigSegmentsItemPredicatesItem,
  traits: Trait,
): PredicateEvaluationResult {
  const field = String(predicate.field || '');
  const operator = String(predicate.operator || '');
  const expected = String(predicate.value || '');
  const rawActual = traits[field];
  const actual: string | number | boolean | null =
    (typeof rawActual === 'string' || typeof rawActual === 'number' || typeof rawActual === 'boolean')
      ? rawActual
      : null;
  const matched = evaluatePredicate(predicate, traits);

  return { field, operator, expected, actual, matched };
}
