/**
 * Static placement resolver — builds a PlacementResolver from a static dataset.
 *
 * Moved from web-sdk/placements/local-resolver.ts for isomorphic use.
 */

import type { ExportedConfig } from '@revt-eng/schema';
import type { ResolvedProviderContext } from '../../core/providers/types';
import type { ImpressionHistory } from '../../core/state/impression-history';
import type {
  PlacementOutput,
  PlacementResolver,
  RevTurbinePlacementDecision,
  RevTurbinePlacementDecisionInput,
  RevTurbinePlacementRecord,
  RevTurbineSurfaceType,
} from '../../core/types';

export interface LocalPlacementDataset {
  placements: LocalPlacementEntry[];
}

export type LocalPlacementEntry = NonNullable<ExportedConfig['placements']>[number];
export type LocalPlacementPayload = LocalPlacementEntry['payloads'][number];
export type LocalPlacementSurface = LocalPlacementPayload['surfaces'][number];

function readEntitlementHandleFromTrigger(trigger: LocalPlacementEntry['trigger'] | undefined): string | undefined {
  if (!trigger || typeof trigger !== 'object' || !('entitlement_handle' in trigger)) {
    return undefined;
  }
  const value = trigger.entitlement_handle;
  return typeof value === 'string' ? value : undefined;
}

function readSlotIdFromTrigger(trigger: LocalPlacementEntry['trigger'] | undefined): string | undefined {
  if (!trigger || typeof trigger !== 'object' || !('slot_id' in trigger)) {
    return undefined;
  }
  const value = trigger.slot_id;
  return typeof value === 'string' ? value : undefined;
}

export interface StaticPlacementResolverOptions {
  placements: LocalPlacementDataset;
  exportedConfig: ExportedConfig;
  /** Optional impression history — if provided, retired placements are filtered out. */
  impressionHistory?: ImpressionHistory;
}

const DEFAULT_TEMPLATE_TO_SURFACE: Record<string, RevTurbineSurfaceType> = {
  modal_overlay: 'modal',
  banner_placement: 'banner',
  in_page_card: 'in_page',
  inline_gate_message: 'in_page',
  usage_counter: 'in_page',
  button: 'button',
  email: 'email',
  full_page: 'full_page',
};

function interpolateStringTokens(template: string, tokens: Record<string, unknown>): string {
  return template.replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_, key: string) => {
    const value = tokens[key];
    return value === undefined || value === null ? `{{${key}}}` : String(value);
  });
}

function interpolateContentTokens(content: Record<string, unknown>): Record<string, unknown> {
  const resolved: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(content)) {
    if (typeof value === 'string') {
      resolved[key] = interpolateStringTokens(value, content);
      continue;
    }
    resolved[key] = value;
  }
  return resolved;
}

function normalizeCtaPath(cta?: { path?: string; config?: Record<string, unknown> }): Record<string, unknown> {
  if (!cta?.path) return { type: 'dismiss' };

  const rawPath = cta.path;
  const config = cta.config ?? {};

  if (rawPath === 'open_checkout') {
    return {
      type: 'open_checkout_modal',
      plan_handle: typeof config.purchase === 'string' ? config.purchase : undefined,
    };
  }

  if (rawPath === 'view_plans') {
    return { type: 'navigate_to_plans' };
  }

  if (rawPath === 'custom') {
    const handle = typeof config.handle === 'string' ? config.handle : undefined;
    return {
      type: 'custom_url',
      url: handle ? `/help/${handle}` : '/help',
    };
  }

  if (rawPath === 'snooze_remind_later') {
    return { type: 'dismiss' };
  }

  if (rawPath === 'open_rt_placement') {
    return {
      type: 'open_rt_placement',
      placement_handle: typeof config.placement_handle === 'string' ? config.placement_handle : undefined,
    };
  }

  return { type: rawPath, ...config };
}

/**
 * Create a placement resolver from a static dataset.
 *
 * Supports:
 * - plan-target filtering from payload targets
 * - token interpolation from payload content
 * - usage token injection from resolved provider context
 * - suppression of upsell/trial-conversion categories for enterprise plans
 */
export function createStaticPlacementResolver({
  placements,
  exportedConfig,
  impressionHistory,
}: StaticPlacementResolverOptions): PlacementResolver {
  const templateToSurface: Record<string, RevTurbineSurfaceType> = {
    ...DEFAULT_TEMPLATE_TO_SURFACE,
  };

  for (const template of exportedConfig.surface_templates ?? []) {
    templateToSurface[template.id] = template.surface_type as RevTurbineSurfaceType;
  }

  const planHandleToId = new Map<string, string>();
  for (const plan of exportedConfig.plans ?? []) {
    planHandleToId.set(plan.unique_handle, plan.id);
  }

  // ── Index: template_id → candidate outputs (sorted by entry order) ───
  interface CandidateOutput {
    output: PlacementOutput;
    entryOrder: number;
    entryCategory: string;
    triggerEntitlementHandle: string | undefined;
    /** For surface_render triggers — the specific slot ID this placement targets. */
    triggerSlotId: string | undefined;
  }

  const outputsByTemplate = new Map<string, CandidateOutput[]>();
  const outputsByName = new Map<string, PlacementOutput>();

  for (const entry of placements.placements) {
    const payload = entry.payloads.find((p: LocalPlacementPayload) => p.status === 'active');
    if (!payload) continue;

    const surface = payload.surfaces[0];
    if (!surface) continue;

    const templateId = surface.template_id;
    const surfaceType = templateToSurface[templateId] ?? 'custom';

    const content: Record<string, unknown> = { ...surface.fields };
    if (surface.ctas?.[0]) {
      content.cta_label = surface.ctas[0].label;
    }
    if (surface.ctas?.[1]) {
      content.secondary_cta_label = surface.ctas[1].label;
    }

    const ctaPath = normalizeCtaPath(surface.ctas?.[0]);

    const output: PlacementOutput = {
      output_id: payload.id,
      category: entry.category,
      surface: {
        template: templateId,
        type: surfaceType,
        slot_id: entry.id,
      },
      content,
      cta_path: ctaPath,
      rule_id: entry.id,
      decision_id: payload.id,
      config_version: exportedConfig.version,
      present_upsell: true,
    };

    if (payload.target) {
      output.content = {
        ...output.content,
        __target_plan_ids: Array.isArray(payload.target.plan_ids) ? payload.target.plan_ids : [],
      };
    }

    const triggerEntitlementHandle = readEntitlementHandleFromTrigger(entry.trigger);
    if (triggerEntitlementHandle) {
      output.content = {
        ...output.content,
        __trigger_entitlement_handle: triggerEntitlementHandle,
      };
    }

    const triggerSlotId = readSlotIdFromTrigger(entry.trigger);

    // Index by surface template for candidate-based lookup.
    const bucket = outputsByTemplate.get(templateId) ?? [];
    bucket.push({ output, entryOrder: entry.order ?? 0, entryCategory: entry.category, triggerEntitlementHandle, triggerSlotId });
    outputsByTemplate.set(templateId, bucket);

    // Index by name / id for backward-compatible direct lookups.
    const shortName = entry.id.replace(/^pl_/, '');
    outputsByName.set(shortName, output);
    outputsByName.set(entry.id, output);
  }

  // Sort each template bucket by entry order (lower = higher priority).
  for (const bucket of outputsByTemplate.values()) {
    bucket.sort((a, b) => a.entryOrder - b.entryOrder);
  }

  // ── Eligibility helpers ────────────────────────────────────────────────

  function isEligibleForPlan(
    output: PlacementOutput,
    currentPlanId: string | undefined,
    planHandle: string | undefined,
    billingPeriod?: string,
  ): boolean {
    const targetPlanIds = Array.isArray(output.content.__target_plan_ids)
      ? (output.content.__target_plan_ids as unknown[]).filter(
          (item): item is string => typeof item === 'string',
        )
      : [];

    // If a target list exists and the user's plan is NOT in it → ineligible.
    if (targetPlanIds.length > 0 && currentPlanId && !targetPlanIds.includes(currentPlanId)) {
      return false;
    }

    // Billing cadence filter: if the output targets specific billing periods and
    // the user's billing period is not in the list → ineligible.
    const targetBillingPeriods = Array.isArray(output.content.__target_billing_periods)
      ? (output.content.__target_billing_periods as unknown[]).filter(
          (item): item is string => typeof item === 'string',
        )
      : [];
    if (targetBillingPeriods.length > 0 && billingPeriod && !targetBillingPeriods.includes(billingPeriod)) {
      return false;
    }

    // Suppress upsell / trial-conversion for enterprise plans.
    const isUpsell = output.category === 'upsell' || output.category === 'trial_conversion';
    if (isUpsell && planHandle === 'enterprise') {
      return false;
    }

    return true;
  }

  // ── Resolve function ───────────────────────────────────────────────────

  return async (
    input: RevTurbinePlacementDecisionInput,
    placement?: RevTurbinePlacementRecord,
    context?: Record<string, unknown>,
  ): Promise<RevTurbinePlacementDecision> => {
    const providers = context?.__providers as ResolvedProviderContext | undefined;
    const planHandle = providers?.plan?.currentPlanHandle;
    const billingPeriod = providers?.plan?.billingPeriod;
    const currentPlanId = planHandle ? planHandleToId.get(planHandle) : undefined;
    const headerStr = (h: unknown) => (typeof h === 'string' ? h : '');

    // ── Collect candidates by surfaceTemplateIds ─────────────────────────
    const allowedTemplateIds = Array.isArray(placement?.metadata?.surface_template_ids)
      ? (placement!.metadata!.surface_template_ids as string[])
      : undefined;

    let selectedOutput: PlacementOutput | undefined;
    let reasonCodes: string[] = [];

    if (allowedTemplateIds && allowedTemplateIds.length > 0) {
      // Gather all candidates whose template matches the slot's accepted list.
      const candidates: CandidateOutput[] = [];
      for (const tid of allowedTemplateIds) {
        const bucket = outputsByTemplate.get(tid);
        if (bucket) candidates.push(...bucket);
      }

      if (candidates.length === 0) {
        return {
          placementId: input.placementId,
          requestId: `local_${Date.now()}`,
          visible: false,
          decisionSource: 'fallback',
          reasonCodes: ['no_candidates_for_template'],
          content: {
            header: 'No placements configured for this surface template',
            body: '',
            cta_label: '',
            title: 'No placements configured for this surface template',
            cta: '',
          },
        };
      }

      // Re-sort across template buckets in case multiple templates contributed.
      candidates.sort((a, b) => a.entryOrder - b.entryOrder);

      // ── Narrow candidates using slot metadata hints ──────────────────
      const slotEntitlementHandle = placement?.metadata?.entitlement_handle as string | undefined;
      const slotCategory = placement?.metadata?.surface_slot_category as string | undefined;

      // Map SurfaceSlot category → expected placement config categories.
      const categoryMap: Record<string, string[]> = {
        gated: ['gated'],
        fixed: ['fixed'],
        triggered: ['usage_credit_seat', 'trials', 'other_conversion', 'retention'],
      };
      const preferredCategories = slotCategory ? categoryMap[slotCategory] : undefined;

      // If an entitlement handle hint is provided, prefer exact matches.
      let filtered = candidates;
      if (slotEntitlementHandle) {
        const entFiltered = candidates.filter(
          c => c.triggerEntitlementHandle === slotEntitlementHandle,
        );
        if (entFiltered.length > 0) filtered = entFiltered;
      }

      // Fixed slots only display placements that explicitly target them by slot ID.
      // When a surface_slot_id is present (even without a category), prefer
      // candidates whose trigger slot_id matches — this ensures slot-targeted
      // placements are selected over other template-compatible placements.
      const slotId = placement?.metadata?.surface_slot_id as string | undefined;
      if (slotId) {
        const slotFiltered = filtered.filter(c => c.triggerSlotId === slotId);
        if (slotFiltered.length > 0) filtered = slotFiltered;
      }

      // If a category hint is available (and no entitlement filter narrowed it),
      // prefer candidates whose config category is in the expected set.
      // Fixed slots already filtered by slot ID above — skip category narrowing.
      if (preferredCategories && slotCategory !== 'fixed' && filtered.length > 1) {
        const catFiltered = filtered.filter(
          c => preferredCategories.includes(c.entryCategory),
        );
        if (catFiltered.length > 0) filtered = catFiltered;
      }

      // Filter out retired placements (dismissed/clicked) and time-suppressed placements.
      if (impressionHistory) {
        filtered = filtered.filter(
          c => !impressionHistory.isHiddenSync(c.output.rule_id ?? ''),
        );
      }

      // Pick the first eligible candidate.
      for (const candidate of filtered) {
        if (isEligibleForPlan(candidate.output, currentPlanId, planHandle, billingPeriod)) {
          selectedOutput = candidate.output;
          break;
        }
      }

      if (!selectedOutput) {
        reasonCodes = ['no_eligible_candidate'];
      }
    } else {
      // Fallback: direct name-based lookup (backward compat).
      const name = placement?.name;
      const directOutput = name ? outputsByName.get(name) : undefined;
      if (directOutput && impressionHistory?.isHiddenSync(directOutput.rule_id ?? '')) {
        reasonCodes = ['placement_retired'];
      } else if (directOutput && isEligibleForPlan(directOutput, currentPlanId, planHandle, billingPeriod)) {
        selectedOutput = directOutput;
      } else if (directOutput) {
        reasonCodes = ['plan_target_mismatch'];
      } else {
        reasonCodes = ['placement_not_found'];
      }
    }

    if (!selectedOutput) {
      const code = reasonCodes[0] ?? 'placement_not_found';
      return {
        placementId: input.placementId,
        requestId: `local_${Date.now()}`,
        visible: false,
        decisionSource: 'fallback',
        reasonCodes: [code],
        content: {
          header: 'Placement not configured',
          body: '',
          cta_label: '',
          title: 'Placement not configured',
          cta: '',
        },
      };
    }

    // ── Enrich with usage data & interpolation ───────────────────────────
    const outputContent = { ...selectedOutput.content };

    const entitlementHandle = typeof outputContent.entitlement === 'string'
      ? outputContent.entitlement
      : typeof outputContent.__trigger_entitlement_handle === 'string'
        ? outputContent.__trigger_entitlement_handle
        : undefined;
    const usageEntry = entitlementHandle
      ? providers?.entitlements?.usage?.[entitlementHandle]
      : undefined;

    if (usageEntry) {
      outputContent.usage_remaining = Number.isFinite(usageEntry.remaining) ? usageEntry.remaining : 0;
      outputContent.usage_limit = Number.isFinite(usageEntry.limit) ? usageEntry.limit : 0;
      outputContent.usage_current = Number.isFinite(usageEntry.used) ? usageEntry.used : 0;
      outputContent.usage_percent = usageEntry.limit > 0
        ? Math.min(100, Math.round((usageEntry.used / usageEntry.limit) * 100))
        : 0;
      if (typeof usageEntry.reset_date === 'string' && usageEntry.reset_date.length > 0) {
        outputContent.reset_date = usageEntry.reset_date;
      }
    }

    const interpolatedContent = interpolateContentTokens(outputContent);

    const resolvedOutput: PlacementOutput = {
      ...selectedOutput,
      content: interpolatedContent,
    };

    const isUpsell = selectedOutput.category === 'upsell' || selectedOutput.category === 'trial_conversion';
    const isEnterprise = planHandle === 'enterprise';
    const visible = !(isUpsell && isEnterprise);

    return {
      placementId: input.placementId,
      requestId: `local_${Date.now()}`,
      visible,
      decisionSource: 'fallback',
      reasonCodes: visible ? [] : ['plan_tier_suppressed'],
      content: {
        header: headerStr(resolvedOutput.content.header),
        body: headerStr(resolvedOutput.content.body),
        cta_label: headerStr(resolvedOutput.content.cta_label),
        title: headerStr(resolvedOutput.content.header),
        cta: headerStr(resolvedOutput.content.cta_label),
      },
      output: resolvedOutput,
    };
  };
}
