import { z } from 'zod';
import type { ZodOpenApiOperationObject, ZodOpenApiPathsObject } from 'zod-openapi';

export type { ZodOpenApiOperationObject, ZodOpenApiPathsObject };

export const ListEnvelope = <T extends z.ZodTypeAny>(itemSchema: T) =>
  z.object({
    items: z.array(itemSchema),
  });

export const ErrorEnvelope = z.object({
  error: z.string(),
  code: z.string(),
  request_id: z.string(),
});

export const operation = (op: ZodOpenApiOperationObject): ZodOpenApiOperationObject => op;

export const ListQueryParamsSchema = z.object({
  page: z.number().int().min(1).default(1).optional(),
  per_page: z.number().int().min(1).max(100).default(25).optional(),
  sort: z.string().optional(),
  order: z.enum(['asc', 'desc']).default('asc').optional(),
  include_deleted: z.boolean().default(false).optional(),
});
