/**
 * Payload resolution — content lookup and personalization token application.
 *
 * Moved from web-sdk/placements/payload-resolution.ts for isomorphic use.
 */

import type {
  ContentPromotion,
  ContentUiPath,
  ContentPlacementPayload,
  MessageBlock,
  PersonalizationToken,
} from '@revt-eng/schema';
import type { PersonalizationContext, ResolvedContent, UserTargetingContext } from '../../core/types';

export type { ContentPromotion, ContentUiPath, ContentPlacementPayload, MessageBlock, PersonalizationToken };

export interface ResolvedPayload {
  payload: ContentPlacementPayload;
  messageBlock: MessageBlock;
  resolvedContent: ResolvedContent;
  matchedSegmentId?: string;
  uiPathId?: string;
  promotionId?: string;
  uiPath?: ContentUiPath;
  promotion?: ContentPromotion;
}

export interface PlacementContentLookupProvider {
  listPayloads(surfaceTemplateId: string): ContentPlacementPayload[] | Promise<ContentPlacementPayload[]>;
  getMessageBlockById(blockId: string): MessageBlock | null | undefined | Promise<MessageBlock | null | undefined>;
  getUiPathById?(uiPathId: string): ContentUiPath | null | undefined | Promise<ContentUiPath | null | undefined>;
  getPromotionById?(promotionId: string): ContentPromotion | null | undefined | Promise<ContentPromotion | null | undefined>;
  listPersonalizationTokens?(): PersonalizationToken[] | Promise<PersonalizationToken[]>;
}

export function createStaticPlacementContentLookupProvider(input: {
  payloads?: ContentPlacementPayload[];
  messageBlocks?: MessageBlock[];
  uiPaths?: ContentUiPath[];
  promotions?: ContentPromotion[];
  tokens?: PersonalizationToken[];
}): PlacementContentLookupProvider {
  const payloads = Array.isArray(input.payloads) ? input.payloads : [];
  const blockMap = new Map((Array.isArray(input.messageBlocks) ? input.messageBlocks : []).map(b => [b.block_id, b]));
  const uiPaths = Array.isArray(input.uiPaths) ? input.uiPaths : [];
  const promotions = Array.isArray(input.promotions) ? input.promotions : [];
  const tokens = Array.isArray(input.tokens) ? input.tokens : [];

  return {
    listPayloads: (surfaceTemplateId: string) => payloads.filter(p => p.surface_template_id === surfaceTemplateId),
    getMessageBlockById: (blockId: string) => blockMap.get(blockId),
    getUiPathById: (uiPathId: string) => uiPaths.find(item => {
      const candidateId = (item as unknown as { id?: string }).id;
      return candidateId === uiPathId || item.name === uiPathId;
    }),
    getPromotionById: (promotionId: string) => promotions.find(item => {
      const candidateId = (item as unknown as { id?: string }).id;
      return candidateId === promotionId || item.name === promotionId;
    }),
    listPersonalizationTokens: () => tokens,
  };
}

export function applyValueMaps(
  context: PersonalizationContext,
  tokens: PersonalizationToken[],
): PersonalizationContext {
  const enhanced: PersonalizationContext = { ...context };

  for (const tokenDef of tokens) {
    const rawValue = context[tokenDef.token];
    if (rawValue == null || !tokenDef.value_map) continue;

    const rawStr = String(rawValue);
    const mapped = tokenDef.value_map[rawStr];
    if (mapped !== undefined) {
      enhanced[tokenDef.token] = mapped;
    }
  }

  return enhanced;
}

/**
 * Resolve personalization tokens in a string. Tokens use `{{token_name}}` syntax.
 */
export function resolveTokens(template: string, context: PersonalizationContext): string {
  const TOKEN_ALIASES: Record<string, string> = {
    current_usage: 'usage_current',
    current_limit: 'usage_limit',
    remaining_usage: 'usage_remaining',
  };

  return template.replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (match, key: string) => {
    let value = context[key];
    if (value === undefined) {
      const aliasKey = TOKEN_ALIASES[key];
      if (aliasKey) value = context[aliasKey];
    }
    if (value === undefined) return match;
    return String(value);
  });
}

/**
 * Resolve all token placeholders in a content record.
 */
export function resolveContent(content: Record<string, unknown>, context: PersonalizationContext): ResolvedContent {
  const resolved: ResolvedContent = {};
  for (const [key, value] of Object.entries(content)) {
    if (typeof value === 'string') {
      resolved[key] = resolveTokens(value, context);
    } else {
      resolved[key] = value;
    }
  }
  return resolved;
}

function resolveBlockContent(
  content: Record<string, unknown>,
  context: PersonalizationContext,
): ResolvedContent {
  return resolveContent(content, context);
}

export interface PayloadResolutionOptions {
  /**
   * When provided, enables cross-dimension AND logic for segment matching.
   * Map of dimension name → segment IDs belonging to that dimension.
   * Intra-dimension: OR (any segment matches). Cross-dimension: AND (all dimensions must match).
   */
  segmentDimensions?: Record<string, string[]>;
}

export function resolvePayloadForUser(
  surfaceTemplateId: string,
  userContext: UserTargetingContext,
  payloads: ContentPlacementPayload[],
  blocks: MessageBlock[],
  tokens: PersonalizationToken[],
  personalization: PersonalizationContext,
  options?: PayloadResolutionOptions,
): ResolvedPayload | null {
  const candidates = payloads.filter(
    p => p.surface_template_id === surfaceTemplateId && p.status === 'active',
  );
  if (candidates.length === 0) return null;

  const blockMap = new Map(blocks.map(b => [b.block_id, b]));
  const userSegmentSet = new Set(userContext.segmentIds);
  const enhancedContext = applyValueMaps(personalization, tokens);
  const segmentDimensions = options?.segmentDimensions;

  for (const payload of candidates) {
    let matchedBlockId = payload.default_message_block_id;
    let matchedSegmentId: string | undefined;
    let uiPathId = payload.ui_path_id;
    let promotionId = payload.promotion_id;

    if (payload.segment_content_map) {
      if (segmentDimensions && Object.keys(segmentDimensions).length > 0) {
        // Cross-dimension AND: user must match at least one segment per dimension
        const entriesByDimension = new Map<string, typeof payload.segment_content_map>();
        for (const entry of payload.segment_content_map) {
          const dim = (entry as Record<string, unknown>).dimension as string | undefined;
          if (!dim) continue;
          const list = entriesByDimension.get(dim) ?? [];
          list.push(entry);
          entriesByDimension.set(dim, list);
        }

        if (entriesByDimension.size > 0) {
          let allDimensionsMatch = true;
          let firstMatchEntry: typeof payload.segment_content_map[number] | undefined;
          for (const [, dimEntries] of entriesByDimension) {
            const dimMatch = dimEntries.find(e => userSegmentSet.has(e.segment_id));
            if (!dimMatch) {
              allDimensionsMatch = false;
              break;
            }
            if (!firstMatchEntry) firstMatchEntry = dimMatch;
          }

          if (allDimensionsMatch && firstMatchEntry) {
            matchedBlockId = firstMatchEntry.message_block_id;
            matchedSegmentId = firstMatchEntry.segment_id;
            if (firstMatchEntry.ui_path_id) uiPathId = firstMatchEntry.ui_path_id;
            if (firstMatchEntry.promotion_id) promotionId = firstMatchEntry.promotion_id;
          } else if (!allDimensionsMatch) {
            continue; // Skip this payload — segment AND condition not met
          }
        } else {
          // No dimension metadata on entries — fall back to flat OR
          for (const entry of payload.segment_content_map) {
            if (userSegmentSet.has(entry.segment_id)) {
              matchedBlockId = entry.message_block_id;
              matchedSegmentId = entry.segment_id;
              if (entry.ui_path_id) uiPathId = entry.ui_path_id;
              if (entry.promotion_id) promotionId = entry.promotion_id;
              break;
            }
          }
        }
      } else {
        // Flat OR behavior (backward compatible)
        for (const entry of payload.segment_content_map) {
          if (userSegmentSet.has(entry.segment_id)) {
            matchedBlockId = entry.message_block_id;
            matchedSegmentId = entry.segment_id;
            if (entry.ui_path_id) uiPathId = entry.ui_path_id;
            if (entry.promotion_id) promotionId = entry.promotion_id;
            break;
          }
        }
      }
    }

    const block = blockMap.get(matchedBlockId);
    if (!block || block.status !== 'active') continue;

    let rawContent: Record<string, unknown> = { ...block.default_content };

    if (matchedSegmentId && block.segment_overrides) {
      const override = block.segment_overrides.find((o: NonNullable<typeof block.segment_overrides>[number]) => o.segment_value_id === matchedSegmentId);
      if (override) {
        rawContent = { ...rawContent, ...override.content };
      }
    }

    const resolvedContent = resolveBlockContent(rawContent, enhancedContext);

    return {
      payload,
      messageBlock: block,
      resolvedContent,
      matchedSegmentId,
      uiPathId,
      promotionId,
    };
  }

  return null;
}

export async function resolvePayloadForUserWithProvider(
  surfaceTemplateId: string,
  userContext: UserTargetingContext,
  provider: PlacementContentLookupProvider,
  personalization: PersonalizationContext,
  explicitTokens?: PersonalizationToken[],
): Promise<ResolvedPayload | null> {
  const payloads = await Promise.resolve(provider.listPayloads(surfaceTemplateId));
  const candidates = payloads.filter(p => p.status === 'active');
  if (candidates.length === 0) return null;

  const userSegmentSet = new Set(userContext.segmentIds);
  const providerTokens = explicitTokens ?? (provider.listPersonalizationTokens
    ? await Promise.resolve(provider.listPersonalizationTokens())
    : []);
  const enhancedContext = applyValueMaps(personalization, providerTokens);

  for (const payload of candidates) {
    let matchedBlockId = payload.default_message_block_id;
    let matchedSegmentId: string | undefined;
    let uiPathId = payload.ui_path_id;
    let promotionId = payload.promotion_id;

    if (payload.segment_content_map) {
      for (const entry of payload.segment_content_map) {
        if (userSegmentSet.has(entry.segment_id)) {
          matchedBlockId = entry.message_block_id;
          matchedSegmentId = entry.segment_id;
          if (entry.ui_path_id) uiPathId = entry.ui_path_id;
          if (entry.promotion_id) promotionId = entry.promotion_id;
          break;
        }
      }
    }

    const block = await Promise.resolve(provider.getMessageBlockById(matchedBlockId));
    if (!block || block.status !== 'active') continue;

    let rawContent: Record<string, unknown> = { ...block.default_content };

    if (matchedSegmentId && block.segment_overrides) {
      const override = block.segment_overrides.find((o: NonNullable<typeof block.segment_overrides>[number]) => o.segment_value_id === matchedSegmentId);
      if (override) {
        rawContent = { ...rawContent, ...override.content };
      }
    }

    const resolvedContent = resolveBlockContent(rawContent, enhancedContext);

    let uiPath: ContentUiPath | null | undefined;
    if (uiPathId && provider.getUiPathById) {
      uiPath = await Promise.resolve(provider.getUiPathById(uiPathId));
    }

    let promotion: ContentPromotion | null | undefined;
    if (promotionId && provider.getPromotionById) {
      promotion = await Promise.resolve(provider.getPromotionById(promotionId));
    }

    return {
      payload,
      messageBlock: block,
      resolvedContent,
      matchedSegmentId,
      uiPathId,
      promotionId,
      uiPath: uiPath ?? undefined,
      promotion: promotion ?? undefined,
    };
  }

  return null;
}
