/**
 * ChangeSet schemas — grouped configuration changes with a review/deploy lifecycle.
 *
 * ChangeSets are analogous to git commits wrapped with a pull-request workflow:
 *
 *   draft → awaiting_approval → approved → deploying → deployed
 *                              ↳ rejected
 *   (any non-deployed state)  → archived
 *
 * Lifecycle:
 *  1. When a config change is submitted and no active ChangeSet exists,
 *     the user is prompted to either create a new ChangeSet or associate
 *     the change with an existing draft ChangeSet.
 *  2. Config entries reference the ChangeSet via change_set_id.
 *  3. Submitting for approval transitions status to "awaiting_approval".
 *  4. On deploy, for each entry sharing the change_set_id:
 *       a. The current active entry is found by canonical_id + is_current=true
 *       b. That entry is set to is_current=false (superseded)
 *       c. The new entry is set to is_current=true
 *       d. If the current sequence ≠ base_sequence, a conflict is flagged
 *
 * Git-inspired enhancements:
 *  • base_snapshot_sequence — max global sequence at ChangeSet creation, used
 *    to detect any concurrent changes (like HEAD at branch creation).
 *  • Per-entry base_sequence — parent version this change was forked from,
 *    enabling precise conflict detection (like git's 3-way merge).
 *  • Rollback — create a new ChangeSet that reverts a previously deployed one
 *    by copying the prior versions forward.
 *  • Cherry-pick — select individual entries from one ChangeSet into another.
 *  • Labels — arbitrary tags for categorizing ChangeSets (feature, hotfix, etc.).
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields, NameField, MetadataField, NullableDatetimeField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── ChangeSet status ─────────────────────────────────────────────────────────

export const ChangeSetStatusSchema =
  z.enum([
    'draft',
    'awaiting_approval',
    'approved',
    'deploying',
    'deployed',
    'rejected',
    'archived',
  ])
    .meta({ id: 'ChangeSetStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── ChangeSet ────────────────────────────────────────────────────────────────

export const ChangeSetSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    environment_id: (z.string().min(1)).meta(Unrestricted),
    name: (NameField).meta(Unrestricted),
    description: (z.string().max(2000).optional()).meta(Unrestricted),
    status: (ChangeSetStatusSchema.default('draft')).meta(Unrestricted),
    labels: (z.array(z.string()).default([])).meta(Unrestricted),

    // People
    created_by: (z.string().min(1)).meta(Unrestricted),
    submitted_by: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    reviewed_by: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    deployed_by: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),

    // Dates
    submitted_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    reviewed_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    deployed_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),

    // Snapshot (analogous to HEAD at branch creation)
    base_snapshot_sequence: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),

    // Computed counts
    entry_count: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),
    conflict_count: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),

    // Lineage
    rollback_of_change_set_id: (z.string().nullable().default(null)).meta(Unrestricted),
    cherry_picked_from_change_set_id: (z.string().nullable().default(null)).meta(Unrestricted),

    // Review
    review_notes: (z.string().max(2000).optional()).meta(Unrestricted),
    rejection_reason: (z.string().max(2000).optional()).meta(Unrestricted),

    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'ChangeSet', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── ChangeSet entry summary (computed, read-only) ────────────────────────────

export const ChangeSetEntrySummarySchema =
  z.object({
    canonical_id: (z.string()).meta(Unrestricted),
    resource_type: (z.string()).meta(Unrestricted),
    resource_name: (z.string().optional()).meta(Unrestricted),
    action: (z.enum(['create', 'update', 'delete'])).meta(Unrestricted),
    sequence: (z.number().int()).meta(Unrestricted),
    base_sequence: (z.number().int().nullable()).meta(Unrestricted),
    has_conflict: (z.boolean()).meta(Unrestricted),
    current_sequence: (z.number().int().nullable()).meta(Unrestricted),
  })
    .meta({ id: 'ChangeSetEntrySummary', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── ChangeSet diff (preview before deploy) ───────────────────────────────────

export const ChangeSetDiffSchema =
  z.object({
    change_set_id: (z.string()).meta(Unrestricted),
    entries: (z.array(ChangeSetEntrySummarySchema)).meta(Unrestricted),
    total_entries: (z.number().int().min(0)).meta(Unrestricted),
    total_conflicts: (z.number().int().min(0)).meta(Unrestricted),
    deployable: (z.boolean()).meta(Unrestricted),
  })
    .meta({ id: 'ChangeSetDiff', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Deploy result ────────────────────────────────────────────────────────────

export const ChangeSetDeployResultSchema =
  z.object({
    change_set_id: (z.string()).meta(Unrestricted),
    deployed_count: (z.number().int().min(0)).meta(Unrestricted),
    superseded_count: (z.number().int().min(0)).meta(Unrestricted),
    skipped_conflicts: (z.number().int().min(0)).meta(Unrestricted),
    deployed_at: (z.string().datetime()).meta(Unrestricted),
  })
    .meta({ id: 'ChangeSetDeployResult', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const changeSetPaths: ZodOpenApiPathsObject = {
  '/api/changesets': {
    get: operation({
      operationId: 'listChangeSets',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List change sets (filter by status, environment_id)',
      tags: ['changesets'],
      responses: { '200': { description: 'ChangeSet list', content: { 'application/json': { schema: ListEnvelope(ChangeSetSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createChangeSet',
      summary: 'Create a new change set (draft)',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({
        name: z.string().min(1).max(200),
        description: z.string().max(2000).optional(),
        environment_id: z.string().min(1),
        labels: z.array(z.string()).optional(),
      }) } } },
      responses: {
        '201': { description: 'Created', content: { 'application/json': { schema: ChangeSetSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'create' } },
    }),
  },
  '/api/changesets/{changeSetId}': {
    get: operation({
      operationId: 'getChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Get change set by ID',
      tags: ['changesets'],
      responses: { '200': { description: 'ChangeSet', content: { 'application/json': { schema: ChangeSetSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updateChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Update change set (name, description, labels — draft only)',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({
        name: z.string().min(1).max(200).optional(),
        description: z.string().max(2000).optional(),
        labels: z.array(z.string()).optional(),
      }) } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: ChangeSetSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },

  // ── Lifecycle transitions ────────────────────────────────────────────────

  '/api/changesets/{changeSetId}/submit': {
    post: operation({
      operationId: 'submitChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Submit change set for approval',
      tags: ['changesets'],
      responses: {
        '200': { description: 'Submitted', content: { 'application/json': { schema: ChangeSetSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },
  '/api/changesets/{changeSetId}/approve': {
    post: operation({
      operationId: 'approveChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Approve change set (may auto-deploy if environment allows)',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ review_notes: z.string().max(2000).optional() }) } } },
      responses: {
        '200': { description: 'Approved', content: { 'application/json': { schema: ChangeSetSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },
  '/api/changesets/{changeSetId}/reject': {
    post: operation({
      operationId: 'rejectChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Reject change set',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ rejection_reason: z.string().max(2000) }) } } },
      responses: {
        '200': { description: 'Rejected', content: { 'application/json': { schema: ChangeSetSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },
  '/api/changesets/{changeSetId}/deploy': {
    post: operation({
      operationId: 'deployChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Deploy change set — activates all entries, supersedes previous versions',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ force: z.boolean().default(false) }) } } },
      responses: {
        '200': { description: 'Deploy result', content: { 'application/json': { schema: ChangeSetDeployResultSchema } } },
        default: { description: 'Error (conflicts exist)', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'deploy' } },
    }),
  },
  '/api/changesets/{changeSetId}/archive': {
    post: operation({
      operationId: 'archiveChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Archive (abandon) a change set',
      tags: ['changesets'],
      responses: { '200': { description: 'Archived', content: { 'application/json': { schema: ChangeSetSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },

  // ── Inspection ───────────────────────────────────────────────────────────

  '/api/changesets/{changeSetId}/preview': {
    get: operation({
      operationId: 'previewChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Preview diff of all entries vs current state (dry-run deploy)',
      tags: ['changesets'],
      responses: { '200': { description: 'Diff preview', content: { 'application/json': { schema: ChangeSetDiffSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'preview' } },
    }),
  },
  '/api/changesets/{changeSetId}/conflicts': {
    get: operation({
      operationId: 'listChangeSetConflicts',
      requestParams: { path: z.object({ changeSetId: z.string() }) , query: ListQueryParamsSchema },
      summary: 'List entries with sequence conflicts (base_sequence ≠ current)',
      tags: ['changesets'],
      responses: { '200': { description: 'Conflict list', content: { 'application/json': { schema: ListEnvelope(ChangeSetEntrySummarySchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'list' } },
    }),
  },

  // ── Advanced operations ──────────────────────────────────────────────────

  '/api/changesets/{changeSetId}/rollback': {
    post: operation({
      operationId: 'rollbackChangeSet',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Create a rollback change set that reverts a deployed one',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({
        name: z.string().min(1).max(200).optional(),
      }) } } },
      responses: {
        '201': { description: 'Rollback ChangeSet created', content: { 'application/json': { schema: ChangeSetSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'create' } },
    }),
  },
  '/api/changesets/{changeSetId}/cherry-pick': {
    post: operation({
      operationId: 'cherryPickEntries',
      requestParams: { path: z.object({ changeSetId: z.string() }) },
      summary: 'Cherry-pick individual entries from this ChangeSet into another',
      tags: ['changesets'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({
        canonical_ids: z.array(z.string()).min(1),
        target_change_set_id: z.string().min(1),
      }) } } },
      responses: {
        '200': { description: 'Cherry-picked', content: { 'application/json': { schema: z.object({ copied_count: z.number().int() }) } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changesets', persistence: { table: 'changeSets', mode: 'update' } },
    }),
  },
};
