/**
 * Entitlement check lifecycle — pure functions for local entitlement
 * derivation from ExportedConfig rules.
 */

import type { ExportedConfig, EntitlementStatus, ExportedConfigEntitlementsItem, ExportedConfigPlansItem, ExportedConfigEntitlementRulesItem } from '@revt-eng/schema';
import type { PlacementOutput, EntitlementResult, RevTurbineEntitlementContext } from '../../core/types';
import { isRecord, type JsonObject } from '../../core/helpers';
import { normalizePlacementOutput } from '../../core/normalization';

// ── Types ───────────────────────────────────────────────────────────

export interface EntitlementCheckInput {
  /** Entitlement handle to check. */
  handle: string;
  /** Optional context (used amount, balance, required tier). */
  context?: RevTurbineEntitlementContext;
  /** User's current plan handle (id or unique_handle). */
  currentPlanHandle: string;
  /** Set of segment IDs the user currently belongs to. */
  segmentIds: Set<string>;
  /** Usage balance map (entitlement handle → consumed amount). */
  usageBalances: Record<string, number>;
  /** Usage entries from user context, keyed by handle. */
  userUsage?: Record<string, unknown>;
  /** The full ExportedConfig. */
  exportedConfig: ExportedConfig;
}

// ── Pure functions ──────────────────────────────────────────────────

/**
 * Derive an entitlement result locally from ExportedConfig rules.
 *
 * Evaluates entitlement rules from the config against the user's plan,
 * segments, and usage. Returns null when no config is available or no
 * matching rules exist.
 */
export function deriveLocalEntitlementFromConfiguredRules(
  input: EntitlementCheckInput,
): EntitlementResult | null {
  const { handle, context, exportedConfig, currentPlanHandle, segmentIds, usageBalances, userUsage } = input;

  const entitlements = exportedConfig.entitlements ?? [];
  const entitlement = entitlements.find((item: ExportedConfigEntitlementsItem) => (
    (typeof item?.unique_handle === 'string' && item.unique_handle === handle)
    || (typeof item?.id === 'string' && item.id === handle)
  ));

  const entitlementId = typeof entitlement?.id === 'string' ? entitlement.id : handle;
  const normalizedPlanHandle = String(currentPlanHandle || '').toLowerCase();

  const plans = exportedConfig.plans ?? [];
  const matchedPlan = plans.find((plan: ExportedConfigPlansItem) => (
    (typeof plan.unique_handle === 'string' && plan.unique_handle.toLowerCase() === normalizedPlanHandle)
    || (typeof plan.id === 'string' && String(plan.id).toLowerCase() === normalizedPlanHandle)
  ));

  const currentPlanId = typeof matchedPlan?.id === 'string'
    ? matchedPlan.id
    : (normalizedPlanHandle || undefined);

  const rules = exportedConfig.entitlement_rules ?? [];

  const matchingRules = rules.filter((rule: ExportedConfigEntitlementRulesItem) => {
    const ruleEntitlementId = typeof rule.entitlement_id === 'string'
      ? rule.entitlement_id
      : typeof (rule as JsonObject).entitlementId === 'string'
        ? (rule as JsonObject).entitlementId as string
        : '';
    if (ruleEntitlementId !== entitlementId) return false;

    const planIds = Array.isArray(rule.plan_ids)
      ? rule.plan_ids.filter((id: string): id is string => typeof id === 'string')
      : Array.isArray((rule as JsonObject).planIds)
        ? ((rule as JsonObject).planIds as unknown[]).filter((id): id is string => typeof id === 'string')
        : [];

    if (currentPlanId && planIds.length > 0 && !planIds.includes(currentPlanId)) return false;

    const segmentId = typeof rule.segment_id === 'string'
      ? rule.segment_id
      : typeof (rule as JsonObject).segmentId === 'string'
        ? (rule as JsonObject).segmentId as string
        : null;
    if (segmentId && !segmentIds.has(segmentId)) return false;

    return true;
  });

  if (matchingRules.length === 0) {
    return { status: 'allowed', allowed: true, reason: 'no_matching_entitlement_rule' };
  }

  const selectedRule = matchingRules[0];
  const typeFields = isRecord(selectedRule.type_fields)
    ? selectedRule.type_fields
    : isRecord((selectedRule as JsonObject).typeFields)
      ? (selectedRule as JsonObject).typeFields as JsonObject
      : {};
  const kind = typeof typeFields.kind === 'string' ? typeFields.kind : undefined;

  // Resolve used amount from multiple sources
  const usageAmountFor = (key: string): number | undefined => {
    const entry = userUsage?.[key];
    if (isRecord(entry) && typeof entry.amount === 'number') return entry.amount;
    return undefined;
  };
  const used = context?.used
    ?? (Number.isFinite(usageBalances[handle]) ? usageBalances[handle] : undefined)
    ?? (Number.isFinite(usageBalances[entitlementId]) ? usageBalances[entitlementId] : undefined)
    ?? usageAmountFor(handle)
    ?? usageAmountFor(entitlementId)
    ?? 0;

  if (kind === 'feature') {
    const enabled = typeFields.enabled !== false;
    return {
      status: enabled ? 'allowed' : 'denied',
      allowed: enabled,
      reason: enabled ? undefined : 'feature_not_enabled_for_plan',
    };
  }

  if (kind === 'usage_limit') {
    const limit = Number(typeFields.limit_value);
    if (Number.isFinite(limit) && limit >= 0) {
      const allowed = used < limit;
      return {
        status: allowed ? 'allowed' : 'limited',
        allowed,
        reason: allowed ? undefined : 'usage_limit_reached',
      };
    }
    return { status: 'allowed', allowed: true };
  }

  if (kind === 'credits') {
    const allowance = Number(typeFields.allowance);
    const initialGrant = Number(typeFields.initial_grant);
    const limit = Number.isFinite(allowance) && allowance >= 0
      ? allowance
      : Number.isFinite(initialGrant) && initialGrant >= 0
        ? initialGrant
        : undefined;
    if (limit !== undefined) {
      const allowed = used < limit;
      return {
        status: allowed ? 'allowed' : 'limited',
        allowed,
        reason: allowed ? undefined : 'credit_balance_exhausted',
      };
    }
    return { status: 'allowed', allowed: true };
  }

  if (kind === 'capability_tier') {
    const tierName = typeof typeFields.tier_name === 'string'
      ? typeFields.tier_name
      : undefined;
    return {
      status: 'allowed',
      allowed: true,
      ...(tierName ? { current_tier: tierName } : {}),
    };
  }

  return { status: 'allowed', allowed: true };
}

/**
 * Normalize raw entitlement response data into a typed EntitlementResult.
 *
 * Accepts a `generateRequestId` function for creating synthetic IDs
 * when normalizing embedded placement outputs.
 */
export function normalizeEntitlementResult(
  data: unknown, // sdk-ok: boundary-parse
  generateRequestId: () => string,
): EntitlementResult {
  if (!isRecord(data)) return { status: 'allowed', allowed: true };
  const rawStatus = typeof data.status === 'string' ? data.status : undefined;
  const status: EntitlementStatus = rawStatus === 'limited' || rawStatus === 'denied' || rawStatus === 'allowed'
    ? rawStatus
    : (typeof data.allowed === 'boolean' && data.allowed ? 'allowed' : 'denied');
  const allowed = status !== 'denied';
  const reason = typeof data.reason === 'string' ? data.reason : undefined;
  const current_tier = typeof data.current_tier === 'string' ? data.current_tier : undefined;
  const placement = isRecord(data.placement) ? normalizePlacementOutput(data.placement, generateRequestId) : undefined;
  return {
    status,
    allowed,
    ...(reason !== undefined ? { reason } : {}),
    ...(current_tier !== undefined ? { current_tier } : {}),
    ...(placement != null ? { placement } : {}),
  };
}

/**
 * Look up the usage threshold for an entitlement from configured rules.
 */
export function usageThresholdForEntitlement(
  entitlement: string,
  usageLimitByEntitlement: Map<string, { limit: number; warningPercent: number }>,
  localEntitlementsByHandle: Map<string, EntitlementResult>,
  usageBalances: Record<string, number>,
  defaultWarningPercent: number = 80,
): { limit: number; warningPercent: number } | null {
  const fromRules = usageLimitByEntitlement.get(entitlement);
  if (fromRules) return fromRules;

  const entitlementState = localEntitlementsByHandle.get(entitlement);
  if (entitlementState?.status === 'limited' && Number.isFinite(usageBalances[entitlement])) {
    const current = Number(usageBalances[entitlement]);
    if (current > 0) {
      return { limit: current, warningPercent: defaultWarningPercent };
    }
  }

  return null;
}
