// ── Semantic events ──────────────────────────────────────────────────────────

export const SemanticEventSchema =
  z.object({
    event_type: (z.string().min(1)).meta(Unrestricted),
    payload: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
  })
    .meta({
      id: 'SemanticEvent',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Event search ─────────────────────────────────────────────────────────────

export const EventSearchParamsSchema =
  z.object({
    q: (z.string().optional()).meta(Unrestricted),
    source: (EventSourceSchema.optional()).meta(Unrestricted),
    event_type: (z.string().optional()).meta(Unrestricted),
    from: (z.string().datetime().optional()).meta(Unrestricted),
    to: (z.string().datetime().optional()).meta(Unrestricted),
    page: (z.coerce.number().int().min(1).default(1)).meta(Unrestricted),
    per_page: (z.coerce.number().int().min(1).max(100).default(25)).meta(Unrestricted),
  })
    .meta({
      id: 'EventSearchParams',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Webhook event log ────────────────────────────────────────────────────────

export const WebhookEventSourceSchema =
  z.enum(['stripe', 'apple', 'google'])
    .meta({
      id: 'WebhookEventSource',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

export const WebhookEventStatusSchema =
  z.enum(['processed', 'failed', 'skipped'])
    .meta({
      id: 'WebhookEventStatus',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

export const WebhookEventLogSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    event_id: (z.string().min(1)).meta(Unrestricted),
    event_type: (z.string().min(1)).meta(Unrestricted),
    source: (WebhookEventSourceSchema).meta(Unrestricted),
    payload: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    status: (WebhookEventStatusSchema.default('processed')).meta(Unrestricted),
    processed_at: (z.string().datetime().optional()).meta(Unrestricted),
    error_message: (z.string().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'WebhookEventLog',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Ingest response ──────────────────────────────────────────────────────────

const EventIngestResponseSchema =
  z.object({
    accepted: (z.number().int().min(0)).meta(Unrestricted),
  })
    .meta({
      id: 'null',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const eventPaths: ZodOpenApiPathsObject = {
  '/api/events/ingest': {
    post: operation({
      operationId: 'ingestEventBatch',
      summary: 'Ingest a batch of events',
      tags: ['events'],
      requestBody: { required: true, content: { 'application/json': { schema: EventIngestBatchSchema } } },
      responses: {
        '202': { description: 'Events accepted for processing', content: { 'application/json': { schema: EventIngestResponseSchema } } },
        default: { description: 'Error response', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'external', resource: 'events' },
    }),
  },
  '/api/events/search': {
    get: operation({
      operationId: 'searchEvents',
      summary: 'Search ingested events',
      tags: ['events'],
      responses: {
        '200': { description: 'Paginated event results', content: { 'application/json': { schema: PaginatedResponseSchema(IngestedEventSchema) } } },
        default: { description: 'Error response', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'events' },
    }),
  },
  '/api/events/interactions': {
    post: operation({
      operationId: 'recordTreatmentInteraction',
      summary: 'Record a placement treatment interaction',
      tags: ['events'],
      requestBody: { required: true, content: { 'application/json': { schema: TreatmentInteractionInputSchema } } },
      responses: {
        '202': { description: 'Interaction accepted', content: { 'application/json': { schema: EventIngestResponseSchema } } },
        default: { description: 'Error response', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'external', resource: 'events' },
    }),
  },
  '/api/telemetry': {
    post: operation({
      operationId: 'ingestTelemetry',
      summary: 'Ingest frontend telemetry events',
      tags: ['events'],
      requestBody: { required: true, content: { 'application/json': { schema: EventIngestBatchSchema } } },
      responses: {
        '202': { description: 'Telemetry events accepted', content: { 'application/json': { schema: EventIngestResponseSchema } } },
        default: { description: 'Error response', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'events' },
    }),
  },
  '/api/clickstream': {
    post: operation({
      operationId: 'ingestClickstream',
      summary: 'Ingest browser clickstream events',
      tags: ['events'],
      requestBody: { required: true, content: { 'application/json': { schema: EventIngestBatchSchema } } },
      responses: {
        '202': { description: 'Clickstream events accepted', content: { 'application/json': { schema: EventIngestResponseSchema } } },
        default: { description: 'Error response', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'events' },
    }),
  },
  '/api/webhook-events': {
    get: operation({
      operationId: 'listWebhookEvents',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List webhook event log entries',
      tags: ['events'],
      responses: { '200': { description: 'Webhook event list', content: { 'application/json': { schema: ListEnvelope(WebhookEventLogSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'webhook-events', persistence: { table: 'webhookEventLog', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createWebhookEvent',
      summary: 'Record a processed webhook event',
      tags: ['events'],
      requestBody: { required: true, content: { 'application/json': { schema: WebhookEventLogSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: WebhookEventLogSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'webhook-events', persistence: { table: 'webhookEventLog', mode: 'create' } },
    }),
  },
};
