/**
 * Placement decision lifecycle — pure functions for candidate resolution,
 * scoring, milestone supersession, category suppression, and cache key derivation.
 */

import type { PlacementOutput, RevTurbinePlacementDecision } from '../../core/types';
import type { PlacementCapPolicy, PlacementCapRule, PresentationCapState, SurfaceTypeCapRule } from '../../core/state/types';
import {
  isRecord,
  parseNumberish,
  parseLocalLookupKey,
  parseCapRule,
  periodWindowStart,
  categoryBucket,
  placementScore,
  placementPriority,
  proximityScore,
  serverOrder,
  milestoneVersion,
  supersededVersions,
  stableStringify,
  normalizedRoute,
  type JsonObject,
  type LocalLookupParts,
} from '../../core/helpers';
import { fallbackHashBase64Url } from '../../core/crypto';

// Re-export from core for backward compatibility
export { normalizePlacementOutput } from '../../core/normalization';

// ── Types ───────────────────────────────────────────────────────────

export interface PlacementRequestConfig {
  slotId?: string;
  surfaceType?: string;
  entitlementHandle?: string;
  planHandle?: string;
  placementHandle?: string;
}

export interface DecisionCacheKeyInput {
  tenantId: string;
  placementId: string;
  userId: string;
  contextMode?: string;
  overrides?: Record<string, unknown>;
  traits?: Record<string, unknown>;
  route: string;
  runtimeContextFingerprint?: string;
}

// Re-export for consumers
export type { LocalLookupParts };

// ── Lookup key ──────────────────────────────────────────────────────

export function localPlacementLookupKey(config: PlacementRequestConfig): string {
  return [
    config.slotId || '',
    config.surfaceType || '',
    config.entitlementHandle || '',
    config.planHandle || '',
    config.placementHandle || '',
  ].join('::');
}

// ── Cache key ───────────────────────────────────────────────────────

export function decisionCacheKey(input: DecisionCacheKeyInput): string {
  const fingerprint = stableStringify({
    placementId: input.placementId,
    userId: input.userId,
    contextMode: input.contextMode ?? 'auto',
    overrides: input.overrides ?? {},
    traits: input.traits ?? {},
    route: normalizedRoute(input.route),
    ...(input.runtimeContextFingerprint ? { runtimeContextFingerprint: input.runtimeContextFingerprint } : {}),
  });
  return `${input.tenantId}:${input.placementId}:${input.userId}:${fallbackHashBase64Url(fingerprint)}`;
}

// ── Milestone supersession ──────────────────────────────────────────

export function applyMilestoneSupersession(outputs: PlacementOutput[]): PlacementOutput[] {
  if (outputs.length <= 1) return outputs;

  const suppressed = new Set<string>();

  for (const contender of outputs) {
    const template = contender.surface.template;
    if (!template) continue;

    const supersedes = supersededVersions(contender);
    if (supersedes.length === 0) continue;

    for (const candidate of outputs) {
      if (candidate.output_id === contender.output_id) continue;
      if (candidate.surface.template !== template) continue;

      const version = milestoneVersion(candidate);
      if (!version) continue;
      if (supersedes.includes(version)) {
        suppressed.add(candidate.output_id);
      }
    }
  }

  const byTemplate = new Map<string, PlacementOutput[]>();
  for (const output of outputs) {
    if (!output.surface.template) continue;
    const list = byTemplate.get(output.surface.template) ?? [];
    list.push(output);
    byTemplate.set(output.surface.template, list);
  }

  for (const group of byTemplate.values()) {
    if (group.length <= 1) continue;
    const contenders = group
      .map((output) => {
        const content = isRecord(output.content) ? output.content : {};
        return {
          output,
          order: parseNumberish(content.milestone_order) ?? Number.NEGATIVE_INFINITY,
        };
      })
      .filter((entry) => Number.isFinite(entry.order));

    if (contenders.length <= 1) continue;
    const winner = contenders.reduce((current, next) => (next.order > current.order ? next : current));
    for (const contender of contenders) {
      if (contender.output.output_id !== winner.output.output_id) {
        suppressed.add(contender.output.output_id);
      }
    }
  }

  return outputs.filter((output) => !suppressed.has(output.output_id));
}

// ── Category conflict suppression ───────────────────────────────────

export function applyCategoryConflictSuppression(outputs: PlacementOutput[]): PlacementOutput[] {
  if (outputs.length <= 1) return outputs;

  const suppressed = new Set<string>();

  for (let i = 0; i < outputs.length; i += 1) {
    for (let j = i + 1; j < outputs.length; j += 1) {
      const left = outputs[i];
      const right = outputs[j];
      if (left.surface.type !== right.surface.type) continue;

      const leftBucket = categoryBucket(left.category);
      const rightBucket = categoryBucket(right.category);
      if (leftBucket === rightBucket) continue;

      if (leftBucket < rightBucket) {
        suppressed.add(right.output_id);
      } else {
        suppressed.add(left.output_id);
      }
    }
  }

  return outputs.filter((output) => !suppressed.has(output.output_id));
}

// ── Candidate scoring + selection ───────────────────────────────────

export interface CandidateResolutionOptions {
  /** When true, only fixed-category candidates are considered. */
  fixedOnly?: boolean;
}

export function resolveLocalPlacementFromCandidates(
  candidates: PlacementOutput[],
  enableCategoryPipeline: boolean = false,
  options?: CandidateResolutionOptions,
): PlacementOutput | null {
  let pool = candidates;

  // fixedOnly pre-filter: only fixed-category candidates pass
  if (options?.fixedOnly) {
    pool = pool.filter((output) => categoryBucket(output.category) === 1);
  }

  if (pool.length === 0) return null;

  const milestonesApplied = applyMilestoneSupersession(pool);
  if (milestonesApplied.length === 0) return null;

  const hasExplicitServerOrder = milestonesApplied.some((output) => serverOrder(output) !== null);

  const conflictsApplied = hasExplicitServerOrder
    ? milestonesApplied
    : applyCategoryConflictSuppression(milestonesApplied);
  if (conflictsApplied.length === 0) return null;

  const ordered = [...conflictsApplied].sort((left, right) => {
    if (hasExplicitServerOrder) {
      const leftOrder = serverOrder(left);
      const rightOrder = serverOrder(right);
      if (leftOrder !== null && rightOrder !== null && leftOrder !== rightOrder) {
        return leftOrder - rightOrder;
      }
      if (leftOrder !== null && rightOrder === null) return -1;
      if (leftOrder === null && rightOrder !== null) return 1;
    }

    const leftBucket = categoryBucket(left.category);
    const rightBucket = categoryBucket(right.category);
    const bucketDelta = leftBucket - rightBucket;
    if (bucketDelta !== 0) return bucketDelta;

    // Within priority tier (usage/credit/seat + trial, buckets 2-3):
    // rank by proximity to constraint (higher = closer to limit = higher priority)
    if (leftBucket >= 2 && leftBucket <= 3) {
      const proximityDelta = proximityScore(right) - proximityScore(left);
      if (proximityDelta !== 0) return proximityDelta;
    }

    const scoreDelta = placementScore(right) - placementScore(left);
    if (scoreDelta !== 0) return scoreDelta;

    const priorityDelta = placementPriority(right) - placementPriority(left);
    if (priorityDelta !== 0) return priorityDelta;

    return left.output_id.localeCompare(right.output_id);
  });

  return ordered[0] ?? null;
}

// ── Response normalization ──────────────────────────────────────────

function decisionContent(header: string, body: string, ctaLabel: string) {
  return { header, body, cta_label: ctaLabel, title: header, cta: ctaLabel };
}

export function normalizeDecisionFromResponse(
  placementId: string,
  requestId: string,
  placementName: string,
  payload: unknown, // sdk-ok: boundary-parse
): RevTurbinePlacementDecision {
  const root = isRecord(payload) ? payload : {};
  const decision = isRecord(root.decision) ? root.decision : {};
  const content = isRecord(root.content)
    ? root.content
    : isRecord(decision.content)
      ? decision.content
      : {};

  const visible = typeof decision.visible === 'boolean'
    ? decision.visible
    : typeof root.visible === 'boolean'
      ? root.visible
      : true;

  return {
    placementId,
    requestId: typeof root.request_id === 'string' ? root.request_id : requestId,
    visible,
    decisionSource: 'remote',
    reasonCodes: Array.isArray(root.reason_codes)
      ? root.reason_codes.filter((item): item is string => typeof item === 'string')
      : [],
    content: decisionContent(
      typeof content.title === 'string' ? content.title : `${placementName} recommendation`,
      typeof content.body === 'string' ? content.body : 'Treatment selected by RevTurbine decisioning.',
      typeof content.cta === 'string' ? content.cta : 'Continue',
    ),
  };
}

// ── Cap enforcement (pure computation) ──────────────────────────────

export function extractPlacementCapPolicies(output: PlacementOutput): PlacementCapPolicy[] {
  const policies: PlacementCapPolicy[] = [];
  const roots: unknown[] = [ // sdk-ok: boundary-parse
    output,
    output.content,
    isRecord(output.content) ? output.content.payload : undefined,
    isRecord(output.content) ? output.content.placement : undefined,
    isRecord(output.content) ? output.content.surface : undefined,
  ];

  for (const root of roots) {
    if (!isRecord(root)) continue;
    const caps = isRecord(root.caps) ? root.caps : undefined;
    if (!caps) continue;

    const rules: PlacementCapRule[] = [];
    const rule = parseCapRule(caps.max_per_period);
    if (rule) rules.push(rule);

    const cooldownDays = Number(caps.cooldown_days);
    const cooldownMs = Number.isFinite(cooldownDays) && cooldownDays > 0
      ? cooldownDays * 24 * 60 * 60 * 1000
      : undefined;

    policies.push({ rules, ...(cooldownMs !== undefined ? { cooldownMs } : {}) });
  }

  return policies;
}

export interface CapCheckResult {
  allowed: boolean;
  reason?: string;
  updatedState?: PresentationCapState;
}

/**
 * Pure cap enforcement: check whether a placement is allowed by cap policies.
 *
 * Returns the updated cap state alongside the allow/deny result so the caller
 * can persist it.
 *
 * @param interactionType - When 'dismiss', cooldown is applied. When 'impression'
 *   (default), only period-based caps are enforced. Per spec: cooldown is "after dismiss".
 */
export function checkPlacementCaps(
  output: PlacementOutput,
  capKey: string,
  existingState: PresentationCapState | undefined,
  nowMs: number,
  interactionType: 'impression' | 'dismiss' = 'impression',
): CapCheckResult {
  const policies = extractPlacementCapPolicies(output);
  if (policies.length === 0) return { allowed: true };

  const state: PresentationCapState = {
    ...(existingState ?? { seenAt: [] }),
    seenAt: (existingState?.seenAt ?? []).filter((seenAt) => Number.isFinite(seenAt) && seenAt > 0),
  };

  if (Number.isFinite(state.cooldownUntil) && (state.cooldownUntil as number) > nowMs) {
    return { allowed: false, reason: 'suppressed_by_payload_cooldown', updatedState: state };
  }

  for (const policy of policies) {
    for (const rule of policy.rules) {
      const windowStart = periodWindowStart(rule.period, nowMs);
      const withinWindow = state.seenAt.filter((seenAt) => seenAt >= windowStart && seenAt <= nowMs);
      if (withinWindow.length >= rule.count) {
        return {
          allowed: false,
          reason: `suppressed_by_payload_cap_${rule.period}`,
          updatedState: { ...state, seenAt: withinWindow },
        };
      }
    }
  }

  const updatedSeenAt = [...state.seenAt, nowMs];
  const cooldowns = interactionType === 'dismiss'
    ? policies
        .map((policy) => policy.cooldownMs)
        .filter((value): value is number => typeof value === 'number' && Number.isFinite(value) && value > 0)
    : [];
  const cooldownUntil = cooldowns.length > 0 ? nowMs + Math.max(...cooldowns) : undefined;

  return {
    allowed: true,
    updatedState: {
      seenAt: updatedSeenAt,
      ...(cooldownUntil !== undefined ? { cooldownUntil } : {}),
    },
  };
}

// ── System-level presentation cap enforcement ───────────────────────

/**
 * Check system-level (per-surface-type) presentation caps.
 *
 * Deterministic/priority categories (gated, fixed, usage/credit/seat, trial)
 * are exempt from system caps — they always fire when triggered.
 * Only discretionary categories (conversion/expansion, retention) are capped.
 */
export function checkSystemPresentationCaps(
  output: PlacementOutput,
  surfaceType: string,
  surfaceCapRules?: SurfaceTypeCapRule[],
  sessionCooldownMs?: number,
  presentationHistory?: PresentationCapState,
  nowMs: number = Date.now(),
): CapCheckResult {
  // No rules configured → always allowed
  if (!surfaceCapRules || surfaceCapRules.length === 0) {
    return { allowed: true };
  }

  // Exempt categories: gated (0), fixed (1), usage/credit/seat (2), trial (3)
  const bucket = categoryBucket(output.category);
  if (bucket <= 3) {
    return { allowed: true };
  }

  // Find matching surface-type rule
  const rule = surfaceCapRules.find(
    (r) => r.surface_type.toLowerCase() === surfaceType.toLowerCase(),
  );
  if (!rule) {
    return { allowed: true };
  }

  const state = presentationHistory ?? { seenAt: [] };

  // Check session cooldown
  if (sessionCooldownMs && sessionCooldownMs > 0 && state.seenAt.length > 0) {
    const lastSeen = Math.max(...state.seenAt);
    if (nowMs - lastSeen < sessionCooldownMs) {
      return { allowed: false, reason: 'suppressed_by_system_cooldown' };
    }
  }

  // Check period-based caps
  for (const capRule of rule.rules) {
    const windowStart = periodWindowStart(capRule.period, nowMs);
    const withinWindow = state.seenAt.filter(
      (seenAt) => seenAt >= windowStart && seenAt <= nowMs,
    );
    if (withinWindow.length >= capRule.count) {
      return {
        allowed: false,
        reason: `suppressed_by_system_cap_${capRule.period}`,
      };
    }
  }

  // Check rule-level cooldown
  if (rule.cooldownMs && rule.cooldownMs > 0 && state.seenAt.length > 0) {
    const lastSeen = Math.max(...state.seenAt);
    if (nowMs - lastSeen < rule.cooldownMs) {
      return { allowed: false, reason: 'suppressed_by_system_cooldown' };
    }
  }

  return { allowed: true };
}

// ── Milestone supersession with analytics metadata ──────────────────

export interface SupersessionRecord {
  supersededOutputId: string;
  supersededBy: string;
  reason: 'milestone_version' | 'milestone_order';
}

export interface SupersessionResult {
  survivors: PlacementOutput[];
  superseded: SupersessionRecord[];
}

/**
 * Same logic as `applyMilestoneSupersession` but also returns metadata
 * about which outputs were superseded and why.
 */
export function applyMilestoneSupersessionWithMetadata(outputs: PlacementOutput[]): SupersessionResult {
  if (outputs.length <= 1) return { survivors: outputs, superseded: [] };

  const suppressed = new Map<string, SupersessionRecord>();

  // Phase 1: explicit version-based supersession
  for (const contender of outputs) {
    const template = contender.surface.template;
    if (!template) continue;

    const supersedes = supersededVersions(contender);
    if (supersedes.length === 0) continue;

    for (const candidate of outputs) {
      if (candidate.output_id === contender.output_id) continue;
      if (candidate.surface.template !== template) continue;

      const version = milestoneVersion(candidate);
      if (!version) continue;
      if (supersedes.includes(version)) {
        suppressed.set(candidate.output_id, {
          supersededOutputId: candidate.output_id,
          supersededBy: contender.output_id,
          reason: 'milestone_version',
        });
      }
    }
  }

  // Phase 2: milestone_order tiebreaker within same template
  const byTemplate = new Map<string, PlacementOutput[]>();
  for (const output of outputs) {
    if (!output.surface.template) continue;
    const list = byTemplate.get(output.surface.template) ?? [];
    list.push(output);
    byTemplate.set(output.surface.template, list);
  }

  for (const group of byTemplate.values()) {
    if (group.length <= 1) continue;
    const contenders = group
      .map((output) => {
        const content = isRecord(output.content) ? output.content : {};
        return {
          output,
          order: parseNumberish(content.milestone_order) ?? Number.NEGATIVE_INFINITY,
        };
      })
      .filter((entry) => Number.isFinite(entry.order));

    if (contenders.length <= 1) continue;
    const winner = contenders.reduce((current, next) => (next.order > current.order ? next : current));
    for (const contender of contenders) {
      if (contender.output.output_id !== winner.output.output_id) {
        suppressed.set(contender.output.output_id, {
          supersededOutputId: contender.output.output_id,
          supersededBy: winner.output.output_id,
          reason: 'milestone_order',
        });
      }
    }
  }

  return {
    survivors: outputs.filter((output) => !suppressed.has(output.output_id)),
    superseded: [...suppressed.values()],
  };
}

// ── One-discretionary-per-cycle filter ──────────────────────────────

export interface SlotDecision {
  output: PlacementOutput;
  slotId: string;
}

export interface FilteredSlotDecision extends SlotDecision {
  suppressed?: boolean;
  suppressionReason?: string;
}

/**
 * Enforce the one-discretionary-per-evaluation-cycle rule.
 *
 * Deterministic/priority categories (bucket < 4) always pass through.
 * Discretionary categories (bucket >= 4) are suppressed if a discretionary
 * placement has already fired in this cycle.
 */
export function filterOneDiscretionary(
  decisions: SlotDecision[],
  alreadyFiredDiscretionary: boolean = false,
): FilteredSlotDecision[] {
  let discretionaryFired = alreadyFiredDiscretionary;

  return decisions.map((decision) => {
    const bucket = categoryBucket(decision.output.category);
    if (bucket < 4) {
      return decision;
    }

    // Discretionary category
    if (discretionaryFired) {
      return {
        ...decision,
        suppressed: true,
        suppressionReason: 'one_discretionary_per_cycle',
      };
    }

    discretionaryFired = true;
    return decision;
  });
}
