/**
 * Decision schemas — ServerEvaluationPayload for SSR hydration,
 * PlacementDecisionOutput for typed decision results,
 * and EntitlementCheckResult for entitlement responses.
 */
import { z } from 'zod';
import {
  DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { SurfaceTypeSchema } from '../../core/common';
import { UserTrialStatusSchema } from '../../user/models/schema';

const { Unrestricted, Pii } = DataClassification;
const { Transient, Persisted } = SchemaPersistence;
const { External } = SchemaExposure;

// ── Supersession record (analytics/audit) ────────────────────────────────────

export const SupersessionReasonSchema =
  z.enum(['milestone_version', 'milestone_order'])
    .meta({ id: 'SupersessionReason', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

export const SupersessionRecordSchema =
  z.object({
    superseded_output_id: z.string().min(1).meta(Unrestricted),
    superseded_by: z.string().min(1).meta(Unrestricted),
    reason: SupersessionReasonSchema.meta(Unrestricted),
  })
    .meta({
      id: 'SupersessionRecord',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
      'x-revturbine-data-classification': 'operational',
    });

// ── Entitlement check result ─────────────────────────────────────────────────

export const EntitlementStatusSchema =
  z.enum(['allowed', 'limited', 'denied'])
    .meta({ id: 'EntitlementStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

// ── Placement decision output (wire-format from server → client) ─────────────

export const PlacementDecisionOutputSchema =
  z.object({
    output_id: z.string().meta(Unrestricted),
    category: z.string().meta(Unrestricted),
    surface: z.object({
      template: z.string().optional().meta(Unrestricted),
      type: SurfaceTypeSchema.meta(Unrestricted),
      slot_id: z.string().optional().meta(Unrestricted),
    }).meta(Unrestricted),
    content: z.record(z.string(), z.unknown()).meta(Unrestricted),
    promotion: z.record(z.string(), z.unknown()).optional().meta(Unrestricted),
    cta_path: z.record(z.string(), z.unknown()).optional().meta(Unrestricted),
    /** @deprecated Use cta_path. Kept for compatibility with older SDK consumers. */
    ui_path: z.record(z.string(), z.unknown()).optional().meta(Unrestricted),
    rule_id: z.string().meta(Unrestricted),
    decision_id: z.string().meta(Unrestricted),
    config_version: z.string().meta(Unrestricted),
    present_upsell: z.boolean().meta(Unrestricted),
  })
    .meta({ id: 'PlacementDecisionOutput', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

export const EntitlementCheckResultSchema =
  z.object({
    status: EntitlementStatusSchema.meta(Unrestricted),
    allowed: z.boolean().meta(Unrestricted),
    reason: z.string().optional().meta(Unrestricted),
    current_tier: z.string().optional().meta(Unrestricted),
    /** Upsell placement to render when entitlement is denied. */
    placement: PlacementDecisionOutputSchema.optional().meta(Unrestricted),
  })
    .meta({ id: 'EntitlementCheckResult', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

// ── Runtime promotion snapshot (lightweight promotion in placement context) ──

export const RuntimePromotionSnapshotSchema =
  z.object({
    id: z.string().meta(Unrestricted),
    name: z.string().optional().meta(Unrestricted),
    discount: z.string().optional().meta(Unrestricted),
    type: z.string().optional().meta(Unrestricted),
    status: z.string().optional().meta(Unrestricted),
  })
    .meta({ id: 'RuntimePromotionSnapshot', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

// ── Server evaluation payload sub-schemas ────────────────────────────────────

export const ServerEvaluationPayloadUserSchema =
  z.object({
    id: z.string().meta(Pii),
    anonymous_id: z.string().optional().meta(Unrestricted),
    traits: z.record(z.string(), z.unknown()).optional().meta(Pii),
  })
    .meta({ id: 'ServerEvaluationPayloadUser', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

export const ServerEvaluationPayloadDecisionsItemSchema =
  z.object({
    slot_id: z.string().optional().meta(Unrestricted),
    entitlement_handle: z.string().optional().meta(Unrestricted),
    plan_handle: z.string().optional().meta(Unrestricted),
    placement_handle: z.string().optional().meta(Unrestricted),
    visible: z.boolean().meta(Unrestricted),
    output: PlacementDecisionOutputSchema.optional().meta(Unrestricted),
    reason_codes: z.array(z.string()).optional().meta(Unrestricted),
  })
    .meta({ id: 'ServerEvaluationPayloadDecisionsItem', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

/** Alias: identical schema used in server evaluation payload entitlements map. */
export const ServerEvaluationPayloadEntitlementsValueSchema = EntitlementCheckResultSchema;

/** ServerEvaluationPayloadTrialStatus = UserTrialStatus without the `state` field. */
export const ServerEvaluationPayloadTrialStatusSchema =
  UserTrialStatusSchema.omit({ state: true })
    .meta({ id: 'ServerEvaluationPayloadTrialStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

export const ServerEvaluationPayloadUserContextSchema =
  z.object({
    segments: z.array(z.string()).optional().meta(Unrestricted),
    traits: z.record(z.string(), z.unknown()).optional().meta(Pii),
    usage_balances: z.record(z.string(), z.number()).optional().meta(Unrestricted),
  })
    .meta({ id: 'ServerEvaluationPayloadUserContext', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });

// ── Server evaluation payload (root) ─────────────────────────────────────────

export const ServerEvaluationPayloadSchema =
  z.object({
    version: z.literal('1.0.0').meta(Unrestricted),
    request_id: z.string().meta(Unrestricted),
    tenant_id: z.string().meta(Unrestricted),
    evaluated_at: z.string().datetime().meta(Unrestricted),
    ttl_seconds: z.number().int().min(0).max(86400).meta(Unrestricted),
    user: ServerEvaluationPayloadUserSchema.meta(Pii),
    decisions: z.array(ServerEvaluationPayloadDecisionsItemSchema).meta(Unrestricted),
    entitlements: z.record(z.string(), ServerEvaluationPayloadEntitlementsValueSchema).optional().meta(Unrestricted),
    theme: z.record(z.string(), z.unknown()).optional().meta(Unrestricted),
    trial_status: ServerEvaluationPayloadTrialStatusSchema.optional().meta(Unrestricted),
    user_context: ServerEvaluationPayloadUserContextSchema.optional().meta(Pii),
  })
    .meta({ id: 'ServerEvaluationPayload', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External });
