/**
 * Plan schemas — Zod definitions for pricing plans.
 *
 * These are the single source of truth for Plan types.
 * TypeScript types are inferred via z.infer<>.
 */
import { z } from 'zod';
import { BillingCadenceSchema, ConfigVersionFields, CurrencySchema, IdField, TenantIdField, TimestampFields, NameField, HandleField, DescriptionField, MetadataField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
  toWritableSchema,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Financial } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { External } = SchemaExposure;

// ── Plan tier ────────────────────────────────────────────────────────────────

export const PlanTierSchema =
  z.enum([
    'free',
    'starter',
    'pro',
    'business',
    'enterprise',
    'custom',
  ])
    .meta({
      id: 'PlanTier',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': External,
    }
);

export const PlanStatusSchema =
  z.enum(['active', 'archived'])
    .meta({
      id: 'PlanStatus',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': External,
    }
);

export const PlanVisibilitySchema =
  z.enum(['public', 'unlisted', 'legacy'])
    .meta({
      id: 'PlanVisibility',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': External,
    }
);

export const PricingModelSchema =
  z.enum(['flat', 'per_unit', 'tiered', 'metered'])
    .meta({
      id: 'PricingModel',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Plan schema ──────────────────────────────────────────────────────────────

export const PlanSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    slug: (HandleField).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
    tier: (PlanTierSchema).meta(Unrestricted),
    tier_position: (z.number().int().min(0).default(0)).meta(Unrestricted),
    status: (PlanStatusSchema.default('active')).meta(Unrestricted),
    is_default: (z.boolean().default(false)).meta(Unrestricted),
    default_currency: (CurrencySchema).meta(Financial),
    billing_cadence: (BillingCadenceSchema).meta(Unrestricted),
    price_cents: (z.number().int().min(0)).meta(Financial),
    currency: (CurrencySchema).meta(Financial),
    seat_limit: (z.number().int().min(0).nullable().default(null)).meta(Unrestricted),
    trial_days: (z.number().int().min(0).default(0)).meta(Unrestricted),
    features: (z.record(z.string(), z.union([z.boolean(), z.number(), z.string()])).default({})).meta(Unrestricted),
    stripe_product_id: (z.string().optional()).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
    sort_order: (z.number().int().default(0)).meta(Unrestricted),
  })
    .meta({
      id: 'Plan',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Plan rule ────────────────────────────────────────────────────────────────

export const PlanRuleSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    plan_id: (z.string().min(1)).meta(Unrestricted),
    billing_period: (z.enum(['monthly', 'annual', 'custom'])).meta(Unrestricted),
    segment_id: (z.string().nullable().default(null)).meta(Unrestricted),
    price_amount: (z.number().min(0)).meta(Financial),
    pricing_model: (PricingModelSchema).meta(Unrestricted),
    visibility: (PlanVisibilitySchema.default('public')).meta(Unrestricted),
    stripe_price_id: (z.string().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'PlanRule',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Add-on ───────────────────────────────────────────────────────────────────

export const AddOnSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    status: (PlanStatusSchema.default('active')).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
    sort_order: (z.number().int().default(0)).meta(Unrestricted),
  })
    .meta({
      id: 'AddOn',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

export const AddOnVariationSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    addon_id: (z.string().min(1)).meta(Unrestricted),
    billing_period: (z.enum(['monthly', 'annual', 'custom'])).meta(Unrestricted),
    segment_id: (z.string().nullable().default(null)).meta(Unrestricted),
    price_amount: (z.number().min(0)).meta(Financial),
    pricing_model: (PricingModelSchema).meta(Unrestricted),
    visibility: (PlanVisibilitySchema.default('public')).meta(Unrestricted),
    stripe_price_id: (z.string().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'AddOnVariation',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

