/**
 * Hydration adapter — creates domain providers from a ServerEvaluationPayload.
 *
 * Used for server→client handoff: the server evaluates decisions and serializes
 * the result as a ServerEvaluationPayload, which the client hydrates into
 * static providers (avoiding redundant API calls or re-evaluation).
 */

import type { ServerEvaluationPayload } from '@revt-eng/schema';
import type {
  AnyDomainProvider,
  EntitlementProviderState,
  PlanProviderState,
  SegmentProviderState,
  ThemeProviderState,
  TraitsProviderState,
} from '../providers/types';
import type { EntitlementResult } from '../types';

export interface HydrationAdapterOptions {
  payload: ServerEvaluationPayload;
  cacheTtlMs?: number;
}

/**
 * Create domain providers from a pre-evaluated ServerEvaluationPayload.
 *
 * Each provider returns data extracted from the payload — no network calls.
 * Register these providers in a DecisionEngine for client-side rendering
 * of server-evaluated decisions.
 */
export function createHydrationProviders(options: HydrationAdapterOptions): AnyDomainProvider[] {
  const { payload, cacheTtlMs } = options;
  const providers: AnyDomainProvider[] = [];

  // Plan provider — from user context
  if (payload.user_context) {
    const userCtx = payload.user_context as Record<string, unknown>;
    const planProvider: AnyDomainProvider = {
      domain: 'plan' as const,
      cacheTtlMs,
      resolve: (): PlanProviderState => ({
        currentPlanHandle: (userCtx.plan_handle as string) ?? 'unknown',
        currentPlanName: userCtx.plan_name as string | undefined,
        billingPeriod: userCtx.billing_period as PlanProviderState['billingPeriod'],
        trialActive: userCtx.trial_active as boolean | undefined,
        trialDaysRemaining: userCtx.trial_days_remaining as number | undefined,
      }),
    };
    providers.push(planProvider);
  }

  // Entitlements provider — from entitlement checks
  if (payload.entitlements) {
    const entitlements = payload.entitlements as Record<string, unknown>;
    const entitlementProvider: AnyDomainProvider = {
      domain: 'entitlements' as const,
      cacheTtlMs,
      resolve: (): EntitlementProviderState => {
        const entries: Record<string, EntitlementResult> = {};
        for (const [handle, value] of Object.entries(entitlements)) {
          entries[handle] = value as EntitlementResult;
        }
        return { entries };
      },
    };
    providers.push(entitlementProvider);
  }

  // Segments provider — from user context
  if (payload.user_context) {
    const userCtx = payload.user_context as Record<string, unknown>;
    if (Array.isArray(userCtx.segment_ids)) {
      const segmentProvider: AnyDomainProvider = {
        domain: 'segments' as const,
        cacheTtlMs,
        resolve: (): SegmentProviderState => ({
          segmentIds: userCtx.segment_ids as string[],
        }),
      };
      providers.push(segmentProvider);
    }
  }

  // Traits provider — from user context
  if (payload.user_context) {
    const userCtx = payload.user_context as Record<string, unknown>;
    if (userCtx.traits && typeof userCtx.traits === 'object') {
      const traitsProvider: AnyDomainProvider = {
        domain: 'traits' as const,
        cacheTtlMs,
        resolve: (): TraitsProviderState => ({
          traits: userCtx.traits as Record<string, string | number | boolean>,
        }),
      };
      providers.push(traitsProvider);
    }
  }

  // Theme provider
  if (payload.theme) {
    const themeProvider: AnyDomainProvider = {
      domain: 'theme' as const,
      cacheTtlMs,
      resolve: (): ThemeProviderState => ({
        overrides: payload.theme as Record<string, unknown>,
      }),
    };
    providers.push(themeProvider);
  }

  return providers;
}
