/**
 * Pure utility functions extracted from web-sdk/customer-side.ts.
 *
 * No side effects, no browser APIs, no `this` — just transforms.
 */

import type {
  ExportedConfig,
  UserUsageEntry,
  UserPlanContext,
} from '@revt-eng/schema';
import type { PlacementOutput } from './types';
import type { PlacementCapRule, CapPeriod } from './state/types';

// ── Type guards ─────────────────────────────────────────────────────

/** JSON-serializable value for SDK data bags. */
export type JsonValue =
  | string
  | number
  | boolean
  | null
  | JsonValue[]
  | { [key: string]: JsonValue };

/** JSON-serializable object (record of JsonValue). */
export type JsonObject = { [key: string]: JsonValue };

export function isRecord(value: unknown): value is JsonObject { // sdk-ok: boundary-parse
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

// ── Array / string utilities ────────────────────────────────────────

export function ensureArray(value?: string[]): string[] {
  return Array.isArray(value) ? value.filter((item) => item.trim().length > 0) : [];
}

export function firstStringValue(...values: unknown[]): string | undefined { // sdk-ok: boundary-parse
  for (const value of values) {
    if (typeof value === 'string' && value.trim().length > 0) {
      return value;
    }
  }
  return undefined;
}

export function parseNumberish(value: unknown): number | null { // sdk-ok: boundary-parse
  if (typeof value === 'number' && Number.isFinite(value)) return value;
  if (typeof value === 'string') {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : null;
  }
  return null;
}

// ── Route / slug normalization ──────────────────────────────────────

export function normalizedRoute(pathname: string): string {
  return pathname
    .trim()
    .toLowerCase()
    .replace(/\/+$/, '') || '/';
}

export function sanitizeSlug(input: string, fallbackSuffix?: string): string {
  const normalized = String(input || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

  return normalized || `slot-${fallbackSuffix ?? 'unknown'}`;
}

// ── Event normalization ─────────────────────────────────────────────

export function normalizeEventType(value: string): string {
  const compact = String(value || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_')
    .replace(/-+/g, '_');

  if (!compact) return 'unknown_event';

  switch (compact) {
    case 'pageview':
    case 'page_view':
      return 'clickstream_page_view';
    case 'click':
      return 'clickstream_click';
    case 'doc_view':
      return 'clickstream_doc_view';
    case 'checkout_started':
      return 'clickstream_checkout_started';
    case 'checkout_completed':
      return 'clickstream_checkout_completed';
    case 'payment_failed':
      return 'clickstream_payment_failed';
    default:
      return compact;
  }
}

// ── Cap / period helpers ────────────────────────────────────────────

export function parseCapRule(input: unknown): PlacementCapRule | null { // sdk-ok: boundary-parse
  if (!isRecord(input)) return null;
  const count = Number(input.count);
  const period = typeof input.period === 'string' ? input.period : '';
  if (!Number.isFinite(count) || count <= 0) return null;
  if (period !== 'session' && period !== 'day' && period !== 'week' && period !== 'month' && period !== 'lifetime') {
    return null;
  }
  return { count, period };
}

export function periodWindowStart(period: CapPeriod, nowMs: number): number {
  if (period === 'session' || period === 'lifetime') return 0;
  if (period === 'day') return nowMs - (24 * 60 * 60 * 1000);
  if (period === 'week') return nowMs - (7 * 24 * 60 * 60 * 1000);
  return nowMs - (30 * 24 * 60 * 60 * 1000);
}

// ── Lookup key parsing ──────────────────────────────────────────────

export type LocalLookupParts = {
  slotId: string;
  surfaceType: string;
  entitlementHandle: string;
  planHandle: string;
  placementHandle: string;
};

export function parseLocalLookupKey(key: string): LocalLookupParts {
  const parts = key.split('::');
  return {
    slotId: parts[0] || '',
    surfaceType: parts[1] || '',
    entitlementHandle: parts[2] || '',
    planHandle: parts[3] || '',
    placementHandle: parts[4] || '',
  };
}

// ── Plan target matching ────────────────────────────────────────────

export function planTargetAliases(planHandle: string): string[] {
  const normalized = planHandle.trim().toLowerCase();
  if (!normalized) return [];

  if (normalized === 'starter' || normalized === 'free') {
    return ['starter', 'free'];
  }
  if (normalized === 'professional' || normalized === 'pro') {
    return ['professional', 'pro'];
  }
  if (normalized === 'enterprise') {
    return ['enterprise'];
  }

  return [normalized];
}

export function placementTargetPlanIds(output: PlacementOutput): string[] {
  const root = output as JsonObject;
  const directTarget = isRecord(root.target) ? root.target : undefined;
  const directPlanIds = Array.isArray(directTarget?.plan_ids)
    ? directTarget.plan_ids.filter((item): item is string => typeof item === 'string')
    : [];
  if (directPlanIds.length > 0) return directPlanIds;

  const content = isRecord(output.content) ? output.content : {};
  const embeddedPlanIds = Array.isArray(content.__target_plan_ids)
    ? (content.__target_plan_ids as unknown[]).filter((item): item is string => typeof item === 'string')
    : [];
  return embeddedPlanIds;
}

export function placementMatchesPlanTarget(output: PlacementOutput, planHandle?: string): boolean {
  const targetPlanIds = placementTargetPlanIds(output);
  if (targetPlanIds.length === 0 || !planHandle) return true;

  const aliases = planTargetAliases(planHandle);
  if (aliases.length === 0) return true;

  return targetPlanIds.some((target) => {
    const normalizedTarget = target.toLowerCase();
    return aliases.some((alias) => (
      normalizedTarget === alias
      || normalizedTarget.endsWith(`_${alias}`)
      || normalizedTarget.includes(alias)
    ));
  });
}

// ── Usage token helpers ─────────────────────────────────────────────

export function usageTokenPrefixFromEntitlementId(entitlementId: string): string {
  return entitlementId
    .replace(/_(minutes|minute|credits|credit|seats|seat)$/i, '')
    .replace(/_usage$/i, '')
    .trim()
    .toLowerCase();
}

export function sanitizeUsageTokenPrefix(value: string): string {
  return value
    .trim()
    .toLowerCase()
    .replace(/\s+/g, '_')
    .replace(/[^a-z0-9_]/g, '');
}

export function looksGenericUsageUnit(unit: string): boolean {
  return unit === 'minutes'
    || unit === 'minute'
    || unit === 'credits'
    || unit === 'credit'
    || unit === 'seats'
    || unit === 'seat'
    || unit === 'units'
    || unit === 'unit';
}

// ── Usage extraction ────────────────────────────────────────────────

export function usageAmountsFromEntries(usage: Record<string, UserUsageEntry> | undefined): Record<string, number> {
  if (!usage) return {};
  const amounts: Record<string, number> = {};
  for (const [key, entry] of Object.entries(usage)) {
    if (isRecord(entry) && typeof entry.amount === 'number') {
      amounts[key] = entry.amount;
    } else if (typeof entry === 'number') {
      amounts[key] = entry as number;
    }
  }
  return amounts;
}

// ── Config plan name lookup ─────────────────────────────────────────

export function configuredPlanNameFromExportedConfig(
  exportedConfig: ExportedConfig | undefined,
  planValue: string | UserPlanContext | undefined,
): string | undefined {
  if (!exportedConfig) return undefined;
  if (!Array.isArray(exportedConfig.plans)) return undefined;

  let planId: string | undefined;
  if (typeof planValue === 'string' && planValue.trim().length > 0) {
    planId = planValue.trim();
  } else if (isRecord(planValue) && typeof planValue.id === 'string' && planValue.id.trim().length > 0) {
    planId = planValue.id.trim();
  }
  if (!planId) return undefined;

  const normalizedPlan = planId.toLowerCase();

  for (const rawPlan of exportedConfig.plans) {
    if (!isRecord(rawPlan)) continue;

    const id = typeof rawPlan.id === 'string' ? rawPlan.id.toLowerCase() : '';
    const handle = typeof rawPlan.unique_handle === 'string'
      ? rawPlan.unique_handle.toLowerCase()
      : '';

    if (id === normalizedPlan || handle === normalizedPlan || id.endsWith(`_${normalizedPlan}`)) {
      const name = typeof rawPlan.name === 'string' ? rawPlan.name.trim() : '';
      if (name.length > 0) return name;
    }
  }

  return undefined;
}

// ── Config validation ───────────────────────────────────────────────

const REQUIRED_EXPORTED_CONFIG_ARRAY_FIELDS = [
  'plans',
  'entitlements',
  'entitlement_rules',
  'segments',
  'content_ui_paths',
  'surface_templates',
] as const;

export function parseExportedConfigOrThrow(raw: unknown, source: string): ExportedConfig | undefined { // sdk-ok: boundary-parse
  if (raw === undefined) return undefined;
  if (!isRecord(raw)) {
    throw new Error(`Invalid ${source}: expected top-level object`);
  }
  if (typeof raw.version !== 'string') {
    throw new Error(`Invalid ${source}: missing string "version"`);
  }
  if (typeof raw.exported_at !== 'string') {
    throw new Error(`Invalid ${source}: missing string "exported_at"`);
  }
  for (const key of REQUIRED_EXPORTED_CONFIG_ARRAY_FIELDS) {
    if (!Array.isArray(raw[key])) {
      throw new Error(`Invalid ${source}: missing array "${key}"`);
    }
  }
  return raw as unknown as ExportedConfig; // sdk-ok: boundary-parse
}

// ── Placement scoring ───────────────────────────────────────────────

export function categoryBucket(category: string): number {
  const normalized = String(category || '').trim().toLowerCase();
  if (!normalized) return 99;

  if (normalized.includes('gated') || normalized.includes('entitlement')) return 0;
  if (normalized.includes('fixed')) return 1;
  if (normalized.includes('usage') || normalized.includes('credit') || normalized.includes('seat') || normalized.includes('quota')) return 2;
  if (normalized.includes('trial')) return 3;
  if (normalized.includes('conversion') || normalized.includes('expansion') || normalized.includes('upsell')) return 4;
  if (normalized.includes('retention') || normalized.includes('winback') || normalized.includes('churn')) return 5;
  return 99;
}

export function placementScore(output: PlacementOutput): number {
  const root = output as JsonObject;
  const content = isRecord(output.content) ? output.content : {};

  const scored = [
    parseNumberish(root.score),
    parseNumberish(root.ltv_propensity_score),
    parseNumberish(content.score),
    parseNumberish(content.ltv_propensity_score),
    parseNumberish(content.ranking_score),
  ].find((value): value is number => value !== null);

  return scored ?? 0;
}

export function placementPriority(output: PlacementOutput): number {
  const root = output as JsonObject;
  const content = isRecord(output.content) ? output.content : {};

  const priority = [
    parseNumberish(root.priority),
    parseNumberish(root.placement_priority),
    parseNumberish(content.priority),
    parseNumberish(content.placement_priority),
  ].find((value): value is number => value !== null);

  return priority ?? 0;
}

/**
 * Proximity-to-constraint score for priority-tier placements (usage/credit/seat + trial).
 *
 * Reads from content bag: `usage_percent`, `trial_percent_elapsed`, `threshold_percent`.
 * Higher value = closer to constraint = higher priority.
 * Falls back to `placementScore()` when no proximity data is available.
 */
export function proximityScore(output: PlacementOutput): number {
  const content = isRecord(output.content) ? output.content : {};

  const proximity = [
    parseNumberish(content.usage_percent),
    parseNumberish(content.trial_percent_elapsed),
    parseNumberish(content.threshold_percent),
  ].find((value): value is number => value !== null);

  return proximity ?? placementScore(output);
}

/**
 * Whether a surface type is safe for unprompted rendering (no user action required).
 *
 * Modal and full_page are interruptive — they should only render at safe moments
 * (user action, task completion, natural transition). All other types are safe on render.
 */
export function isModalSafeSurfaceType(surfaceType: string): boolean {
  const normalized = surfaceType.trim().toLowerCase();
  return normalized !== 'modal' && normalized !== 'full_page';
}

export function serverOrder(output: PlacementOutput): number | null {
  const root = output as JsonObject;
  const content = isRecord(output.content) ? output.content : {};
  const ordered = [
    parseNumberish(root.server_order),
    parseNumberish(root.order),
    parseNumberish(root.rank),
    parseNumberish(root.order_index),
    parseNumberish(content.server_order),
    parseNumberish(content.order),
    parseNumberish(content.rank),
    parseNumberish(content.order_index),
  ].find((value): value is number => value !== null);
  return ordered ?? null;
}

// ── Milestone version helpers ───────────────────────────────────────

export function milestoneVersion(output: PlacementOutput): string | null {
  const content = isRecord(output.content) ? output.content : {};
  const direct = content.template_version;
  if (typeof direct === 'string' && direct.trim().length > 0) return direct.trim();
  const numeric = parseNumberish(direct);
  if (numeric !== null) return String(numeric);

  const fallback = content.milestone_version;
  if (typeof fallback === 'string' && fallback.trim().length > 0) return fallback.trim();
  const fallbackNumeric = parseNumberish(fallback);
  return fallbackNumeric !== null ? String(fallbackNumeric) : null;
}

export function supersededVersions(output: PlacementOutput): string[] {
  const content = isRecord(output.content) ? output.content : {};
  const raw = content.supersedes_template_version;
  if (Array.isArray(raw)) {
    return raw
      .map((item) => (typeof item === 'string' ? item.trim() : parseNumberish(item)))
      .filter((item): item is string | number => item !== null && item !== '')
      .map((item) => String(item));
  }
  if (typeof raw === 'string' && raw.trim().length > 0) return [raw.trim()];
  const numeric = parseNumberish(raw);
  return numeric !== null ? [String(numeric)] : [];
}

// ── Stable JSON stringify ───────────────────────────────────────────

export function stableStringify(value: unknown): string { // sdk-ok: boundary-parse
  if (value == null || typeof value !== 'object') {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return `[${value.map((item) => stableStringify(item)).join(',')}]`;
  }
  const entries = Object.entries(value as JsonObject).sort(([left], [right]) => left.localeCompare(right));
  return `{${entries.map(([key, item]) => `${JSON.stringify(key)}:${stableStringify(item)}`).join(',')}}`;
}

// ── Trial status validation ─────────────────────────────────────────

export interface TrialContext {
  in_trial: boolean;
  trial_type?: string;
  plan_handle?: string;
  day_number?: number;
  days_remaining?: number;
}

export function validateTrialStatusShape(data: unknown): TrialContext { // sdk-ok: boundary-parse
  if (!isRecord(data)) return { in_trial: false };
  return {
    in_trial: typeof data.in_trial === 'boolean' ? data.in_trial : false,
    ...(typeof data.trial_type === 'string' ? { trial_type: data.trial_type } : {}),
    ...(typeof data.plan_handle === 'string' ? { plan_handle: data.plan_handle } : {}),
    ...(typeof data.day_number === 'number' ? { day_number: data.day_number } : {}),
    ...(typeof data.days_remaining === 'number' ? { days_remaining: data.days_remaining } : {}),
  };
}
