/**
 * Customer schemas — Zod definitions for customers, identities, and overrides.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, MetadataField, NullableDatetimeField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Pii } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Identity ─────────────────────────────────────────────────────────────────

export const IdentitySchema = 
  z.object({
    external_id: (z.string().min(1)).meta(Pii),
    traits: (z.record(z.string(), z.unknown()).default({})).meta(Pii),
    plan_id: (z.string().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'Identity',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

export const CustomerSchema = 
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    external_id: (z.string().min(1)).meta(Pii),
    identity: (IdentitySchema).meta(Pii),
    stripe_customer_id: (z.string().optional()).meta(Unrestricted),
    current_plan_id: (z.string().optional()).meta(Unrestricted),
    subscription_status: (z.enum(['active', 'past_due', 'canceled', 'trialing', 'unpaid', 'none']).default('none')).meta(Unrestricted),
    status: (z.enum(['active', 'churned', 'trial', 'suspended']).default('active')).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({
      id: 'Customer',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Customer overrides ───────────────────────────────────────────────────────

export const CustomerOverrideDurationSchema = 
  z.enum([
    'permanent',
    'for_duration',
  ])
    .meta({
      id: 'CustomerOverrideDuration',
      'x-revturbine-schema-persistence': Transient,
      'x-revturbine-schema-exposure': Internal,
    }
);

export const CustomerOverrideTypeSchema =
  z.enum(['grant_plan', 'grant_addon', 'grant_entitlement'])
    .meta({ id: 'CustomerOverrideType', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const CustomerOverrideStatusSchema =
  z.enum(['active', 'expired', 'revoked'])
    .meta({ id: 'CustomerOverrideStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const CustomerOverrideSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    customer_id: (z.string().min(1)).meta(Pii),
    customer_id_list: (z.array(z.string()).optional()).meta(Pii),
    override_type: (CustomerOverrideTypeSchema).meta(Unrestricted),
    target_id: (z.string().min(1)).meta(Unrestricted),
    value: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    duration_type: (CustomerOverrideDurationSchema.default('permanent')).meta(Unrestricted),
    duration_value: (z.string().optional()).meta(Unrestricted),
    expiry_date: (NullableDatetimeField).meta(Unrestricted),
    status: (CustomerOverrideStatusSchema.default('active')).meta(Unrestricted),
    reason: (z.string().max(500).optional()).meta(Unrestricted),
    created_by: (z.string().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'CustomerOverride',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const customerPaths: ZodOpenApiPathsObject = {
  '/api/customers': {
    get: operation({
      operationId: 'listCustomers',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List customers',
      tags: ['customers'],
      responses: { '200': { description: 'Customer list', content: { 'application/json': { schema: ListEnvelope(CustomerSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customers', persistence: { table: 'customers', mode: 'list' } },
    }),
  },
  '/api/customers/{customerId}': {
    get: operation({
      operationId: 'getCustomer',
      requestParams: { path: z.object({ customerId: z.string() }) },
      summary: 'Get customer by ID',
      tags: ['customers'],
      responses: { '200': { description: 'Customer', content: { 'application/json': { schema: CustomerSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customers', persistence: { table: 'customers', mode: 'get' } },
    }),
  },
  '/api/customer-overrides': {
    get: operation({
      operationId: 'listCustomerOverrides',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List customer overrides',
      tags: ['customers'],
      responses: { '200': { description: 'Override list', content: { 'application/json': { schema: ListEnvelope(CustomerOverrideSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createCustomerOverride',
      summary: 'Create customer override',
      tags: ['customers'],
      requestBody: { required: true, content: { 'application/json': { schema: CustomerOverrideSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: CustomerOverrideSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'create' } },
    }),
  },
  '/api/customer-overrides/{overrideId}': {
    get: operation({
      operationId: 'getCustomerOverride',
      requestParams: { path: z.object({ overrideId: z.string() }) },
      summary: 'Get customer override',
      tags: ['customers'],
      responses: { '200': { description: 'Override', content: { 'application/json': { schema: CustomerOverrideSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updateCustomerOverride',
      requestParams: { path: z.object({ overrideId: z.string() }) },
      summary: 'Update customer override',
      tags: ['customers'],
      requestBody: { required: true, content: { 'application/json': { schema: CustomerOverrideSchema.partial() } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: CustomerOverrideSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deleteCustomerOverride',
      requestParams: { path: z.object({ overrideId: z.string() }) },
      summary: 'Delete customer override',
      tags: ['customers'],
      responses: { '204': { description: 'Deleted' } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'delete' } },
    }),
  },
  '/api/customer-overrides/{overrideId}/revoke': {
    post: operation({
      operationId: 'revokeCustomerOverride',
      requestParams: { path: z.object({ overrideId: z.string() }) },
      summary: 'Revoke an active customer override',
      tags: ['customers'],
      responses: { '200': { description: 'Revoked', content: { 'application/json': { schema: CustomerOverrideSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'update' } },
    }),
  },
  '/api/customer-overrides/{overrideId}/duplicate': {
    post: operation({
      operationId: 'duplicateCustomerOverride',
      requestParams: { path: z.object({ overrideId: z.string() }) },
      summary: 'Duplicate customer override for another customer',
      tags: ['customers'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ customer_id: z.string() }) } } },
      responses: { '201': { description: 'Duplicated', content: { 'application/json': { schema: CustomerOverrideSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'customer-overrides', persistence: { table: 'customerOverrides', mode: 'create' } },
    }),
  },
};
