/**
 * CryptoProvider — injectable hash abstraction.
 *
 * Decouples placement ID generation and fingerprinting from
 * runtime-specific crypto APIs (browser `crypto.subtle` vs Node `crypto`).
 */

/* ------------------------------------------------------------------ */
/*  Interface                                                          */
/* ------------------------------------------------------------------ */

export interface CryptoProvider {
  /** SHA-256 hash → URL-safe base64 string. */
  sha256Base64Url(input: string): Promise<string>;
  /** Cryptographically random hex string of `length` hex chars. */
  randomHex(length: number): string;
}

/* ------------------------------------------------------------------ */
/*  Fallback (FNV-1a) — available everywhere, no crypto required       */
/* ------------------------------------------------------------------ */

export function base64UrlFromBytes(bytes: Uint8Array): string {
  let binary = '';
  bytes.forEach((value) => {
    binary += String.fromCharCode(value);
  });

  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

export function fallbackHashBase64Url(input: string): string {
  let hash = 2166136261;
  for (let index = 0; index < input.length; index += 1) {
    hash ^= input.charCodeAt(index);
    hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24);
  }

  const buffer = new Uint8Array(8);
  const view = new DataView(buffer.buffer);
  view.setUint32(0, hash >>> 0);
  view.setUint32(4, (hash * 1103515245) >>> 0);
  return base64UrlFromBytes(buffer);
}

/**
 * FallbackCryptoProvider — uses FNV-1a for hashing and Math.random for hex.
 *
 * Use this when no runtime crypto is available. NOT cryptographically secure.
 */
export const FallbackCryptoProvider: CryptoProvider = {
  async sha256Base64Url(input: string): Promise<string> {
    return fallbackHashBase64Url(input);
  },
  randomHex(length: number): string {
    const chars = '0123456789abcdef';
    let result = '';
    for (let i = 0; i < length; i += 1) {
      result += chars[Math.floor(Math.random() * 16)];
    }
    return result;
  },
};
