/**
 * LocalRuntime — standard composition of core subsystems for local-only
 * (client-side or embedded) placement decisioning.
 *
 * Composes: DomainProviderRegistry + DecisionEngine + InteractionTracker +
 * CapEnforcer + ImpressionHistory + local resolver. All pure, no browser APIs.
 *
 * @example
 * ```ts
 * import { LocalRuntime, createStaticProviders, InMemoryStorage } from '@revt-eng/core';
 *
 * const runtime = new LocalRuntime({
 *   tenantId: 'tenant_abc',
 *   userId: 'user_123',
 *   exportedConfig: myConfig,
 *   providers: createStaticProviders({ config: myConfig, planHandle: 'pro' }),
 *   storage: new InMemoryStorage(),
 * });
 *
 * const decision = await runtime.getPlacementDecision({ placementId: 'slot_1', userId: 'user_123' });
 * const entitlement = await runtime.checkEntitlement('feature_x');
 * ```
 */

import type { ExportedConfig } from '@revt-eng/schema';
import { DomainProviderRegistry } from '../providers/registry';
import type { AnyDomainProvider, ResolvedProviderContext } from '../providers/types';
import { DecisionEngine } from '../../decisions/controllers/engine';
import type { DecisionEngineConfig } from '../../decisions/controllers/engine';
import type { DecisionEngineOptions, EntitlementCheckResult } from '../../decisions/models/types';
import { InteractionTracker } from '../state/interaction-tracker';
import type { InteractionTrackerOptions } from '../state/interaction-tracker';
import { CapEnforcer } from '../state/cap-enforcer';
import { ImpressionHistory } from '../state/impression-history';
import { InMemoryImpressionStore } from '../state/impression-history-stores';
import type { ImpressionHistoryStore } from '../state/impression-history-types';
import { InMemoryStorage } from '../state/storage';
import type { RevTurbineStorage } from '../state/storage';
import { createStaticPlacementResolver } from '../../placements/controllers/local-resolver';
import type { LocalPlacementDataset } from '../../placements/controllers/local-resolver';
import { evaluateSegments } from '../../segments/controllers/segments';
import { buildTargetingState } from '../../user/controllers/user-context';
import type { UserContextSnapshot, TargetingState } from '../../user/controllers/user-context';
import { deriveLocalEntitlementFromConfiguredRules } from '../../entitlements/controllers/entitlement-check';
import { derivePlacementPersonalizationTokens } from '../../placements/controllers/token-derivation';
import type {
  RevTurbinePlacementDecision,
  RevTurbinePlacementDecisionInput,
  RevTurbinePlacementRecord,
  RevTurbineEntitlementContext,
  EntitlementResult,
  PlacementOutput,
  PersonalizationContext,
  UserTargetingContext,
} from '../types';
import type { RevTurbineTreatmentInteractionInput } from '../state/types';

/* ------------------------------------------------------------------ */
/*  Options                                                            */
/* ------------------------------------------------------------------ */

export interface LocalRuntimeOptions {
  /** Tenant identifier. */
  tenantId: string;
  /** Current user identifier. */
  userId: string;

  /** Full ExportedConfig for local resolution. */
  exportedConfig: ExportedConfig;
  /** Pre-built domain providers (from createStaticProviders, etc.). */
  providers: AnyDomainProvider[];

  /**
   * Optional pre-built placements dataset. If not provided, derived from
   * `exportedConfig.placements`.
   */
  placements?: LocalPlacementDataset;

  /**
   * Optional custom placement resolver. When provided, takes precedence
   * over the built-in static resolver.
   */
  customResolver?: DecisionEngineConfig['placementResolver'];

  /** Storage backend for interaction state and caps. Default: InMemoryStorage. */
  storage?: RevTurbineStorage;
  /** Impression history store backend. Default: InMemoryImpressionStore. */
  impressionStore?: ImpressionHistoryStore;

  /** Decision engine behavior flags. */
  engineOptions?: DecisionEngineOptions;
  /** Interaction tracker options. */
  interactionOptions?: Partial<Pick<InteractionTrackerOptions, 'defaultDismissCooldownMs' | 'defaultRemindLaterMs'>>;
}

/* ------------------------------------------------------------------ */
/*  LocalRuntime                                                       */
/* ------------------------------------------------------------------ */

export class LocalRuntime {
  readonly tenantId: string;
  readonly registry: DomainProviderRegistry;
  readonly engine: DecisionEngine;
  readonly interactionTracker: InteractionTracker;
  readonly capEnforcer: CapEnforcer;
  readonly impressionHistory: ImpressionHistory;

  private readonly exportedConfig: ExportedConfig;
  private readonly registeredPlacements = new Map<string, RevTurbinePlacementRecord>();
  private userId: string;

  constructor(options: LocalRuntimeOptions) {
    this.tenantId = options.tenantId;
    this.userId = options.userId;
    this.exportedConfig = options.exportedConfig;

    const storage = options.storage ?? new InMemoryStorage();

    // Provider registry
    this.registry = new DomainProviderRegistry();
    for (const p of options.providers) {
      this.registry.register(p);
    }

    // Interaction tracker
    this.interactionTracker = new InteractionTracker({
      storage,
      tenantId: options.tenantId,
      userId: options.userId,
      ...options.interactionOptions,
    });

    // Cap enforcer
    this.capEnforcer = new CapEnforcer({
      storage,
      tenantId: options.tenantId,
      userId: options.userId,
    });

    // Impression history
    this.impressionHistory = new ImpressionHistory({
      store: options.impressionStore ?? new InMemoryImpressionStore(),
      userId: options.userId,
    });

    // Placement resolver
    const placementResolver = options.customResolver ?? this.buildPlacementResolver(options);

    // Decision engine
    this.engine = new DecisionEngine({
      registry: this.registry,
      interactionTracker: this.interactionTracker,
      capEnforcer: this.capEnforcer,
      options: options.engineOptions,
      placements: this.registeredPlacements,
      placementResolver,
    });
  }

  /* ---------------------------------------------------------------- */
  /*  Placement registration                                           */
  /* ---------------------------------------------------------------- */

  /**
   * Register a placement record so the engine can look it up by ID.
   */
  registerPlacement(record: RevTurbinePlacementRecord): void {
    this.registeredPlacements.set(record.id, record);
  }

  /* ---------------------------------------------------------------- */
  /*  Decision pipeline                                                */
  /* ---------------------------------------------------------------- */

  /**
   * Evaluate a single placement decision through the full pipeline:
   * suppression → providers → segments → resolver → caps → decision.
   */
  async getPlacementDecision(
    input: RevTurbinePlacementDecisionInput,
  ): Promise<RevTurbinePlacementDecision> {
    return this.engine.evaluate(input);
  }

  /**
   * Evaluate multiple placement decisions in parallel.
   */
  async getPlacementDecisions(
    inputs: RevTurbinePlacementDecisionInput[],
  ): Promise<RevTurbinePlacementDecision[]> {
    return this.engine.evaluateBatch(inputs);
  }

  /* ---------------------------------------------------------------- */
  /*  Entitlement checking                                             */
  /* ---------------------------------------------------------------- */

  /**
   * Check entitlement access locally using ExportedConfig rules.
   */
  async checkEntitlement(
    handle: string,
    context?: RevTurbineEntitlementContext,
  ): Promise<EntitlementResult> {
    // Try engine first (uses provider context)
    const engineResult = await this.engine.checkEntitlement(handle, context);

    // If the engine has no provider, fall back to config rules
    if (engineResult.reason === 'no_entitlement_provider') {
      return this.deriveEntitlementFromConfig(handle, context);
    }

    return engineResult as EntitlementResult;
  }

  /* ---------------------------------------------------------------- */
  /*  Interaction tracking                                             */
  /* ---------------------------------------------------------------- */

  /**
   * Record a treatment interaction (dismiss, snooze, cta_clicked, etc.).
   */
  trackInteraction(input: RevTurbineTreatmentInteractionInput): void {
    this.engine.trackInteraction(input);
  }

  /**
   * Clear suppression for a placement.
   */
  clearSuppression(placementId: string, userId?: string): void {
    this.interactionTracker.clearSuppression(placementId, userId ?? this.userId);
  }

  /* ---------------------------------------------------------------- */
  /*  Provider context                                                 */
  /* ---------------------------------------------------------------- */

  /**
   * Resolve all domain providers and return the merged context.
   */
  async resolveProviders(): Promise<ResolvedProviderContext> {
    return this.registry.resolveAll();
  }

  /* ---------------------------------------------------------------- */
  /*  Segment evaluation                                               */
  /* ---------------------------------------------------------------- */

  /**
   * Evaluate segments for a set of user traits.
   */
  evaluateSegments(
    traits: Record<string, string | number | boolean>,
  ): string[] {
    const segments = this.exportedConfig.segments ?? [];
    return evaluateSegments(segments as Parameters<typeof evaluateSegments>[0], traits);
  }

  /* ---------------------------------------------------------------- */
  /*  Targeting state                                                  */
  /* ---------------------------------------------------------------- */

  /**
   * Build the full targeting state from a user context snapshot.
   */
  buildTargetingState(
    context: UserContextSnapshot,
    usageOverrides?: Record<string, number>,
  ): TargetingState {
    return buildTargetingState(context, this.exportedConfig, usageOverrides);
  }

  /* ---------------------------------------------------------------- */
  /*  Personalization tokens                                           */
  /* ---------------------------------------------------------------- */

  /**
   * Derive personalization tokens from the current provider state.
   */
  async derivePersonalizationTokens(
    base?: PersonalizationContext,
  ): Promise<Record<string, string | number>> {
    const providers = await this.registry.resolveAll();
    return derivePlacementPersonalizationTokens({
      userId: this.userId,
      providers,
      base,
    });
  }

  /* ---------------------------------------------------------------- */
  /*  User identity                                                    */
  /* ---------------------------------------------------------------- */

  /**
   * Switch the active user. Clears interaction/impression caches.
   */
  setUserId(userId: string): void {
    this.userId = userId;
    this.impressionHistory.setUserId(userId);
  }

  /** Current user ID. */
  getUserId(): string {
    return this.userId;
  }

  /* ---------------------------------------------------------------- */
  /*  Config access                                                    */
  /* ---------------------------------------------------------------- */

  /** Return the active ExportedConfig snapshot. */
  getExportedConfig(): ExportedConfig {
    return this.exportedConfig;
  }

  /* ---------------------------------------------------------------- */
  /*  Lifecycle                                                        */
  /* ---------------------------------------------------------------- */

  /**
   * Pre-warm caches (impression history, etc.) for synchronous access.
   */
  async hydrate(): Promise<void> {
    await this.impressionHistory.hydrate();
  }

  /**
   * Update domain providers. Clears and re-registers.
   */
  updateProviders(providers: AnyDomainProvider[]): void {
    this.registry.clear();
    for (const p of providers) {
      this.registry.register(p);
    }
  }

  /* ---------------------------------------------------------------- */
  /*  Internal                                                         */
  /* ---------------------------------------------------------------- */

  private buildPlacementResolver(
    options: LocalRuntimeOptions,
  ): DecisionEngineConfig['placementResolver'] {
    const dataset: LocalPlacementDataset = options.placements
      ?? { placements: options.exportedConfig.placements ?? [] };

    return createStaticPlacementResolver({
      placements: dataset,
      exportedConfig: options.exportedConfig,
      impressionHistory: this.impressionHistory,
    });
  }

  private deriveEntitlementFromConfig(
    handle: string,
    context?: RevTurbineEntitlementContext,
  ): EntitlementResult {
    const result = deriveLocalEntitlementFromConfiguredRules({
      handle,
      context,
      currentPlanHandle: '',
      segmentIds: new Set(),
      usageBalances: {},
      exportedConfig: this.exportedConfig,
    });

    return result ?? { status: 'allowed', allowed: true, reason: 'local_runtime_default_allow' };
  }
}
