/**
 * Placement schemas — Zod definitions for placements, payloads, variants, and surface slots.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, SurfaceTypeSchema, NameField, HandleField, DescriptionField, MetadataField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
  toWritableSchema,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

// Re-export SurfaceTypeSchema from core/common for backward compatibility
export { SurfaceTypeSchema };

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { External, Internal } = SchemaExposure;

export const PlacementCategorySchema =
  z.enum([
    'fixed', 'gated_feature', 'usage_limit', 'trial', 'other_conversion', 'retention',
  ])
    .meta({ id: 'PlacementCategory', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const PlacementStatusSchema =
  z.enum(['new', 'active', 'inactive'])
    .meta({ id: 'PlacementStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const PayloadStatusSchema =
  z.enum(['new', 'active', 'inactive'])
    .meta({ id: 'PayloadStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const CapPeriodSchema =
  z.enum(['session', 'day', 'week', 'month', 'lifetime'])
    .meta({ id: 'CapPeriod', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const PlacementCapRuleSchema =
  z.object({
    count: (z.number().int().positive()).meta(Unrestricted),
    period: (CapPeriodSchema).meta(Unrestricted),
  })
    .meta({ id: 'PlacementCapRule', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const SurfaceTypeCapRuleSchema =
  z.object({
    surface_type: (z.string().min(1)).meta(Unrestricted),
    rules: (z.array(PlacementCapRuleSchema)).meta(Unrestricted),
    cooldown_ms: (z.number().int().nonnegative().optional()).meta(Unrestricted),
  })
    .meta({
      id: 'SurfaceTypeCapRule',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
      'x-revturbine-data-classification': 'operational',
    }
);

export const CtaPathTypeSchema =
  z.enum([
    'open_checkout', 'view_plans', 'book_demo', 'contact_sales',
    'complete_onboarding', 'invite_teammate', 'refer_friend',
    'verify_work_email', 'update_payment_method', 'enable_auto_renewal',
    'manage_subscription', 'switch_billing_period', 'extend_trial',
    'open_rt_placement', 'dismiss', 'snooze', 'custom',
  ])
    .meta({ id: 'CtaPathType', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Placement schema ─────────────────────────────────────────────────────────

export const PlacementSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
    category: (PlacementCategorySchema).meta(Unrestricted),
    status: (PlacementStatusSchema.default('new')).meta(Unrestricted),
    drag_order_in_category: (z.number().int().default(0)).meta(Unrestricted),
    // Trigger config (populated based on category)
    surface_slot_id: (z.string().optional()).meta(Unrestricted),
    entitlement_id: (z.string().optional()).meta(Unrestricted),
    tier_threshold: (z.string().optional()).meta(Unrestricted),
    threshold_percent: (z.number().min(0).max(100).optional()).meta(Unrestricted),
    trial_type: (z.enum(['free', 'reverse']).optional()).meta(Unrestricted),
    trigger_type: (z.string().optional()).meta(Unrestricted),
    trial_progress_percent: (z.number().min(0).max(100).optional()).meta(Unrestricted),
    days_before_end: (z.number().int().min(0).optional()).meta(Unrestricted),
    qualifier: (z.enum(['none_always_on', 'overage_vs_upgrade', 'time_bound', 'clicks_paid_feature', 'clicks_cancel', 'payment_failed', 'payment_at_risk']).optional()).meta(Unrestricted),
    activation_window_start: (z.string().datetime().optional()).meta(Unrestricted),
    activation_window_end: (z.string().datetime().optional()).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({
      id: 'Placement',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── CTA object (embedded in payload) ─────────────────────────────────────────

export const CtaObjectSchema =
  z.object({
    label: (z.string().min(1).max(200)).meta(Unrestricted),
    cta_path_type: (CtaPathTypeSchema).meta(Unrestricted),
    config_fields: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
  })
    .meta({ id: 'CtaObject', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Placement payload ────────────────────────────────────────────────────────

export const PlacementPayloadSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    placement_id: (z.string().min(1)).meta(Unrestricted),
    drag_order: (z.number().int().default(0)).meta(Unrestricted),
    target_plan_id: (z.string().optional()).meta(Unrestricted),
    target_plan_billing_cadence: (z.string().optional()).meta(Unrestricted),
    target_segments: (z.array(z.string()).default([])).meta(Unrestricted),
    surface_template_id: (z.string().min(1)).meta(Unrestricted),
    content_fields: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    cta_list: (z.array(CtaObjectSchema).default([])).meta(Unrestricted),
    max_per_period: (z.number().int().min(0).nullable().default(null)).meta(Unrestricted),
    max_period_unit: (CapPeriodSchema.default('session')).meta(Unrestricted),
    cooldown_after_dismiss_days: (z.number().int().min(0).default(7)).meta(Unrestricted),
    status: (PayloadStatusSchema.default('new')).meta(Unrestricted),
  })
    .meta({
      id: 'PlacementPayload',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Placement variant (A/B) ─────────────────────────────────────────────────

export const PlacementVariantSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    placement_payload_id: (z.string().min(1)).meta(Unrestricted),
    experiment_id: (z.string().min(1)).meta(Unrestricted),
    variant_name: (z.string().min(1).max(200)).meta(Unrestricted),
    is_control: (z.boolean().default(false)).meta(Unrestricted),
    traffic_allocation_percent: (z.number().min(0).max(100)).meta(Unrestricted),
    override_fields: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    status: (z.enum(['active', 'paused', 'complete']).default('active')).meta(Unrestricted),
  })
    .meta({
      id: 'PlacementVariant',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Surface slot (auto-discovered) ──────────────────────────────────────────

export const SurfaceSlotSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    surface_slot_handle: (z.string().min(1).max(200)).meta(Unrestricted),
    surface_type: (SurfaceTypeSchema).meta(Unrestricted),
    surface_template_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    surface_slot_category: (z.enum(['fixed', 'gated', 'triggered']).default('fixed')).meta(Unrestricted),
    first_seen: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    last_seen: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    status: (z.enum(['active', 'inactive', 'new']).default('new')).meta(Unrestricted),
    placement_count: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({
      id: 'SurfaceSlot',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

const PlacementWriteSchema = toWritableSchema(PlacementSchema);
const PayloadWriteSchema = toWritableSchema(PlacementPayloadSchema);

export const placementPaths: ZodOpenApiPathsObject = {
  '/api/placements': {
    get: operation({
      operationId: 'listPlacements',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List placements',
      tags: ['placements'],
      responses: { '200': { description: 'Placement list', content: { 'application/json': { schema: ListEnvelope(PlacementSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createPlacement',
      summary: 'Create placement',
      tags: ['placements'],
      requestBody: { required: true, content: { 'application/json': { schema: PlacementWriteSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: PlacementSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'create' } },
    }),
  },
  '/api/placements/{placementId}': {
    get: operation({
      operationId: 'getPlacement',
      requestParams: { path: z.object({ placementId: z.string() }) },
      summary: 'Get placement',
      tags: ['placements'],
      responses: { '200': { description: 'Placement detail', content: { 'application/json': { schema: PlacementSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updatePlacement',
      requestParams: { path: z.object({ placementId: z.string() }) },
      summary: 'Update placement',
      tags: ['placements'],
      requestBody: { required: true, content: { 'application/json': { schema: PlacementWriteSchema } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: PlacementSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deletePlacement',
      requestParams: { path: z.object({ placementId: z.string() }) },
      summary: 'Delete placement',
      tags: ['placements'],
      responses: { '204': { description: 'Deleted' }, default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'delete' } },
    }),
  },
  '/api/placements/{placementId}/duplicate': {
    post: operation({
      operationId: 'duplicatePlacement',
      requestParams: { path: z.object({ placementId: z.string() }) },
      summary: 'Duplicate placement',
      tags: ['placements'],
      responses: { '201': { description: 'Duplicated', content: { 'application/json': { schema: PlacementSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'duplicate' } },
    }),
  },
  '/api/placements/reorder': {
    post: operation({
      operationId: 'reorderPlacements',
      summary: 'Reorder placements within category',
      tags: ['placements'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ category: PlacementCategorySchema, ids: z.array(z.string()) }) } } },
      responses: { '200': { description: 'Reordered' } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placements', persistence: { table: 'placements', mode: 'reorder' } },
    }),
  },
  '/api/placements/{placementId}/payloads': {
    get: operation({
      operationId: 'listPlacementPayloads',
      requestParams: { path: z.object({ placementId: z.string() }) , query: ListQueryParamsSchema },
      summary: 'List placement payloads',
      tags: ['placements'],
      responses: { '200': { description: 'Payload list', content: { 'application/json': { schema: ListEnvelope(PlacementPayloadSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placement-payloads', persistence: { table: 'placementPayloads', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createPlacementPayload',
      requestParams: { path: z.object({ placementId: z.string() }) },
      summary: 'Create placement payload',
      tags: ['placements'],
      requestBody: { required: true, content: { 'application/json': { schema: PayloadWriteSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: PlacementPayloadSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placement-payloads', persistence: { table: 'placementPayloads', mode: 'create' } },
    }),
  },
  '/api/placement-payloads/{payloadId}': {
    patch: operation({
      operationId: 'updatePlacementPayload',
      requestParams: { path: z.object({ payloadId: z.string() }) },
      summary: 'Update placement payload',
      tags: ['placements'],
      requestBody: { required: true, content: { 'application/json': { schema: PayloadWriteSchema } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: PlacementPayloadSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placement-payloads', persistence: { table: 'placementPayloads', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deletePlacementPayload',
      requestParams: { path: z.object({ payloadId: z.string() }) },
      summary: 'Delete placement payload',
      tags: ['placements'],
      responses: { '204': { description: 'Deleted' } },
      'x-revturbine-operation': { exposure: 'external', resource: 'placement-payloads', persistence: { table: 'placementPayloads', mode: 'delete' } },
    }),
  },
  '/api/surface-slots': {
    get: operation({
      operationId: 'listSurfaceSlots',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List auto-discovered surface slots',
      tags: ['placements'],
      responses: { '200': { description: 'Surface slot list', content: { 'application/json': { schema: ListEnvelope(SurfaceSlotSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'surface-slots', persistence: { table: 'surfaceSlots', mode: 'list' } },
    }),
  },
};
