import { z } from 'zod';

export const SchemaPersistence = {
  Persisted: 'persisted',
  Transient: 'transient',
} as const;

export type SchemaPersistence = (typeof SchemaPersistence)[keyof typeof SchemaPersistence];

export const SchemaExposure = {
  Internal: 'internal',
  External: 'external',
} as const;

export type SchemaExposure = (typeof SchemaExposure)[keyof typeof SchemaExposure];

export const DataClassification = {
  Pii: { 'x-revturbine-data-classification': 'pii' as const },
  Financial: { 'x-revturbine-data-classification': 'financial' as const },
  Unrestricted: { 'x-revturbine-data-classification': 'unrestricted' as const },
} as const;

export type DataClassification = (typeof DataClassification)[keyof typeof DataClassification];

export type DataClassificationValue = DataClassification['x-revturbine-data-classification'];

export type SchemaClassification = {
  persistence: SchemaPersistence;
  exposure: SchemaExposure;
};

const DATA_CLASSIFICATION_META_KEY = 'x-revturbine-data-classification';
const SCHEMA_PERSISTENCE_META_KEY = 'x-revturbine-schema-persistence';
const SCHEMA_EXPOSURE_META_KEY = 'x-revturbine-schema-exposure';
const READ_ONLY_META_KEY = 'readOnly';

export function getSchemaClassification(schema: z.ZodTypeAny): SchemaClassification | undefined {
  const meta = schema.meta();
  const persistence = meta?.[SCHEMA_PERSISTENCE_META_KEY];
  const exposure = meta?.[SCHEMA_EXPOSURE_META_KEY];

  if (
    (persistence === SchemaPersistence.Persisted ||
      persistence === SchemaPersistence.Transient) &&
    (exposure === SchemaExposure.Internal || exposure === SchemaExposure.External)
  ) {
    return {
      persistence,
      exposure,
    };
  }

  return undefined;
}

export function getFieldClassification(schema: z.ZodTypeAny): DataClassificationValue | undefined {
  const meta = schema.meta();
  const classification = meta?.[DATA_CLASSIFICATION_META_KEY];
  return typeof classification === 'string'
    ? (classification as DataClassificationValue)
    : undefined;
}

export function getObjectFieldClassifications(
  schema: z.ZodObject<z.ZodRawShape>,
): Record<string, DataClassificationValue | undefined> {
  const result: Record<string, DataClassificationValue | undefined> = {};

  for (const [fieldName, fieldSchema] of Object.entries(schema.shape)) {
    result[fieldName] =
      typeof fieldSchema === 'object' && fieldSchema !== null
        ? getFieldClassification(fieldSchema as z.ZodTypeAny)
        : undefined;
  }

  return result;
}

/**
 * Read the schema-level exposure from a Zod schema's .meta().
 */
export function getSchemaExposure(schema: z.ZodTypeAny): SchemaExposure | undefined {
  const meta = schema.meta();
  const exposure = meta?.[SCHEMA_EXPOSURE_META_KEY];
  if (exposure === SchemaExposure.Internal || exposure === SchemaExposure.External) {
    return exposure;
  }
  return undefined;
}

/**
 * Read the schema-level persistence from a Zod schema's .meta().
 */
export function getSchemaPersistence(schema: z.ZodTypeAny): SchemaPersistence | undefined {
  const meta = schema.meta();
  const persistence = meta?.[SCHEMA_PERSISTENCE_META_KEY];
  if (persistence === SchemaPersistence.Persisted || persistence === SchemaPersistence.Transient) {
    return persistence;
  }
  return undefined;
}

/**
 * Filter a map of named Zod schemas to only those with exposure: 'external'.
 */
export function filterExternalSchemas(
  allSchemas: Record<string, z.ZodTypeAny>,
): Record<string, z.ZodTypeAny> {
  const result: Record<string, z.ZodTypeAny> = {};
  for (const [name, schema] of Object.entries(allSchemas)) {
    if (getSchemaExposure(schema) === SchemaExposure.External) {
      result[name] = schema;
    }
  }
  return result;
}

/**
 * Filter a map of named Zod schemas to only those with persistence: 'persisted'.
 */
export function filterPersistedSchemas(
  allSchemas: Record<string, z.ZodTypeAny>,
): Record<string, z.ZodTypeAny> {
  const result: Record<string, z.ZodTypeAny> = {};
  for (const [name, schema] of Object.entries(allSchemas)) {
    if (getSchemaPersistence(schema) === SchemaPersistence.Persisted) {
      result[name] = schema;
    }
  }
  return result;
}

/**
 * Derive a write/input schema from a canonical object schema by dropping
 * fields marked with OpenAPI readOnly metadata.
 */
export function toWritableSchema<T extends z.ZodObject<z.ZodRawShape>>(
  schema: T,
): z.ZodObject<Record<string, z.ZodTypeAny>> {
  const writableShape: Record<string, z.ZodTypeAny> = {};

  for (const [fieldName, fieldSchema] of Object.entries(schema.shape)) {
    if (typeof fieldSchema !== 'object' || fieldSchema === null) {
      continue;
    }

    const isReadOnly = (fieldSchema as z.ZodTypeAny).meta()?.[READ_ONLY_META_KEY] === true;
    if (!isReadOnly) {
      writableShape[fieldName] = fieldSchema as z.ZodTypeAny;
    }
  }

  return z.object(writableShape);
}
