/**
 * Segment schemas — Zod definitions for dimensional targeting model.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, NameField, HandleField, DescriptionField, MetadataField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Segment dimension ────────────────────────────────────────────────────────

export const DimensionCategorySchema =
  z.enum(['default', 'custom'])
    .meta({ id: 'DimensionCategory', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const DimensionSourceTypeSchema =
  z.enum(['system', 'sdk_trait', 'sdk_trait_enum', 'cdp_property', 'manual_list'])
    .meta({ id: 'DimensionSourceType', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const SegmentDimensionSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    category: (DimensionCategorySchema.default('custom')).meta(Unrestricted),
    visibility_toggle: (z.boolean().default(true)).meta(Unrestricted),
    source_type: (DimensionSourceTypeSchema.default('system')).meta(Unrestricted),
    estimated_size: (z.number().int().min(0).optional()).meta(Unrestricted),
  })
    .meta({
      id: 'SegmentDimension',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Segment value ────────────────────────────────────────────────────────────

export const SegmentValueSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    dimension_id: (z.string().min(1)).meta(Unrestricted),
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
    definition_rule: (z.record(z.string(), z.unknown()).optional()).meta(Unrestricted),
    used_in_count: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({
      id: 'SegmentValue',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Flat segment (legacy / convenience) ──────────────────────────────────────

export const SegmentSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    slug: (HandleField).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
    rules: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    is_active: (z.boolean().default(true)).meta(Unrestricted),
    estimated_size: (z.number().int().min(0).nullable().default(null)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({
      id: 'Segment',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const segmentPaths: ZodOpenApiPathsObject = {
  '/api/segments': {
    get: operation({
      operationId: 'listSegmentDimensions',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List segment dimensions',
      tags: ['segments'],
      responses: { '200': { description: 'Dimension list', content: { 'application/json': { schema: ListEnvelope(SegmentDimensionSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segments', persistence: { table: 'segmentDimensions', mode: 'list' } },
    }),
  },
  '/api/segments/custom': {
    post: operation({
      operationId: 'createCustomDimension',
      summary: 'Create custom segment dimension',
      tags: ['segments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ name: z.string(), description: z.string().optional() }) } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: SegmentDimensionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segments', persistence: { table: 'segmentDimensions', mode: 'create' } },
    }),
  },
  '/api/segments/{dimensionId}': {
    delete: operation({
      operationId: 'deleteCustomDimension',
      requestParams: { path: z.object({ dimensionId: z.string() }) },
      summary: 'Delete custom dimension',
      tags: ['segments'],
      responses: { '204': { description: 'Deleted' }, default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segments', persistence: { table: 'segmentDimensions', mode: 'delete' } },
    }),
  },
  '/api/segments/{dimensionId}/visibility': {
    patch: operation({
      operationId: 'toggleDimensionVisibility',
      requestParams: { path: z.object({ dimensionId: z.string() }) },
      summary: 'Toggle dimension visibility',
      tags: ['segments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ visible: z.boolean() }) } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: SegmentDimensionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segments', persistence: { table: 'segmentDimensions', mode: 'update' } },
    }),
  },
  '/api/segments/{dimensionId}/values': {
    get: operation({
      operationId: 'listSegmentValues',
      requestParams: { path: z.object({ dimensionId: z.string() }) , query: ListQueryParamsSchema },
      summary: 'List segment values for dimension',
      tags: ['segments'],
      responses: { '200': { description: 'Value list', content: { 'application/json': { schema: ListEnvelope(SegmentValueSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segment-values', persistence: { table: 'segmentValues', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createSegmentValue',
      requestParams: { path: z.object({ dimensionId: z.string() }) },
      summary: 'Create segment value',
      tags: ['segments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ name: z.string(), handle: z.string(), definition_rule: z.record(z.string(), z.unknown()).optional() }) } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: SegmentValueSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segment-values', persistence: { table: 'segmentValues', mode: 'create' } },
    }),
  },
  '/api/segment-values/{valueId}': {
    patch: operation({
      operationId: 'updateSegmentValue',
      requestParams: { path: z.object({ valueId: z.string() }) },
      summary: 'Update segment value',
      tags: ['segments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({ name: z.string().optional(), definition_rule: z.record(z.string(), z.unknown()).optional() }) } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: SegmentValueSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segment-values', persistence: { table: 'segmentValues', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deleteSegmentValue',
      requestParams: { path: z.object({ valueId: z.string() }) },
      summary: 'Delete segment value',
      tags: ['segments'],
      responses: { '204': { description: 'Deleted' } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'segment-values', persistence: { table: 'segmentValues', mode: 'delete' } },
    }),
  },
};
