/**
 * Trial schemas — free trial rules, reverse trial rules, and trial instances.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, NameField, HandleField, MetadataField, NullableDatetimeField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Trial status ─────────────────────────────────────────────────────────────

export const TrialStatusSchema =
  z.enum(['not_started', 'active', 'expired', 'converted', 'cancelled'])
    .meta({ id: 'TrialStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Free trial rule ──────────────────────────────────────────────────────────

export const FreeTrialRuleSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    plan_id: (z.string().min(1)).meta(Unrestricted),
    duration_days: (z.number().int().min(1).max(365)).meta(Unrestricted),
    grace_period_days: (z.number().int().min(0).default(0)).meta(Unrestricted),
    require_payment_method: (z.boolean().default(false)).meta(Unrestricted),
    auto_convert: (z.boolean().default(true)).meta(Unrestricted),
    convert_to_plan_id: (z.string().optional()).meta(Unrestricted),
    limit_per_customer: (z.number().int().min(1).default(1)).meta(Unrestricted),
    is_active: (z.boolean().default(true)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'FreeTrialRule', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Reverse trial rule ───────────────────────────────────────────────────────

export const ReverseTrialRuleSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    premium_plan_id: (z.string().min(1)).meta(Unrestricted),
    fallback_plan_id: (z.string().min(1)).meta(Unrestricted),
    duration_days: (z.number().int().min(1).max(365)).meta(Unrestricted),
    show_upgrade_prompt_at_day: (z.number().int().min(0).optional()).meta(Unrestricted),
    entitlements_during_trial: (z.array(z.string()).default([])).meta(Unrestricted),
    is_active: (z.boolean().default(true)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'ReverseTrialRule', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Trial instance ───────────────────────────────────────────────────────────

export const TrialInstanceSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    customer_id: (z.string().min(1)).meta(Unrestricted),
    rule_id: (z.string().min(1)).meta(Unrestricted),
    rule_type: (z.enum(['free_trial', 'reverse_trial'])).meta(Unrestricted),
    plan_id: (z.string().min(1)).meta(Unrestricted),
    status: (TrialStatusSchema.default('active')).meta(Unrestricted),
    started_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    expires_at: (z.string().datetime()).meta(Unrestricted),
    converted_at: (NullableDatetimeField).meta(Unrestricted),
    cancelled_at: (NullableDatetimeField).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'TrialInstance', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

