/**
 * Entitlement grant resolution — pure functions for resolving effective
 * entitlements and usage across the account → instance → user hierarchy.
 *
 * Most-specific wins: user-level overrides instance-level overrides account-level.
 */

import type {
  EntitlementGrant,
  EntitlementGrantSet,
  EntitlementUsageEntry,
} from '../../core/providers/types';

// ── Effective entitlement resolution ────────────────────────────────

export interface ResolveEntitlementOptions {
  /** When provided, include instance-level grants in the merge. */
  productInstanceId?: string;
}

/**
 * Merge entitlement grants across hierarchy levels.
 *
 * Resolution order (most-specific wins per entitlement handle):
 * 1. Start with account-level grants as base
 * 2. Override with instance-level grants (if productInstanceId provided)
 * 3. Override with user-level grants
 *
 * If no grants are provided at any level, that level is skipped.
 */
export function resolveEffectiveEntitlements(
  grants: EntitlementGrantSet,
  options?: ResolveEntitlementOptions,
): Record<string, EntitlementGrant> {
  const effective: Record<string, EntitlementGrant> = {};

  // Layer 1: account-level base
  if (grants.account) {
    for (const [handle, grant] of Object.entries(grants.account)) {
      effective[handle] = grant;
    }
  }

  // Layer 2: instance-level overrides (only when productInstanceId is provided)
  if (options?.productInstanceId && grants.instance) {
    for (const [handle, grant] of Object.entries(grants.instance)) {
      effective[handle] = grant;
    }
  }

  // Layer 3: user-level overrides (always applied, most specific)
  if (grants.user) {
    for (const [handle, grant] of Object.entries(grants.user)) {
      effective[handle] = grant;
    }
  }

  return effective;
}

// ── Effective usage resolution ──────────────────────────────────────

/**
 * Select the correct usage entries based on the entitlement's allocation type.
 *
 * - `account_pool` → accountUsage (shared across all instances)
 * - `per_instance` → instanceUsage (scoped to current product instance)
 * - `per_user` / `per_user_pooled` → usage (per-user, default)
 *
 * Falls back to `usage` when the requested level's data is not provided.
 */
export function resolveEffectiveUsage(
  usage: Record<string, EntitlementUsageEntry>,
  allocation: string,
  instanceUsage?: Record<string, EntitlementUsageEntry>,
  accountUsage?: Record<string, EntitlementUsageEntry>,
): Record<string, EntitlementUsageEntry> {
  if (allocation === 'account_pool' && accountUsage) {
    return accountUsage;
  }
  if (allocation === 'per_instance' && instanceUsage) {
    return instanceUsage;
  }
  // per_user, per_user_pooled, or fallback
  return usage;
}
