/**
 * InteractionTracker — manages dismissal and interaction suppression state.
 *
 * Isomorphic: works with any RevTurbineStorage backend (InMemoryStorage,
 * BrowserStorage, or a custom RevTurbineStorage).
 *
 * Extracted from customer-side.ts updateInteractionState / suppressionForState.
 */

import type { RevTurbineStorage } from './storage';
import type {
  InteractionState,
  RevTurbineTreatmentInteractionInput,
  SuppressionResult,
} from './types';

const STORAGE_PREFIX = 'revturbine:interaction-state';

export interface InteractionTrackerOptions {
  storage: RevTurbineStorage;
  tenantId: string;
  userId: string;
  /** Default dismiss cooldown (ms). Default: 24 hours. */
  defaultDismissCooldownMs?: number;
  /** Default remind-me-later delay (ms). Default: 1 hour. */
  defaultRemindLaterMs?: number;
}

export class InteractionTracker {
  private readonly storage: RevTurbineStorage;
  private readonly tenantId: string;
  private readonly userId: string;
  private readonly defaultDismissCooldownMs: number;
  private readonly defaultRemindLaterMs: number;
  private readonly state = new Map<string, InteractionState>();

  constructor(options: InteractionTrackerOptions) {
    this.storage = options.storage;
    this.tenantId = options.tenantId;
    this.userId = options.userId;
    this.defaultDismissCooldownMs = options.defaultDismissCooldownMs ?? 24 * 60 * 60 * 1000;
    this.defaultRemindLaterMs = options.defaultRemindLaterMs ?? 60 * 60 * 1000;
    this.hydrate();
  }

  /* ---- Public API ---- */

  /** Track an interaction and update suppression state. */
  track(input: RevTurbineTreatmentInteractionInput): void {
    const key = this.stateKey(input.placementId, input.userId, input.treatmentId);
    const now = Date.now();
    const metadata = input.metadata ?? {};
    const existing = this.state.get(key) ?? { updatedAt: new Date(now).toISOString() };

    const next: InteractionState = {
      ...existing,
      lastInteractionType: input.interactionType,
      updatedAt: input.interactionAt ?? new Date(now).toISOString(),
    };

    if (input.interactionType === 'dismiss') {
      const cooldownMs = Number(metadata.cooldown_ms);
      next.suppressedUntil = now + (
        Number.isFinite(cooldownMs) && cooldownMs > 0
          ? cooldownMs
          : this.defaultDismissCooldownMs
      );
    }

    if (input.interactionType === 'remind_me_later') {
      const remindAfterSeconds = Number(metadata.remind_after_seconds);
      next.suppressedUntil = now + (
        Number.isFinite(remindAfterSeconds) && remindAfterSeconds > 0
          ? remindAfterSeconds * 1000
          : this.defaultRemindLaterMs
      );
    }

    if (input.interactionType === 'cta_clicked' || input.interactionType === 'cta_completed') {
      next.suppressedUntil = now + 5 * 60 * 1000; // 5 minutes
    }

    this.state.set(key, next);
    this.persist();
  }

  /** Check whether a placement is suppressed by a recent interaction. */
  checkSuppression(placementId: string, userId: string, treatmentId?: string): SuppressionResult {
    const key = this.stateKey(placementId, userId, treatmentId);
    const entry = this.state.get(key);

    if (!entry?.suppressedUntil) return { suppressed: false };

    if (entry.suppressedUntil <= Date.now()) {
      return { suppressed: false };
    }

    return {
      suppressed: true,
      reason: entry.lastInteractionType === 'remind_me_later'
        ? 'suppressed_until_remind_window'
        : 'suppressed_by_dismiss_cooldown',
    };
  }

  /** Clear suppression state for a specific placement. */
  clearSuppression(placementId: string, userId: string, treatmentId?: string): void {
    const key = this.stateKey(placementId, userId, treatmentId);
    this.state.delete(key);
    this.persist();
  }

  /* ---- Serialization ---- */

  /** Load state from storage. Called automatically on construction. */
  hydrate(): void {
    const raw = this.storage.getItem(this.storageKey());
    if (!raw) return;

    try {
      const parsed = JSON.parse(raw) as Record<string, InteractionState>;
      for (const [key, value] of Object.entries(parsed)) {
        if (!value || typeof value !== 'object') continue;
        this.state.set(key, value);
      }
    } catch {
      this.storage.removeItem(this.storageKey());
    }
  }

  /** Persist current state to storage. */
  persist(): void {
    try {
      const payload = Object.fromEntries(this.state.entries());
      this.storage.setItem(this.storageKey(), JSON.stringify(payload));
    } catch {
      // Swallow quota/serialization errors
    }
  }

  /* ---- Internal ---- */

  private storageKey(): string {
    return `${STORAGE_PREFIX}:${this.tenantId}:${this.userId}`;
  }

  private stateKey(placementId: string, userId: string, treatmentId?: string): string {
    return [this.tenantId, userId, placementId, treatmentId || 'default'].join(':');
  }
}
