/**
 * Storage abstraction for the RevTurbine SDK core.
 *
 * Provides a pluggable interface that works in browser, server, and edge contexts.
 * Browser environments use `BrowserStorage` (in web-sdk).
 * Server environments can use `InMemoryStorage` or a custom `RevTurbineStorage` implementation.
 */

/**
 * Minimal storage interface matching the Web Storage API subset used by the SDK.
 *
 * Implementations:
 * - `InMemoryStorage` — in-process Map-backed (this file)
 * - `BrowserStorage` — wraps localStorage/sessionStorage (web-sdk)
 * - `DrizzleStateStore` — Postgres-backed via Drizzle (adapters/drizzle-state-store.ts)
 */
export interface RevTurbineStorage {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
  removeItem(key: string): void;
}

/**
 * In-memory storage backed by a `Map`.
 *
 * Used as the default on the server, edge, or when persistent storage
 * is unavailable. Data does not survive beyond the current process / request.
 */
export class InMemoryStorage implements RevTurbineStorage {
  private readonly store = new Map<string, string>();

  getItem(key: string): string | null {
    return this.store.get(key) ?? null;
  }

  setItem(key: string, value: string): void {
    this.store.set(key, value);
  }

  removeItem(key: string): void {
    this.store.delete(key);
  }
}
