/**
 * Analytics schemas — reporting, KPIs, attribution, journey, usage, drift.
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields, MetadataField, NullableDatetimeField, SeveritySchema } from '../../core/common';
import {    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Financial } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { External, Internal } = SchemaExposure;

// ── Existing analytics shapes ────────────────────────────────────────────────

export const CohortMonthSchema = 
  z.object({
    month: (z.string()).meta(Unrestricted),
    cohort_size: (z.number().int().min(0)).meta(Unrestricted),
    retained: (z.number().int().min(0)).meta(Unrestricted),
    retention_rate: (z.number().min(0).max(1)).meta(Unrestricted),
    revenue_cents: (z.number().int().min(0)).meta(Financial),
  })
    .meta({ id: 'CohortMonth', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const FunnelStepSchema = 
  z.object({
    step: (z.string()).meta(Unrestricted),
    label: (z.string()).meta(Unrestricted),
    count: (z.number().int().min(0)).meta(Unrestricted),
    conversion_rate: (z.number().min(0).max(1)).meta(Unrestricted),
    drop_off_rate: (z.number().min(0).max(1)).meta(Unrestricted),
  })
    .meta({ id: 'FunnelStep', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const PlacementPerformanceRowSchema = 
  z.object({
    placement_id: (z.string()).meta(Unrestricted),
    placement_name: (z.string()).meta(Unrestricted),
    impressions: (z.number().int().min(0)).meta(Unrestricted),
    clicks: (z.number().int().min(0)).meta(Unrestricted),
    conversions: (z.number().int().min(0)).meta(Unrestricted),
    ctr: (z.number().min(0)).meta(Unrestricted),
    conversion_rate: (z.number().min(0)).meta(Unrestricted),
    revenue_cents: (z.number().int().min(0)).meta(Financial),
  })
    .meta({ id: 'PlacementPerformanceRow', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

export const RevenueMetricSchema = 
  z.object({
    date: (z.string()).meta(Unrestricted),
    mrr_cents: (z.number().int().min(0)).meta(Financial),
    arr_cents: (z.number().int().min(0)).meta(Financial),
    new_mrr_cents: (z.number().int().min(0)).meta(Financial),
    churned_mrr_cents: (z.number().int().min(0)).meta(Financial),
    expansion_mrr_cents: (z.number().int().min(0)).meta(Financial),
    net_new_mrr_cents: (z.number().int()).meta(Financial),
  })
    .meta({ id: 'RevenueMetric', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── KPI aggregate ────────────────────────────────────────────────────────────

export const KpiAggregateSchema =
  z.object({
    metric_key: (z.string().min(1)).meta(Unrestricted),
    label: (z.string()).meta(Unrestricted),
    current_value: (z.number()).meta(Financial),
    previous_value: (z.number().nullable().default(null)).meta(Financial),
    change_percent: (z.number().nullable().default(null)).meta(Unrestricted),
    period: (z.string()).meta(Unrestricted),
    unit: (z.enum(['count', 'cents', 'percent', 'ratio', 'seconds']).default('count')).meta(Unrestricted),
  })
    .meta({ id: 'KpiAggregate', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Drift report ─────────────────────────────────────────────────────────────

export const DriftReportSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    report_type: (z.enum(['plan_drift', 'entitlement_drift', 'usage_anomaly', 'revenue_anomaly'])).meta(Unrestricted),
    severity: (SeveritySchema).meta(Unrestricted),
    resource_type: (z.string().min(1)).meta(Unrestricted),
    resource_id: (z.string().min(1)).meta(Unrestricted),
    summary: (z.string().max(1000)).meta(Unrestricted),
    expected_value: (z.unknown().optional()).meta(Unrestricted),
    actual_value: (z.unknown().optional()).meta(Unrestricted),
    affected_customer_count: (z.number().int().min(0).default(0)).meta(Unrestricted),
    is_resolved: (z.boolean().default(false)).meta(Unrestricted),
    resolved_at: (NullableDatetimeField).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'DriftReport', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Alert ────────────────────────────────────────────────────────────────────

export const AlertSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    alert_type: (z.enum(['usage_threshold', 'revenue_drop', 'conversion_drop', 'experiment_significance', 'drift_detected', 'custom'])).meta(Unrestricted),
    severity: (SeveritySchema).meta(Unrestricted),
    title: (z.string().min(1).max(300)).meta(Unrestricted),
    description: (z.string().max(2000)).meta(Unrestricted),
    resource_type: (z.string().optional()).meta(Unrestricted),
    resource_id: (z.string().optional()).meta(Unrestricted),
    is_acknowledged: (z.boolean().default(false)).meta(Unrestricted),
    acknowledged_at: (NullableDatetimeField).meta(Unrestricted),
    acknowledged_by: (z.string().nullable().default(null)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Alert', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const analyticsPaths: ZodOpenApiPathsObject = {
  '/api/analytics/kpis': {
    get: operation({
      operationId: 'listKpiAggregates',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List KPI aggregate metrics',
      tags: ['analytics'],
      responses: { '200': { description: 'KPI list', content: { 'application/json': { schema: ListEnvelope(KpiAggregateSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'kpiAggregates', mode: 'list' } },
    }),
  },
  '/api/analytics/placement-performance': {
    get: operation({
      operationId: 'listPlacementPerformance',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List placement performance rows',
      tags: ['analytics'],
      responses: { '200': { description: 'Performance rows', content: { 'application/json': { schema: ListEnvelope(PlacementPerformanceRowSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'placementPerformance', mode: 'list' } },
    }),
  },
  '/api/analytics/revenue': {
    get: operation({
      operationId: 'listRevenueMetrics',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List revenue metrics over time',
      tags: ['analytics'],
      responses: { '200': { description: 'Revenue metrics', content: { 'application/json': { schema: ListEnvelope(RevenueMetricSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'revenueMetrics', mode: 'list' } },
    }),
  },
  '/api/analytics/cohorts': {
    get: operation({
      operationId: 'listCohortMetrics',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List cohort retention metrics',
      tags: ['analytics'],
      responses: { '200': { description: 'Cohort metrics', content: { 'application/json': { schema: ListEnvelope(CohortMonthSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'cohortMetrics', mode: 'list' } },
    }),
  },
  '/api/analytics/funnels': {
    get: operation({
      operationId: 'listFunnelSteps',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List funnel step metrics',
      tags: ['analytics'],
      responses: { '200': { description: 'Funnel steps', content: { 'application/json': { schema: ListEnvelope(FunnelStepSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'funnelSteps', mode: 'list' } },
    }),
  },
  '/api/analytics/drift-reports': {
    get: operation({
      operationId: 'listDriftReports',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List drift reports',
      tags: ['analytics'],
      responses: { '200': { description: 'Drift reports', content: { 'application/json': { schema: ListEnvelope(DriftReportSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'driftReports', mode: 'list' } },
    }),
  },
  '/api/analytics/drift-reports/{reportId}/resolve': {
    post: operation({
      operationId: 'resolveDriftReport',
      requestParams: { path: z.object({ reportId: z.string() }) },
      summary: 'Mark a drift report as resolved',
      tags: ['analytics'],
      responses: { '200': { description: 'Resolved', content: { 'application/json': { schema: DriftReportSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'driftReports', mode: 'update' } },
    }),
  },
  '/api/analytics/alerts': {
    get: operation({
      operationId: 'listAlerts',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List alerts',
      tags: ['analytics'],
      responses: { '200': { description: 'Alert list', content: { 'application/json': { schema: ListEnvelope(AlertSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'alerts', mode: 'list' } },
    }),
  },
  '/api/analytics/alerts/{alertId}/acknowledge': {
    post: operation({
      operationId: 'acknowledgeAlert',
      requestParams: { path: z.object({ alertId: z.string() }) },
      summary: 'Acknowledge an alert',
      tags: ['analytics'],
      responses: { '200': { description: 'Acknowledged', content: { 'application/json': { schema: AlertSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'analytics', persistence: { table: 'alerts', mode: 'update' } },
    }),
  },
};
