/**
 * Token derivation — derives personalization tokens from provider state.
 *
 * Moved from web-sdk/placements/token-derivation.ts for isomorphic use.
 */

import type { ResolvedProviderContext, EntitlementGrant } from '../../core/providers/types';
import type { PersonalizationContext } from '../../core/types';

type TokenValue = string | number;

type DeriveTokenOptions = {
  userId?: string;
  /** User display name. */
  userName?: string;
  providers?: ResolvedProviderContext;
  base?: PersonalizationContext;
  /** Recommended upgrade plan info. */
  upgradePlan?: {
    name?: string;
    price?: string;
    handle?: string;
  };
  /** Plan name granted during trial. */
  trialPlanName?: string;
  /** Promotion discount string (e.g. '20%'). */
  promoDiscount?: string;
  /** Uniform feature interaction data (no isPremium — derived from entitlement graph). */
  featureInteractions?: {
    /** Feature handles the user has invoked. */
    invokedFeatureHandles: string[];
    /** Per-feature invocation counts. */
    interactionCounts?: Record<string, number>;
    /** Server-supplied ranked list of features by cross-user engagement. */
    topFeaturesByEngagement?: string[];
  };
  /** Product instance for instance-scoped usage tokens. */
  productInstanceId?: string;
  /** Pre-resolved effective grants from resolveEffectiveEntitlements(). */
  effectiveGrants?: Record<string, EntitlementGrant>;
  /** Features the user would lose on downgrade (names, comma-separated). */
  featuresLostOnDowngrade?: string;
};

function toFiniteNumber(value: unknown): number | undefined {
  if (typeof value === 'number' && Number.isFinite(value)) return value;
  if (typeof value === 'string' && value.trim().length > 0) {
    const parsed = Number(value);
    if (Number.isFinite(parsed)) return parsed;
  }
  return undefined;
}

function usageTokenPrefix(entitlementId: string): string {
  return entitlementId
    .replace(/_(minutes|minute|credits|credit|seats|seat)$/i, '')
    .replace(/_usage$/i, '')
    .trim();
}

function resolveUsageLimitFromRule(ruleFields: Record<string, unknown>, planHandle?: string): number | undefined {
  const directLimit = toFiniteNumber(
    ruleFields.limit_value
      ?? ruleFields.usage_limit
      ?? ruleFields.limit
      ?? ruleFields.allowance
      ?? ruleFields.initial_grant,
  );
  if (directLimit !== undefined) return directLimit;

  const usageLimits = ruleFields.usageLimits;
  if (usageLimits && typeof usageLimits === 'object' && !Array.isArray(usageLimits)) {
    const planKey = (planHandle ?? '').toLowerCase();
    for (const [key, value] of Object.entries(usageLimits)) {
      if (key.toLowerCase() === planKey) {
        return toFiniteNumber(value);
      }
    }
  }

  return undefined;
}

function resolveWarningThresholdPercent(ruleFields: Record<string, unknown>): number | undefined {
  const raw = toFiniteNumber(
    ruleFields.warning_threshold_percent
      ?? ruleFields.warning_percentage
      ?? ruleFields.threshold_percent
      ?? ruleFields.threshold,
  );

  if (raw === undefined) return undefined;
  return Math.max(0, Math.min(100, raw));
}

/**
 * Derive a placement personalization token map from user context and resolved
 * provider state (plan, traits, entitlement usage, and entitlement rules).
 */
export function derivePlacementPersonalizationTokens(
  options: DeriveTokenOptions,
): Record<string, TokenValue> {
  const tokens: Record<string, TokenValue> = {};
  const providers = options.providers;

  if (options.userId) {
    tokens.user_id = options.userId;
  }

  if (options.base) {
    for (const [key, value] of Object.entries(options.base)) {
      if (typeof value === 'string' || typeof value === 'number') {
        tokens[key] = value;
      }
    }
  }

  const planHandle = providers?.plan?.currentPlanHandle;
  const planName = providers?.plan?.currentPlanName ?? planHandle;
  if (typeof planName === 'string' && planName.length > 0) {
    tokens.plan_name = planName;
  }

  // Trial tokens from plan provider
  const trialDaysRemaining = providers?.plan?.trialDaysRemaining;
  if (trialDaysRemaining !== undefined && Number.isFinite(trialDaysRemaining)) {
    tokens.trial_days_remaining = trialDaysRemaining;
  }
  const trialDaysTotal = providers?.plan?.trialDaysTotal;
  if (trialDaysTotal !== undefined && Number.isFinite(trialDaysTotal)) {
    tokens.trial_days_total = trialDaysTotal;
  }

  const traits = providers?.traits?.traits ?? {};
  for (const [key, value] of Object.entries(traits)) {
    if (typeof value === 'string' || typeof value === 'number') {
      tokens[key] = value;
    }
  }

  const usageByEntitlement = providers?.entitlements?.usage ?? {};
  for (const [entitlementId, usage] of Object.entries(usageByEntitlement)) {
    const prefix = usageTokenPrefix(entitlementId);
    if (!prefix) continue;

    const current = toFiniteNumber(usage.used);
    const remaining = toFiniteNumber(usage.remaining);
    const limit = toFiniteNumber(usage.limit);

    if (current !== undefined) {
      tokens[`${prefix}_usage_current`] = current;
      if (tokens.usage_current === undefined) tokens.usage_current = current;
      if (tokens.current_usage === undefined) tokens.current_usage = current;
    }
    if (limit !== undefined) {
      tokens[`${prefix}_usage_limit`] = limit;
      if (tokens.usage_limit === undefined) tokens.usage_limit = limit;
      if (tokens.current_limit === undefined) tokens.current_limit = limit;
    }

    if (remaining !== undefined) {
      tokens[`${prefix}_usage_remaining`] = remaining;
      if (tokens.usage_remaining === undefined) tokens.usage_remaining = remaining;
    } else if (current !== undefined && limit !== undefined) {
      const derivedRemaining = Math.max(0, limit - current);
      tokens[`${prefix}_usage_remaining`] = derivedRemaining;
      if (tokens.usage_remaining === undefined) tokens.usage_remaining = derivedRemaining;
    }

    if (current !== undefined && limit !== undefined && limit > 0) {
      const percent = Math.min(100, Math.round((current / limit) * 100));
      tokens[`${prefix}_usage_percent`] = percent;
      if (tokens.usage_percent === undefined) tokens.usage_percent = percent;
    }

    // Extract reset_date from usage entry
    const resetDate = usage.reset_date;
    if (typeof resetDate === 'string' && resetDate.length > 0) {
      tokens[`${prefix}_reset_date`] = resetDate;
      if (tokens.reset_date === undefined) tokens.reset_date = resetDate;
    }
  }

  const entitlementRules = providers?.rules?.entitlementRules ?? {};
  for (const [entitlementId, rules] of Object.entries(entitlementRules)) {
    if (!Array.isArray(rules) || rules.length === 0) continue;

    const usageRule = rules.find(rule =>
      rule.kind === 'usage_limit' || rule.kind === 'usage_rate' || rule.kind === 'credits' || rule.kind === 'seat',
    );
    if (!usageRule) continue;

    const prefix = usageTokenPrefix(entitlementId);
    if (!prefix) continue;

    const fields = usageRule.fields ?? {};
    const limitFromRule = resolveUsageLimitFromRule(fields, planHandle);
    if (limitFromRule !== undefined && tokens[`${prefix}_usage_limit`] === undefined) {
      tokens[`${prefix}_usage_limit`] = limitFromRule;
    }

    const warningThreshold = resolveWarningThresholdPercent(fields);
    if (warningThreshold !== undefined) {
      tokens[`${prefix}_usage_warning_threshold_percent`] = warningThreshold;
    }
  }

  // ── New tokens (all inputs optional) ─────────────────────────────────

  // user_name
  if (options.userName && options.userName.length > 0) {
    tokens.user_name = options.userName;
  }

  // plan_price
  const planPrice = providers?.plan?.currentPlanPrice;
  if (typeof planPrice === 'string' && planPrice.length > 0) {
    tokens.plan_price = planPrice;
  }

  // upgrade plan
  if (options.upgradePlan?.name) {
    tokens.upgrade_plan_name = options.upgradePlan.name;
  }
  if (options.upgradePlan?.price) {
    tokens.upgrade_plan_price = options.upgradePlan.price;
  }

  // trial plan name
  if (options.trialPlanName && options.trialPlanName.length > 0) {
    tokens.trial_plan_name = options.trialPlanName;
  }

  // promo discount
  if (options.promoDiscount && options.promoDiscount.length > 0) {
    tokens.promo_discount = options.promoDiscount;
  }

  // features lost on downgrade
  if (options.featuresLostOnDowngrade && options.featuresLostOnDowngrade.length > 0) {
    tokens.features_lost_on_downgrade = options.featuresLostOnDowngrade;
  }

  // credits_remaining, seat_count, seat_limit — aliases from entitlement kind
  const effectiveGrants = options.effectiveGrants;
  if (effectiveGrants) {
    for (const [handle, grant] of Object.entries(effectiveGrants)) {
      if (grant.allocation === 'per_user' || grant.allocation === 'per_user_pooled' || !grant.allocation) {
        // Use effective grant data for usage tokens when available
        const prefix = usageTokenPrefix(handle);
        if (!prefix) continue;

        if (grant.used !== undefined && tokens[`${prefix}_usage_current`] === undefined) {
          tokens[`${prefix}_usage_current`] = grant.used;
        }
        if (grant.limit !== undefined && tokens[`${prefix}_usage_limit`] === undefined) {
          tokens[`${prefix}_usage_limit`] = grant.limit;
        }
      }

      // Emit enforcement mode when a grant is constrained (limited or denied)
      if (grant.enforcement && (grant.status === 'limited' || grant.status === 'denied')) {
        const prefix = usageTokenPrefix(handle);
        if (prefix && tokens[`${prefix}_enforcement`] === undefined) {
          tokens[`${prefix}_enforcement`] = grant.enforcement;
        }
        // Set a top-level enforcement token for the first constrained grant
        if (tokens.enforcement_mode === undefined) {
          tokens.enforcement_mode = grant.enforcement;
        }
      }
    }
  }

  // Explicit credit/seat aliases from entitlement rules
  const rules = providers?.rules?.entitlementRules ?? {};
  for (const [entId, ruleList] of Object.entries(rules)) {
    if (!Array.isArray(ruleList)) continue;
    const prefix = usageTokenPrefix(entId);
    if (!prefix) continue;

    for (const rule of ruleList) {
      if (rule.kind === 'credits') {
        const rem = tokens[`${prefix}_usage_remaining`];
        if (rem !== undefined && tokens.credits_remaining === undefined) {
          tokens.credits_remaining = rem;
        }
      }
      if (rule.kind === 'seat') {
        const cur = tokens[`${prefix}_usage_current`];
        const lim = tokens[`${prefix}_usage_limit`];
        if (cur !== undefined && tokens.seat_count === undefined) {
          tokens.seat_count = cur;
        }
        if (lim !== undefined && tokens.seat_limit === undefined) {
          tokens.seat_limit = lim;
        }
      }
    }
  }

  // Feature interaction–derived tokens (entitlement-graph, no isPremium)
  if (options.featureInteractions && effectiveGrants) {
    const { invokedFeatureHandles, interactionCounts, topFeaturesByEngagement } = options.featureInteractions;
    const invokedSet = new Set(invokedFeatureHandles);

    // A feature is "gated" if it's bound to an entitlement with status denied or limited
    // We check if any entitlement whose handle contains the feature handle is gated
    const gatedEntitlementHandles = new Set<string>();
    for (const [handle, grant] of Object.entries(effectiveGrants)) {
      if (grant.status === 'denied' || grant.status === 'limited') {
        gatedEntitlementHandles.add(handle);
      }
    }

    // Count features the user invoked that are bound to gated entitlements
    let gatedFeaturesUsedCount = 0;
    let gatedActionCount = 0;
    for (const feature of invokedFeatureHandles) {
      if (gatedEntitlementHandles.has(feature)) {
        gatedFeaturesUsedCount++;
        if (interactionCounts) {
          gatedActionCount += interactionCounts[feature] ?? 0;
        }
      }
    }

    tokens.gated_features_used_count = gatedFeaturesUsedCount;
    if (interactionCounts) {
      tokens.gated_action_count = gatedActionCount;
    }

    // Top unused gated feature
    if (topFeaturesByEngagement) {
      const topUnused = topFeaturesByEngagement.find(
        f => !invokedSet.has(f) && gatedEntitlementHandles.has(f),
      );
      if (topUnused) {
        tokens.top_unused_gated_feature = topUnused;
      }
    }

    // Trial features used — features invoked that are bound to entitlements
    // This is the count regardless of gating, since during trial all are allowed
    if (providers?.plan?.trialActive) {
      let trialFeaturesUsed = 0;
      for (const feature of invokedFeatureHandles) {
        // Any feature that has a corresponding entitlement (any status) is trial-relevant
        if (feature in effectiveGrants) {
          trialFeaturesUsed++;
        }
      }
      tokens.trial_features_used = trialFeaturesUsed;
    }
  }

  return tokens;
}
