/**
 * Interaction lifecycle — pure functions for interaction state key
 * generation and suppression checking.
 *
 * Complements `core/state/interaction-tracker.ts` (stateful class) with
 * standalone pure functions.
 */

import type { InteractionState } from './types';

// ── Pure functions ──────────────────────────────────────────────────

/** Generate a deterministic key for interaction state storage. */
export function interactionStateKey(input: {
  tenantId: string;
  userId: string;
  placementId: string;
  treatmentId?: string;
}): string {
  return [
    input.tenantId,
    input.userId,
    input.placementId,
    input.treatmentId || 'default',
  ].join(':');
}

/** Check whether an interaction state indicates the user should be suppressed. */
export function suppressionForState(
  state: InteractionState | undefined,
  nowMs: number = Date.now(),
): { suppressed: boolean; reason?: string } {
  if (!state?.suppressedUntil) return { suppressed: false };
  if (state.suppressedUntil <= nowMs) return { suppressed: false };
  return {
    suppressed: true,
    reason: state.lastInteractionType === 'remind_me_later'
      ? 'suppressed_until_remind_window'
      : 'suppressed_by_dismiss_cooldown',
  };
}
