/**
 * User schemas — Zod definitions for user context, trial status, and usage.
 *
 * These are external/SDK-facing types that describe an identified user's
 * current state (plan, entitlements, usage, personalization tokens).
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields } from '../../core/common';
import { EntitlementGrantSchema } from '../../entitlements/models/schema';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Pii } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { External } = SchemaExposure;

// ── User trial status ────────────────────────────────────────────────────────

export const UserTrialStatusSchema =
  z.object({
    in_trial: (z.boolean()).meta(Unrestricted),
    trial_type: (z.string().optional()).meta(Unrestricted),
    plan_handle: (z.string().optional()).meta(Unrestricted),
    state: (z.enum(['active', 'running_out', 'expired', 'none']).optional()).meta(Unrestricted),
    day_number: (z.number().int().min(0).optional()).meta(Unrestricted),
    days_remaining: (z.number().int().min(0).optional()).meta(Unrestricted),
  })
    .meta({ id: 'UserTrialStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── User context — structured maps ───────────────────────────────────────────

/** A single usage entry derived from a credits / usage_limit entitlement. */
export const UserUsageEntrySchema =
  z.object({
    entitlement_handle: (z.string().min(1)).meta(Unrestricted),
    unit: (z.string().min(1)).meta(Unrestricted),
    amount: (z.number().min(0)).meta(Unrestricted),
    limit: (z.number().min(0).optional()).meta(Unrestricted),
    reset_date: (z.string().optional()).meta(Unrestricted),
  })
    .meta({ id: 'UserUsageEntry', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

/** Plan context for the identified user. */
export const UserPlanContextSchema =
  z.object({
    id: (z.string().min(1)).meta(Unrestricted),
    name: (z.string().min(1)).meta(Unrestricted),
    price: (z.string().optional()).meta(Unrestricted),
    billing_period: (z.enum(['monthly', 'annual', 'none']).optional()).meta(Unrestricted),
  })
    .meta({ id: 'UserPlanContext', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Instance-scoped user context ─────────────────────────────────────────────

/**
 * Usage and entitlements for a specific product instance.
 *
 * When a user has access to multiple product instances within an account,
 * each instance carries its own usage balances and entitlement state.
 */
export const UserInstanceContextSchema =
  z.object({
    product_instance_id: (z.string().min(1)).meta(Unrestricted),
    user_id: (z.string().min(1)).meta(Pii),
    plan: (UserPlanContextSchema.optional()).meta(Unrestricted),
    /** Usage entries for this instance, keyed by entitlement handle. */
    usage: (z.record(z.string(), UserUsageEntrySchema).default({})).meta(Unrestricted),
    trial: (UserTrialStatusSchema.optional()).meta(Unrestricted),
    /** Entitlements resolved at this instance level, keyed by handle. */
    entitlements: (z.record(z.string(), z.union([z.boolean(), EntitlementGrantSchema])).default({})).meta(Unrestricted),
  })
    .meta({
      id: 'UserInstanceContext',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

// ── Aggregate user context ───────────────────────────────────────────────────

/**
 * Aggregate user context across all product instances.
 *
 * Top-level `plan`, `usage`, `entitlements`, and `trial` represent the
 * account-level aggregate view.  The optional `instances` array holds
 * per-instance breakdowns when the account has multiple product instances.
 */
export const UserContextSchema =
  IdField.merge(TenantIdField).merge(TimestampFields).extend({
    user_id: (z.string().min(1)).meta(Pii),
    account_id: (z.string().min(1).nullable().optional()).meta(Pii),
    email: (z.string().email().nullable().optional()).meta(Pii),
    /** Optional email classification (e.g. `business`, `personal`). */
    email_type: (z.string().optional()).meta(Unrestricted),
    plan: (UserPlanContextSchema.optional()).meta(Unrestricted),
    /** Aggregate usage entries across all instances, keyed by handle. */
    usage: (z.record(z.string(), UserUsageEntrySchema).default({})).meta(Unrestricted),
    trial: (UserTrialStatusSchema.optional()).meta(Unrestricted),
    /** Account-level entitlements, keyed by handle. */
    entitlements: (z.record(z.string(), z.union([z.boolean(), EntitlementGrantSchema])).default({})).meta(Unrestricted),
    /** Per-instance breakdowns when the account has multiple product instances. */
    instances: (z.array(UserInstanceContextSchema).optional()).meta(Unrestricted),
    /** Customer-defined fields: role, app-level permissions, display prefs. */
    custom: (z.record(z.string(), z.union([z.string(), z.number(), z.boolean(), z.null()])).default({})).meta(Pii),
    /**
     * Transient personalization token map.
     *
     * Holds SDK-derived tokens (plan_name, usage_current, etc.) merged with
     * app-provided tokens.  Not persisted to the backend — rebuilt on each
     * SDK session from context + exported config.
     */
    personalization: (z.record(z.string(), z.union([z.string(), z.number()])).default({}))
      .meta({ ...Unrestricted, 'x-revturbine-schema-persistence': Transient }),
  })
    .meta({ id: 'UserContext', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const userContextPaths: ZodOpenApiPathsObject = {
  '/api/user-contexts': {
    get: operation({
      operationId: 'listUserContexts',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List user contexts',
      tags: ['users'],
      responses: { '200': { description: 'User context list', content: { 'application/json': { schema: ListEnvelope(UserContextSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'user-contexts', persistence: { table: 'userContexts', mode: 'list' } },
    }),
  },
  '/api/user-contexts/{userContextId}': {
    get: operation({
      operationId: 'getUserContext',
      requestParams: { path: z.object({ userContextId: z.string() }) },
      summary: 'Get user context',
      tags: ['users'],
      responses: { '200': { description: 'User context', content: { 'application/json': { schema: UserContextSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'user-contexts', persistence: { table: 'userContexts', mode: 'get' } },
    }),
  },
};
