/**
 * Usage lifecycle — pure functions for deriving usage personalization
 * tokens, evaluating threshold crossings, and building usage snapshots.
 */

import type { ExportedConfig } from '@revt-eng/schema';
import type { EntitlementResult } from '../../core/types';
import {
  isRecord,
  usageAmountsFromEntries,
  usageTokenPrefixFromEntitlementId,
  configuredPlanNameFromExportedConfig,
  type JsonObject,
  type JsonValue,
} from '../../core/helpers';
import type { UserContextSnapshot } from './user-context';

// ── Types ───────────────────────────────────────────────────────────

export type UsageBalances = Record<string, number>;

export type PersonalizationTokens = Record<string, string | number>;

export interface UsageSnapshotEntry {
  current: number;
  limit?: number;
}

export type UsageSnapshot = Record<string, UsageSnapshotEntry>;

export interface UsageThreshold {
  limit: number;
  warningPercent: number;
}

export interface UsageThresholdCrossing {
  type: 'usage_limit_approaching' | 'usage_limit_reached';
  entitlement_handle: string;
  current_usage: number;
  usage_limit: number;
  usage_percent: number;
  threshold: number;
}

export type TrialStage = 'none' | 'midpoint' | 'expiring' | 'expired';

export interface TrialContext {
  in_trial: boolean;
  trial_type?: string;
  plan_handle?: string;
  day_number?: number;
  days_remaining?: number;
}

// ── Pure functions ──────────────────────────────────────────────────

/**
 * Recalculate derived usage personalization tokens.
 *
 * Returns a new personalization map with `usage_current`, `usage_limit`,
 * `usage_remaining`, `usage_percent` tokens — both per-entitlement prefixed
 * and top-level shorthand.
 */
export function recalculateDerivedUsageTokens(input: {
  context: UserContextSnapshot;
  exportedConfig: ExportedConfig | undefined;
  usageBalances: UsageBalances;
  usageTokenPrefixByEntitlement: Map<string, string>;
  usageThresholdLookup: (entitlement: string) => UsageThreshold | null;
}): Record<string, JsonValue> {
  const { context, exportedConfig, usageBalances, usageTokenPrefixByEntitlement, usageThresholdLookup } = input;

  // Preserve app-provided personalization tokens (non-derived).
  const appTokens: JsonObject = {};
  for (const [key, value] of Object.entries(context.personalization ?? {})) {
    if (!/^(usage_(current|limit|remaining|percent)|.+_usage_(current|limit|remaining|percent)|plan_name|user_id)$/i.test(key)) {
      appTokens[key] = value as JsonValue;
    }
  }

  const nextPersonalization: JsonObject = { ...appTokens };
  const configuredPlanName = configuredPlanNameFromExportedConfig(exportedConfig, context.plan);

  if (configuredPlanName) {
    nextPersonalization.plan_name = configuredPlanName;
  } else if (typeof context.plan === 'object' && context.plan?.name) {
    nextPersonalization.plan_name = context.plan.name;
  }

  const mergedUsage: Record<string, number> = {
    ...usageAmountsFromEntries(context.usage),
    ...usageBalances,
  };

  const usageEntries = Object.entries(mergedUsage)
    .filter(([, current]) => Number.isFinite(current))
    .sort(([a], [b]) => a.localeCompare(b));

  let firstUsageCurrent: number | undefined;
  let firstUsageLimit: number | undefined;
  let firstUsageRemaining: number | undefined;
  let firstUsagePercent: number | undefined;
  const usageCandidates: Array<{
    prefix: string;
    current: number;
    limit?: number;
    remaining?: number;
    percent?: number;
  }> = [];

  for (const [entitlementId, current] of usageEntries) {
    const prefix = usageTokenPrefixByEntitlement.get(entitlementId)
      ?? usageTokenPrefixFromEntitlementId(entitlementId);
    if (!prefix) continue;

    const threshold = usageThresholdLookup(entitlementId);
    const limit = threshold?.limit;
    const remaining = limit !== undefined ? Math.max(0, limit - current) : undefined;
    const percent = limit !== undefined && limit > 0 ? Math.min(100, Math.round((current / limit) * 100)) : undefined;

    nextPersonalization[`${prefix}_usage_current`] = current;
    if (limit !== undefined) {
      nextPersonalization[`${prefix}_usage_limit`] = limit;
    }
    if (remaining !== undefined) {
      nextPersonalization[`${prefix}_usage_remaining`] = remaining;
    }
    if (percent !== undefined) {
      nextPersonalization[`${prefix}_usage_percent`] = percent;
    }

    usageCandidates.push({
      prefix,
      current,
      ...(limit !== undefined ? { limit } : {}),
      ...(remaining !== undefined ? { remaining } : {}),
      ...(percent !== undefined ? { percent } : {}),
    });

    if (firstUsageCurrent === undefined) {
      firstUsageCurrent = current;
      firstUsageLimit = limit;
      firstUsageRemaining = remaining;
      firstUsagePercent = percent;
    }
  }

  const preferredUsage = usageCandidates.find((candidate) => candidate.prefix === 'core')
    ?? usageCandidates.find((candidate) => candidate.limit !== undefined)
    ?? usageCandidates[0];

  if (preferredUsage) {
    firstUsageCurrent = preferredUsage.current;
    firstUsageLimit = preferredUsage.limit;
    firstUsageRemaining = preferredUsage.remaining;
    firstUsagePercent = preferredUsage.percent;
  }

  if (firstUsageCurrent !== undefined) nextPersonalization.usage_current = firstUsageCurrent;
  if (firstUsageLimit !== undefined) nextPersonalization.usage_limit = firstUsageLimit;
  if (firstUsageRemaining !== undefined) nextPersonalization.usage_remaining = firstUsageRemaining;
  if (firstUsagePercent !== undefined) nextPersonalization.usage_percent = firstUsagePercent;

  return nextPersonalization;
}

/**
 * Build personalization tokens from user context + config.
 */
export function getPersonalizationTokens(
  context: UserContextSnapshot,
  exportedConfig: ExportedConfig | undefined,
): PersonalizationTokens {
  const tokens: PersonalizationTokens = {};
  const personalization = context.personalization ?? {};

  for (const [key, value] of Object.entries(personalization)) {
    if (key === 'user_id') continue;
    if (typeof value === 'string' || typeof value === 'number') {
      tokens[key] = value;
    }
  }

  if (tokens.plan_name === undefined) {
    const configuredPlanName = configuredPlanNameFromExportedConfig(exportedConfig, context.plan);
    if (configuredPlanName) {
      tokens.plan_name = configuredPlanName;
    } else if (typeof context.plan === 'object' && context.plan?.name) {
      tokens.plan_name = context.plan.name;
    }
  }

  return tokens;
}

/**
 * Build a usage snapshot from merged usage balances.
 */
export function getUsage(input: {
  context: UserContextSnapshot;
  usageBalances: UsageBalances;
  usageTokenPrefixByEntitlement: Map<string, string>;
  usageThresholdLookup: (entitlement: string) => UsageThreshold | null;
}): UsageSnapshot {
  const mergedUsage: Record<string, number> = {
    ...usageAmountsFromEntries(input.context.usage),
    ...input.usageBalances,
  };

  const snapshot: UsageSnapshot = {};

  for (const [entitlementId, current] of Object.entries(mergedUsage)) {
    if (!Number.isFinite(current)) continue;

    const usageUnit = input.usageTokenPrefixByEntitlement.get(entitlementId)
      ?? usageTokenPrefixFromEntitlementId(entitlementId)
      ?? entitlementId;
    const threshold = input.usageThresholdLookup(entitlementId);

    snapshot[usageUnit] = {
      current,
      ...(threshold?.limit !== undefined ? { limit: threshold.limit } : {}),
    };
  }

  return snapshot;
}

/**
 * Evaluate usage threshold crossings between prev and next usage states.
 *
 * Returns a list of crossing events (approaching / reached) that should
 * be emitted as triggers.
 */
export function evaluateUsageThresholdCrossings(
  prevUsage: Record<string, number>,
  nextUsage: Record<string, number>,
  thresholdLookup: (entitlement: string) => UsageThreshold | null,
): UsageThresholdCrossing[] {
  const crossings: UsageThresholdCrossing[] = [];

  for (const [entitlement, value] of Object.entries(nextUsage)) {
    const prevVal = prevUsage[entitlement] || 0;
    if (!Number.isFinite(value) || value <= prevVal) continue;

    const threshold = thresholdLookup(entitlement);
    if (!threshold) continue;

    const prevPercent = (prevVal / threshold.limit) * 100;
    const nextPercent = (value / threshold.limit) * 100;

    if (nextPercent >= threshold.warningPercent && prevPercent < threshold.warningPercent) {
      crossings.push({
        type: 'usage_limit_approaching',
        entitlement_handle: entitlement,
        current_usage: value,
        usage_limit: threshold.limit,
        usage_percent: Math.min(100, Math.round(nextPercent)),
        threshold: threshold.warningPercent,
      });
    }

    if (value >= threshold.limit && prevVal < threshold.limit) {
      crossings.push({
        type: 'usage_limit_reached',
        entitlement_handle: entitlement,
        current_usage: value,
        usage_limit: threshold.limit,
        usage_percent: Math.min(100, Math.round(nextPercent)),
        threshold: 100,
      });
    }
  }

  return crossings;
}

/**
 * Derive the trial trigger stage from current trial status and prior stage.
 */
export function deriveTrialTriggerStage(
  status: TrialContext,
  lastStage: TrialStage,
  trialExpiringDays: number = 3,
): TrialStage {
  if (!status.in_trial) return lastStage === 'none' ? 'none' : 'expired';

  const daysRemaining = Number(status.days_remaining);
  if (Number.isFinite(daysRemaining) && daysRemaining <= 0) return 'expired';
  if (Number.isFinite(daysRemaining) && daysRemaining <= trialExpiringDays) return 'expiring';

  const dayNumber = Number(status.day_number);
  if (Number.isFinite(dayNumber) && dayNumber > 0 && Number.isFinite(daysRemaining)) {
    const totalDays = dayNumber + Math.max(0, daysRemaining);
    if (totalDays > 0 && dayNumber >= Math.ceil(totalDays / 2)) {
      return 'midpoint';
    }
  }

  return 'none';
}
