/**
 * Content schemas — content surfaces, messages, CTA paths, surface templates, and message blocks.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, StudioSurfaceTypeSchema, CtaActionTypeSchema, NameField, HandleField, DescriptionField, MetadataField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { External } = SchemaExposure;



// ── Message ──────────────────────────────────────────────────────────────────

export const MessageSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    channel: (z.enum(['in_app', 'email', 'push', 'sms', 'webhook'])).meta(Unrestricted),
    subject: (z.string().max(500).optional()).meta(Unrestricted),
    body: (z.string()).meta(Unrestricted),
    template_variables: (z.array(z.string()).default([])).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Message', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

// ── CTA path ─────────────────────────────────────────────────────────────────

// CtaActionTypeSchema is re-exported from core/common.ts
export { CtaActionTypeSchema } from '../../core/common';

export const CtaPathSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    slug: (HandleField).meta(Unrestricted),
    action_type: (CtaActionTypeSchema).meta(Unrestricted),
    target_url: (z.string().optional()).meta(Unrestricted),
    target_plan_id: (z.string().optional()).meta(Unrestricted),
    config_fields: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'CtaPath', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

// ── Surface template ─────────────────────────────────────────────────────────

export const TemplateFieldTypeSchema =
  z.enum([
    'header', 'body', 'secondary_body', 'message', 'cta_label', 'secondary_label',
    'image', 'toggle', 'duration', 'send_delay', 'entitlement', 'plan',
    'dropdown', 'json',
  ])
    .meta({ id: 'TemplateFieldType', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

export const FieldDefinitionSchema =
  z.object({
    name: z.string().min(1),
    field_type: TemplateFieldTypeSchema,
    required: z.boolean().default(false),
    default_value: z.unknown().optional(),
  })
    .meta({ id: 'FieldDefinition', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

export const SurfaceTemplateSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    surface_type: (StudioSurfaceTypeSchema).meta(Unrestricted),
    field_definitions: (z.array(FieldDefinitionSchema).default([])).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
  })
    .meta({ id: 'SurfaceTemplate', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

// ── Message block (reusable content with segment variation) ──────────────────

export const MessageBlockRecordSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    content_fields: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    variation_dimension_id: (z.string().optional()).meta(Unrestricted),
    variation_values: (z.array(z.object({
      segment_value_id: z.string(),
      content_fields_override: z.record(z.string(), z.unknown()),
    })).optional()).meta(Unrestricted),
    notes: (z.string().max(1000).optional()).meta(Unrestricted),
    used_in_count: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'MessageBlockRecord', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': External }
);

// ── Content placement payload (segment→block content delivery) ───────────────

/** An entry in a payload's segment→message-block routing table. */
export const ContentPayloadSegmentEntrySchema =
  z.object({
    segment_id: (z.string().min(1)).meta(Unrestricted),
    message_block_id: (z.string().min(1)).meta(Unrestricted),
    ui_path_id: (z.string().optional()).meta(Unrestricted),
    promotion_id: (z.string().optional()).meta(Unrestricted),
  })
    .meta({ id: 'ContentPayloadSegmentEntry', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

/**
 * A content delivery payload that binds a surface template to message blocks,
 * with optional segment-based content routing. Used by the SDK to resolve
 * which message block to display for a given user's segments.
 */
export const ContentPlacementPayloadSchema =
  z.object({
    payload_id: (z.string().min(1)).meta(Unrestricted),
    tenant_id: (z.string().min(1)).meta(Unrestricted),
    name: (NameField).meta(Unrestricted),
    surface_template_id: (z.string().min(1)).meta(Unrestricted),
    default_message_block_id: (z.string().min(1)).meta(Unrestricted),
    segment_content_map: (z.array(ContentPayloadSegmentEntrySchema).optional()).meta(Unrestricted),
    ui_path_id: (z.string().optional()).meta(Unrestricted),
    promotion_id: (z.string().optional()).meta(Unrestricted),
    status: (z.enum(['draft', 'active', 'inactive'])).meta(Unrestricted),
    created_at: (z.string().datetime().optional()).meta({ ...Unrestricted, readOnly: true }),
    updated_at: (z.string().datetime().optional()).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'ContentPlacementPayload', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const contentPaths: ZodOpenApiPathsObject = {
  '/api/surface-templates': {
    get: operation({
      operationId: 'listSurfaceTemplates',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List surface templates',
      tags: ['content'],
      responses: { '200': { description: 'Template list', content: { 'application/json': { schema: ListEnvelope(SurfaceTemplateSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'surface-templates', persistence: { table: 'surfaceTemplates', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createSurfaceTemplate',
      summary: 'Create surface template',
      tags: ['content'],
      requestBody: { required: true, content: { 'application/json': { schema: SurfaceTemplateSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: SurfaceTemplateSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'surface-templates', persistence: { table: 'surfaceTemplates', mode: 'create' } },
    }),
  },
  '/api/messages': {
    get: operation({
      operationId: 'listMessageBlocks',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List message blocks',
      tags: ['content'],
      responses: { '200': { description: 'Message block list', content: { 'application/json': { schema: ListEnvelope(MessageBlockRecordSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'message-blocks', persistence: { table: 'messageBlocks', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createMessageBlock',
      summary: 'Create message block',
      tags: ['content'],
      requestBody: { required: true, content: { 'application/json': { schema: MessageBlockRecordSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: MessageBlockRecordSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'message-blocks', persistence: { table: 'messageBlocks', mode: 'create' } },
    }),
  },
  '/api/cta-paths': {
    get: operation({
      operationId: 'listCtaPaths',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List CTA paths',
      tags: ['content'],
      responses: { '200': { description: 'CTA path list', content: { 'application/json': { schema: ListEnvelope(CtaPathSchema) } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'cta-paths', persistence: { table: 'ctaPaths', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createCtaPath',
      summary: 'Create custom CTA path',
      tags: ['content'],
      requestBody: { required: true, content: { 'application/json': { schema: CtaPathSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: CtaPathSchema } } } },
      'x-revturbine-operation': { exposure: 'external', resource: 'cta-paths', persistence: { table: 'ctaPaths', mode: 'create' } },
    }),
  },
};
