// ── Stripe integration config ────────────────────────────────────────────────

/**
 * Onboarding funnel state. Tracks where a tenant is in the Stripe Connect
 * onboarding pipeline. Used to gate features and drive re-engagement.
 *
 *   not_started → started → details_submitted → charges_enabled → activated
 *                 ↑ deauthorized (terminal unless re-started)
 */
export const OnboardingStateSchema =
  z.enum(['not_started', 'started', 'details_submitted', 'charges_enabled', 'activated', 'deauthorized'])
    .meta({ id: 'OnboardingState', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal });

export const StripeIntegrationConfigSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    stripe_account_id: (z.string().min(1)).meta(Unrestricted),
    live_mode: (z.boolean().default(false)).meta(Unrestricted),
    /** Funnel state for the Connect onboarding pipeline. */
    onboarding_state: (OnboardingStateSchema.default('not_started')).meta({ ...Unrestricted, readOnly: true }),
    /** Connect onboarding status — tracks whether hosted onboarding is complete. */
    onboarding_complete: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    /** Whether the connected account can process charges (read from Stripe). */
    charges_enabled: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    /** Whether the connected account has details submitted (read from Stripe). */
    details_submitted: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    /** Whether the connected account can receive payouts (read from Stripe). */
    payouts_enabled: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    webhook_secret_set: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    sync_products: (z.boolean().default(true)).meta(Unrestricted),
    sync_prices: (z.boolean().default(true)).meta(Unrestricted),
    sync_subscriptions: (z.boolean().default(true)).meta(Unrestricted),
    sync_invoices: (z.boolean().default(false)).meta(Unrestricted),
    default_currency: (z.string().length(3).default('USD')).meta(Unrestricted),
    tax_behavior: (z.enum(['inclusive', 'exclusive', 'unspecified']).default('unspecified')).meta(Unrestricted),
    /** ISO timestamp of the last successful full data sync from Stripe. */
    last_sync_at: (z.string().optional()).meta({ ...Unrestricted, readOnly: true }),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'StripeIntegrationConfig', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

