import type {
  AnyDomainProvider,
  DomainProviderName,
  ResolvedProviderContext,
  ResolvedDomainType,
  TraitsProviderState,
} from './types';

/* ------------------------------------------------------------------ */
/*  Cache entry                                                        */
/* ------------------------------------------------------------------ */

interface CacheEntry {
  value: unknown;
  resolvedAt: number;
  ttlMs: number;
}

/* ------------------------------------------------------------------ */
/*  DomainProviderRegistry                                             */
/* ------------------------------------------------------------------ */

/**
 * Manages registered domain providers and resolves their collective
 * state into a typed {@link ResolvedProviderContext}.
 *
 * Lifecycle:
 * 1. Providers are registered at SDK init time (or later via hooks).
 * 2. Before each placement decision, `resolveAll()` is called.
 * 3. Each provider's `resolve()` is invoked (or its cached value is reused
 *    if within `cacheTtlMs`).
 * 4. Subscriptions are wired automatically on register for push-based
 *    invalidation.
 */
export class DomainProviderRegistry {
  private providers = new Map<DomainProviderName, AnyDomainProvider>();
  private cache = new Map<DomainProviderName, CacheEntry>();
  private unsubscribers = new Map<DomainProviderName, () => void>();

  /* ---- Registration ---- */

  /** Register a domain provider, replacing any existing for the same domain. */
  register(provider: AnyDomainProvider): void {
    const prev = this.providers.get(provider.domain);
    if (prev) {
      this.unregister(prev.domain);
    }

    this.providers.set(provider.domain, provider);

    // Wire push-based cache invalidation
    if (provider.subscribe) {
      const unsub = provider.subscribe((next) => {
        this.cache.set(provider.domain, {
          value: next,
          resolvedAt: Date.now(),
          ttlMs: provider.cacheTtlMs ?? 0,
        });
      });
      this.unsubscribers.set(provider.domain, unsub);
    }
  }

  /** Unregister a provider by domain name. */
  unregister(domain: DomainProviderName): void {
    this.providers.delete(domain);
    this.cache.delete(domain);
    const unsub = this.unsubscribers.get(domain);
    if (unsub) {
      unsub();
      this.unsubscribers.delete(domain);
    }
  }

  /** Remove all providers, caches, and subscriptions. */
  clear(): void {
    for (const unsub of this.unsubscribers.values()) unsub();
    this.providers.clear();
    this.cache.clear();
    this.unsubscribers.clear();
  }

  /* ---- Resolution ---- */

  /**
   * Resolve all registered providers into a single typed context.
   * Respects per-provider `cacheTtlMs`; stale entries are re-resolved.
   *
   * All trait-contributing providers (`'traits'` and `'traits:*'`) are
   * merged into a single `traits` slot. Later-resolved providers
   * override earlier ones for the same key.
   */
  async resolveAll(): Promise<ResolvedProviderContext> {
    const entries = Array.from(this.providers.entries());
    const results = await Promise.all(
      entries.map(async ([domain, provider]) => {
        const cached = this.cache.get(domain);
        const now = Date.now();

        if (cached && cached.ttlMs > 0 && now - cached.resolvedAt < cached.ttlMs) {
          return [domain, cached.value] as const;
        }

        const value = await provider.resolve();

        this.cache.set(domain, {
          value,
          resolvedAt: now,
          ttlMs: provider.cacheTtlMs ?? 0,
        });

        return [domain, value] as const;
      }),
    );

    const ctx: ResolvedProviderContext = {};
    const mergedTraits: Record<string, string | number | boolean> = {};
    let hasTraits = false;

    for (const [domain, value] of results) {
      if (domain === 'traits' || domain.startsWith('traits:')) {
        const traitState = value as TraitsProviderState;
        if (traitState?.traits) {
          Object.assign(mergedTraits, traitState.traits);
          hasTraits = true;
        }
      } else {
        (ctx as any)[domain] = value;
      }
    }

    if (hasTraits) {
      ctx.traits = { traits: mergedTraits };
    }

    return ctx;
  }

  /**
   * Return the raw resolved value for a single domain (cache-aware).
   */
  async get<D extends DomainProviderName>(
    domain: D,
  ): Promise<ResolvedDomainType<D> | undefined> {
    const provider = this.providers.get(domain);
    if (!provider) return undefined;

    const cached = this.cache.get(domain);
    const now = Date.now();
    if (cached && cached.ttlMs > 0 && now - cached.resolvedAt < cached.ttlMs) {
      return cached.value as ResolvedDomainType<D>;
    }

    const value = await provider.resolve();
    this.cache.set(domain, {
      value,
      resolvedAt: now,
      ttlMs: provider.cacheTtlMs ?? 0,
    });
    return value as ResolvedDomainType<D>;
  }

  /** Check whether a specific domain provider has been registered. */
  has(domain: DomainProviderName): boolean {
    return this.providers.has(domain);
  }

  /** Number of registered providers. */
  get size(): number {
    return this.providers.size;
  }

  /** Invalidate a single domain cache entry. */
  invalidate(domain: DomainProviderName): void {
    this.cache.delete(domain);
  }

  /** Invalidate all cached values (forces re-resolve on next call). */
  invalidateAll(): void {
    this.cache.clear();
  }
}
