/**
 * Tenant schemas — top-level data isolation boundary.
 *
 * A Tenant is the root grouping of all data.  Data may NEVER be joined
 * across Tenants; every query is implicitly scoped to a single tenant_id.
 */
import { z } from 'zod';
import { IdField, TimestampFields, NameField, HandleField, MetadataField } from '../common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Tenant status ────────────────────────────────────────────────────────────

export const TenantStatusSchema =
  z.enum(['active', 'suspended', 'archived'])
    .meta({ id: 'TenantStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Tenant ───────────────────────────────────────────────────────────────────

export const TenantSchema =
  IdField.merge(TimestampFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    status: (TenantStatusSchema.default('active')).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Tenant', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const tenantPaths: ZodOpenApiPathsObject = {
  '/api/tenants': {
    get: operation({
      operationId: 'listTenants',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List tenants',
      tags: ['tenants'],
      responses: { '200': { description: 'Tenant list', content: { 'application/json': { schema: ListEnvelope(TenantSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createTenant',
      summary: 'Create tenant',
      tags: ['tenants'],
      requestBody: { required: true, content: { 'application/json': { schema: TenantSchema } } },
      responses: {
        '201': { description: 'Created', content: { 'application/json': { schema: TenantSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'create' } },
    }),
  },
  '/api/tenants/{tenantId}': {
    get: operation({
      operationId: 'getTenant',
      requestParams: { path: z.object({ tenantId: z.string() }) },
      summary: 'Get tenant by ID',
      tags: ['tenants'],
      responses: { '200': { description: 'Tenant', content: { 'application/json': { schema: TenantSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updateTenant',
      requestParams: { path: z.object({ tenantId: z.string() }) },
      summary: 'Update tenant',
      tags: ['tenants'],
      requestBody: { required: true, content: { 'application/json': { schema: TenantSchema.partial() } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: TenantSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'update' } },
    }),
  },
  '/api/tenants/{tenantId}/suspend': {
    post: operation({
      operationId: 'suspendTenant',
      requestParams: { path: z.object({ tenantId: z.string() }) },
      summary: 'Suspend tenant (disables all API access)',
      tags: ['tenants'],
      responses: { '200': { description: 'Suspended', content: { 'application/json': { schema: TenantSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'update' } },
    }),
  },
  '/api/tenants/{tenantId}/reactivate': {
    post: operation({
      operationId: 'reactivateTenant',
      requestParams: { path: z.object({ tenantId: z.string() }) },
      summary: 'Reactivate a suspended tenant',
      tags: ['tenants'],
      responses: { '200': { description: 'Reactivated', content: { 'application/json': { schema: TenantSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'tenants', persistence: { table: 'tenants', mode: 'update' } },
    }),
  },
};
