/**
 * Changelog schemas — audit log entries for control-plane changes.
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields, MetadataField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Change log entry ─────────────────────────────────────────────────────────

export const ChangeLogActionSchema =
  z.enum(['create', 'update', 'delete', 'archive', 'restore', 'reorder', 'duplicate', 'sync', 'publish'])
    .meta({ id: 'ChangeLogAction', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

export const ChangeLogEntrySchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    action: (ChangeLogActionSchema).meta(Unrestricted),
    resource_type: (z.string().min(1).max(100)).meta(Unrestricted),
    resource_id: (z.string().min(1)).meta(Unrestricted),
    resource_name: (z.string().max(200).optional()).meta(Unrestricted),
    actor_id: (z.string().min(1)).meta(Unrestricted),
    actor_email: (z.string().email().optional()).meta(Unrestricted),
    diff: (z.object({
      before: z.record(z.string(), z.unknown()).optional(),
      after: z.record(z.string(), z.unknown()).optional(),
    }).optional()).meta(Unrestricted),
    summary: (z.string().max(1000).optional()).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'ChangeLogEntry', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const changelogPaths: ZodOpenApiPathsObject = {
  '/api/changelog': {
    get: operation({
      operationId: 'listChangeLogEntries',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List change log entries',
      tags: ['changelog'],
      responses: { '200': { description: 'Change log entries', content: { 'application/json': { schema: ListEnvelope(ChangeLogEntrySchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changelog', persistence: { table: 'changeLogEntries', mode: 'list' } },
    }),
  },
  '/api/changelog/{entryId}': {
    get: operation({
      operationId: 'getChangeLogEntry',
      requestParams: { path: z.object({ entryId: z.string() }) },
      summary: 'Get change log entry by ID',
      tags: ['changelog'],
      responses: { '200': { description: 'Change log entry', content: { 'application/json': { schema: ChangeLogEntrySchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'changelog', persistence: { table: 'changeLogEntries', mode: 'get' } },
    }),
  },
};
