/**
 * Promotion schemas — discount and promotional offer definitions.
 */
import { z } from 'zod';
import { ConfigVersionFields, IdField, TenantIdField, TimestampFields, NameField, HandleField, MetadataField, NullableDatetimeField } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../../core/classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Financial } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Promotion status ─────────────────────────────────────────────────────────

export const PromotionStatusSchema =
  z.enum(['draft', 'scheduled', 'live', 'expired', 'archived'])
    .meta({ id: 'PromotionStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

export const DiscountTypeSchema =
  z.enum(['percentage', 'fixed_amount', 'free_months'])
    .meta({ id: 'DiscountType', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Promotion ────────────────────────────────────────────────────────────────

export const PromotionSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).merge(ConfigVersionFields).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    description: (z.string().max(1000).optional()).meta(Unrestricted),
    rt_status: (PromotionStatusSchema.default('draft')).meta(Unrestricted),
    discount_type: (DiscountTypeSchema).meta(Unrestricted),
    discount_value: (z.number().min(0)).meta(Financial),
    currency: (z.string().length(3).default('USD')).meta(Financial),
    applicable_plan_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    applicable_addon_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    target_segment_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    max_redemptions: (z.number().int().min(0).nullable().default(null)).meta(Unrestricted),
    current_redemptions: (z.number().int().min(0).default(0)).meta({ ...Unrestricted, readOnly: true }),
    coupon_code: (z.string().max(100).optional()).meta(Unrestricted),
    starts_at: (NullableDatetimeField).meta(Unrestricted),
    ends_at: (NullableDatetimeField).meta(Unrestricted),
    // Stripe integration
    stripe_coupon_id: (z.string().nullable().default(null)).meta(Unrestricted),
    stripe_promotion_code_id: (z.string().nullable().default(null)).meta(Unrestricted),
    auto_sync_stripe: (z.boolean().default(false)).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Promotion', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const promotionPaths: ZodOpenApiPathsObject = {
  '/api/promotions': {
    get: operation({
      operationId: 'listPromotions',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List promotions',
      tags: ['promotions'],
      responses: { '200': { description: 'Promotion list', content: { 'application/json': { schema: ListEnvelope(PromotionSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createPromotion',
      summary: 'Create promotion',
      tags: ['promotions'],
      requestBody: { required: true, content: { 'application/json': { schema: PromotionSchema } } },
      responses: { '201': { description: 'Created', content: { 'application/json': { schema: PromotionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'create' } },
    }),
  },
  '/api/promotions/{promotionId}': {
    get: operation({
      operationId: 'getPromotion',
      requestParams: { path: z.object({ promotionId: z.string() }) },
      summary: 'Get promotion',
      tags: ['promotions'],
      responses: { '200': { description: 'Promotion', content: { 'application/json': { schema: PromotionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updatePromotion',
      requestParams: { path: z.object({ promotionId: z.string() }) },
      summary: 'Update promotion',
      tags: ['promotions'],
      requestBody: { required: true, content: { 'application/json': { schema: PromotionSchema.partial() } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: PromotionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'update' } },
    }),
    delete: operation({
      operationId: 'deletePromotion',
      requestParams: { path: z.object({ promotionId: z.string() }) },
      summary: 'Delete (archive) promotion',
      tags: ['promotions'],
      responses: { '204': { description: 'Deleted' } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'delete' } },
    }),
  },
  '/api/promotions/{promotionId}/sync-stripe': {
    post: operation({
      operationId: 'syncPromotionToStripe',
      requestParams: { path: z.object({ promotionId: z.string() }) },
      summary: 'Sync promotion to Stripe as coupon/promotion code',
      tags: ['promotions'],
      responses: { '200': { description: 'Synced', content: { 'application/json': { schema: PromotionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'update' } },
    }),
  },
  '/api/promotions/{promotionId}/duplicate': {
    post: operation({
      operationId: 'duplicatePromotion',
      requestParams: { path: z.object({ promotionId: z.string() }) },
      summary: 'Duplicate promotion',
      tags: ['promotions'],
      responses: { '201': { description: 'Duplicated', content: { 'application/json': { schema: PromotionSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'promotions', persistence: { table: 'promotions', mode: 'create' } },
    }),
  },
};
