/**
 * Surface slot lifecycle — pure functions for deterministic slot ID
 * generation, route normalization, and slug sanitization.
 */

import type { CryptoProvider } from '../../core/crypto';
import { fallbackHashBase64Url } from '../../core/crypto';
import { normalizedRoute } from '../../core/helpers';

// ── Types ───────────────────────────────────────────────────────────

export interface SlotIdInput {
  tenantId: string;
  placementName: string;
  placementScopeKey?: string;
  pageRoute: string;
}

// ── Pure functions ──────────────────────────────────────────────────

/**
 * Generate a deterministic placement ID from slot registration inputs.
 *
 * Uses SHA-256 when a CryptoProvider is supplied; falls back to FNV-1a
 * otherwise. The ID is a 22-char URL-safe base64 string.
 */
export async function generatePlacementId(
  input: SlotIdInput,
  crypto?: CryptoProvider,
): Promise<string> {
  const route = normalizedRoute(input.pageRoute);
  const canonical = [
    input.tenantId,
    route,
    input.placementName.trim().toLowerCase(),
    String(input.placementScopeKey || '').trim().toLowerCase(),
  ].join('::');

  if (crypto) {
    try {
      const digest = await crypto.sha256Base64Url(canonical);
      return digest.slice(0, 22);
    } catch {
      // Fall through to FNV-1a fallback
    }
  }

  return fallbackHashBase64Url(canonical).slice(0, 22);
}
