/**
 * Cross-domain normalization helpers.
 *
 * Pure functions that normalize wire-format data into typed shapes.
 * Extracted here because they serve multiple domains (entitlements,
 * placements, decisions) and should not create domain-to-domain imports.
 */

import type { SurfaceType } from '@revt-eng/schema';
import type { PlacementOutput } from './types';
import { isRecord } from './helpers';
import { SurfaceTypeSchema } from './common';

type RevTurbineSurfaceType = SurfaceType;

const VALID_SURFACE_TYPES: ReadonlySet<SurfaceType> = new Set<SurfaceType>(SurfaceTypeSchema.options);

export function normalizePlacementOutput(
  data: unknown, // sdk-ok: boundary-parse
  generateRequestId: () => string,
): PlacementOutput | null {
  if (!isRecord(data)) return null;
  const output_id = typeof data.output_id === 'string' ? data.output_id : '';
  if (!output_id) return null;
  const surfaceRaw = isRecord(data.surface) ? data.surface : {};
  const surfaceType = VALID_SURFACE_TYPES.has(surfaceRaw.type as RevTurbineSurfaceType)
    ? (surfaceRaw.type as RevTurbineSurfaceType)
    : 'custom';
  const ctaPath = isRecord(data.cta_path)
    ? data.cta_path
    : isRecord(data.ui_path)
      ? data.ui_path
      : {};

  return {
    output_id,
    category: typeof data.category === 'string' ? data.category : 'unknown',
    surface: {
      ...(typeof surfaceRaw.template === 'string' ? { template: surfaceRaw.template } : {}),
      type: surfaceType,
      ...(typeof surfaceRaw.slot_id === 'string' ? { slot_id: surfaceRaw.slot_id } : {}),
    },
    content: isRecord(data.content) ? data.content : {},
    ...(isRecord(data.promotion) ? { promotion: data.promotion } : {}),
    cta_path: ctaPath,
    ui_path: ctaPath,
    rule_id: typeof data.rule_id === 'string' ? data.rule_id : '',
    decision_id: typeof data.decision_id === 'string' ? data.decision_id : generateRequestId(),
    config_version: typeof data.config_version === 'string' ? data.config_version : 'unknown',
    present_upsell: typeof data.present_upsell === 'boolean' ? data.present_upsell : false,
  };
}
