/**
 * Impression history store implementations.
 *
 * - InMemoryImpressionStore — ephemeral, in-process.
 * - StorageImpressionStore  — backed by RevTurbineStorage (localStorage / custom implementation).
 */

import type { RevTurbineStorage } from './storage';
import type {
  ImpressionHistoryStore,
  ImpressionQuery,
  ImpressionRecord,
} from './impression-history-types';
import { TERMINAL_OUTCOMES } from './impression-history-types';

/* ------------------------------------------------------------------ */
/*  In-memory store                                                    */
/* ------------------------------------------------------------------ */

/**
 * Ephemeral in-memory impression history store.
 *
 * Data does not survive beyond the current process/request.
 * Suitable for server-side rendering or testing.
 */
export class InMemoryImpressionStore implements ImpressionHistoryStore {
  private readonly records = new Map<string, ImpressionRecord[]>();

  append(userId: string, record: ImpressionRecord): void {
    const list = this.records.get(userId) ?? [];
    list.push(record);
    this.records.set(userId, list);
  }

  query(userId: string, query?: ImpressionQuery): ImpressionRecord[] {
    let records = this.records.get(userId) ?? [];
    if (query) records = applyQuery(records, query);
    return records.slice().reverse();
  }

  getRetiredPlacementIds(userId: string): Set<string> {
    const records = this.records.get(userId) ?? [];
    return extractRetiredIds(records);
  }

  getSuppressedPlacements(userId: string): Map<string, string> {
    const records = this.records.get(userId) ?? [];
    return extractSuppressedPlacements(records);
  }

  clear(userId: string): void {
    this.records.delete(userId);
  }
}

/* ------------------------------------------------------------------ */
/*  Storage-backed store                                               */
/* ------------------------------------------------------------------ */

const STORAGE_PREFIX = 'revturbine:impression-history';

/**
 * Impression history store backed by any RevTurbineStorage implementation.
 *
 * Works with:
 * - `InMemoryStorage` (core)
 * - `BrowserStorage` wrapping localStorage (web-sdk)
 * - A custom `RevTurbineStorage` for Postgres persistence (server)
 *
 * Records are serialized as a JSON array per user key.
 * A configurable `maxRecords` limit prevents unbounded growth (default: 500).
 */
export class StorageImpressionStore implements ImpressionHistoryStore {
  private readonly storage: RevTurbineStorage;
  private readonly tenantId: string;
  private readonly maxRecords: number;

  constructor(options: {
    storage: RevTurbineStorage;
    tenantId: string;
    /** Max records to keep per user. Oldest are dropped. Default: 500. */
    maxRecords?: number;
  }) {
    this.storage = options.storage;
    this.tenantId = options.tenantId;
    this.maxRecords = options.maxRecords ?? 500;
  }

  append(userId: string, record: ImpressionRecord): void {
    const records = this.load(userId);
    records.push(record);
    // Trim oldest records if over limit.
    if (records.length > this.maxRecords) {
      records.splice(0, records.length - this.maxRecords);
    }
    this.save(userId, records);
  }

  query(userId: string, query?: ImpressionQuery): ImpressionRecord[] {
    let records = this.load(userId);
    if (query) records = applyQuery(records, query);
    return records.slice().reverse();
  }

  getRetiredPlacementIds(userId: string): Set<string> {
    const records = this.load(userId);
    return extractRetiredIds(records);
  }

  getSuppressedPlacements(userId: string): Map<string, string> {
    const records = this.load(userId);
    return extractSuppressedPlacements(records);
  }

  clear(userId: string): void {
    this.storage.removeItem(this.key(userId));
  }

  private key(userId: string): string {
    return `${STORAGE_PREFIX}:${this.tenantId}:${userId}`;
  }

  private load(userId: string): ImpressionRecord[] {
    const raw = this.storage.getItem(this.key(userId));
    if (!raw) return [];
    try {
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }

  private save(userId: string, records: ImpressionRecord[]): void {
    try {
      this.storage.setItem(this.key(userId), JSON.stringify(records));
    } catch {
      // Swallow quota / serialization errors
    }
  }
}

/* ------------------------------------------------------------------ */
/*  Shared helpers                                                     */
/* ------------------------------------------------------------------ */

function applyQuery(records: ImpressionRecord[], query: ImpressionQuery): ImpressionRecord[] {
  let filtered = records;

  if (query.placementIds && query.placementIds.length > 0) {
    const ids = new Set(query.placementIds);
    filtered = filtered.filter((r) => ids.has(r.placementId));
  }

  if (query.outcomes && query.outcomes.length > 0) {
    const outcomes = new Set(query.outcomes);
    filtered = filtered.filter((r) => outcomes.has(r.outcome));
  }

  if (query.since) {
    const sinceDate = new Date(query.since).getTime();
    filtered = filtered.filter((r) => new Date(r.occurredAt).getTime() >= sinceDate);
  }

  return filtered;
}

function extractRetiredIds(records: ImpressionRecord[]): Set<string> {
  const retired = new Set<string>();
  for (const record of records) {
    if (TERMINAL_OUTCOMES.has(record.outcome)) {
      retired.add(record.placementId);
    }
  }
  return retired;
}

/**
 * Extract suppressed placements that are still within their window.
 * Returns Map<placementId, suppressUntil ISO string>.
 * Only the most recent suppression per placement is considered.
 */
function extractSuppressedPlacements(records: ImpressionRecord[]): Map<string, string> {
  const suppressed = new Map<string, string>();
  const now = Date.now();
  // Walk newest → oldest so first hit per placement wins.
  for (let i = records.length - 1; i >= 0; i--) {
    const record = records[i];
    if (record.outcome !== 'suppressed') continue;
    if (suppressed.has(record.placementId)) continue;
    const until = record.metadata?.suppressUntil;
    if (typeof until !== 'string') continue;
    if (new Date(until).getTime() > now) {
      suppressed.set(record.placementId, until);
    }
  }
  return suppressed;
}
