/**
 * Auth schemas — Zod definitions for Better Auth tables.
 *
 * Covers: users, sessions, accounts, verifications, two-factor,
 * organizations, members, and invitations.
 */
import { z } from 'zod';
import { IdField, TimestampFields, NameField, NullableDatetimeField } from '../common';
import {
  DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../classification';

const { Unrestricted, Pii } = DataClassification;
const { Persisted } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── User role ────────────────────────────────────────────────────────────────

export const UserRoleSchema =
  z.enum(['user', 'admin'])
    .meta({ id: 'UserRole', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── User ─────────────────────────────────────────────────────────────────────

export const AuthUserSchema =
  IdField.merge(TimestampFields).extend({
    name: (NameField).meta(Unrestricted),
    email: (z.string().email()).meta(Pii),
    email_verified: (z.boolean().default(false)).meta(Unrestricted),
    image: (z.string().url().nullable().default(null)).meta(Pii),
    role: (UserRoleSchema.default('user')).meta(Unrestricted),
    banned: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    ban_reason: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    ban_expires: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    two_factor_enabled: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'AuthUser', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Session ──────────────────────────────────────────────────────────────────

export const AuthSessionSchema =
  IdField.merge(TimestampFields).extend({
    expires_at: (z.string().datetime()).meta(Unrestricted),
    token: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    ip_address: (z.string().nullable().default(null)).meta(Pii),
    user_agent: (z.string().nullable().default(null)).meta(Pii),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    active_organization_id: (z.string().nullable().default(null)).meta(Unrestricted),
    impersonated_by: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'AuthSession', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Account (OAuth / credential provider links) ─────────────────────────────

export const AuthAccountSchema =
  IdField.merge(TimestampFields).extend({
    account_id: (z.string().min(1)).meta(Unrestricted),
    provider_id: (z.string().min(1)).meta(Unrestricted),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    access_token: (z.string().nullable().default(null)).meta({ ...Pii, readOnly: true }),
    refresh_token: (z.string().nullable().default(null)).meta({ ...Pii, readOnly: true }),
    id_token: (z.string().nullable().default(null)).meta({ ...Pii, readOnly: true }),
    access_token_expires_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    refresh_token_expires_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    scope: (z.string().nullable().default(null)).meta(Unrestricted),
    password: (z.string().nullable().default(null)).meta({ ...Pii, readOnly: true }),
  })
    .meta({ id: 'AuthAccount', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Verification (email verification, password reset tokens) ─────────────────

export const AuthVerificationSchema =
  IdField.merge(TimestampFields).extend({
    identifier: (z.string().min(1)).meta(Pii),
    value: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    expires_at: (z.string().datetime()).meta(Unrestricted),
  })
    .meta({ id: 'AuthVerification', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Two-factor ───────────────────────────────────────────────────────────────

export const AuthTwoFactorSchema =
  IdField.extend({
    secret: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    backup_codes: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    verified: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'AuthTwoFactor', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Organization ─────────────────────────────────────────────────────────────

export const AuthOrganizationSchema =
  IdField.extend({
    name: (NameField).meta(Unrestricted),
    slug: (z.string().min(1).max(100).nullable().default(null)).meta(Unrestricted),
    logo: (z.string().url().nullable().default(null)).meta(Unrestricted),
    created_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    metadata: (z.string().nullable().default(null)).meta(Unrestricted),
  })
    .meta({ id: 'AuthOrganization', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Organization member role ─────────────────────────────────────────────────

export const OrgMemberRoleSchema =
  z.enum(['owner', 'admin', 'member'])
    .meta({ id: 'OrgMemberRole', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Member ───────────────────────────────────────────────────────────────────

export const AuthMemberSchema =
  IdField.extend({
    organization_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    role: (OrgMemberRoleSchema.default('member')).meta(Unrestricted),
    created_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'AuthMember', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Invitation status ────────────────────────────────────────────────────────

export const InvitationStatusSchema =
  z.enum(['pending', 'accepted', 'rejected', 'canceled', 'expired'])
    .meta({ id: 'InvitationStatus', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Invitation ───────────────────────────────────────────────────────────────

export const AuthInvitationSchema =
  IdField.extend({
    organization_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    email: (z.string().email()).meta(Pii),
    role: (OrgMemberRoleSchema.nullable().default(null)).meta(Unrestricted),
    status: (InvitationStatusSchema.default('pending')).meta(Unrestricted),
    expires_at: (z.string().datetime()).meta(Unrestricted),
    created_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    inviter_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'AuthInvitation', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── Passkey (WebAuthn / FIDO2) ───────────────────────────────────────────────

export const AuthPasskeySchema =
  IdField.extend({
    name: (z.string().max(200).nullable().default(null)).meta(Unrestricted),
    public_key: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    credential_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    counter: (z.number().int().default(0)).meta({ ...Unrestricted, readOnly: true }),
    device_type: (z.string().min(1)).meta(Unrestricted),
    backed_up: (z.boolean().default(false)).meta(Unrestricted),
    transports: (z.string().nullable().default(null)).meta(Unrestricted),
    created_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    aaguid: (z.string().nullable().default(null)).meta(Unrestricted),
  })
    .meta({ id: 'AuthPasskey', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── API key (Better Auth managed keys) ───────────────────────────────────────

export const AuthApiKeySchema =
  IdField.merge(TimestampFields).extend({
    config_id: (z.string().min(1)).meta(Unrestricted),
    name: (z.string().max(200).nullable().default(null)).meta(Unrestricted),
    start: (z.string().nullable().default(null)).meta(Unrestricted),
    reference_id: (z.string().min(1)).meta(Unrestricted),
    prefix: (z.string().nullable().default(null)).meta(Unrestricted),
    key: (z.string().min(1)).meta({ ...Pii, readOnly: true }),
    refill_interval: (z.number().int().nullable().default(null)).meta(Unrestricted),
    refill_amount: (z.number().int().nullable().default(null)).meta(Unrestricted),
    last_refill_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    enabled: (z.boolean().default(true)).meta(Unrestricted),
    rate_limit_enabled: (z.boolean().default(false)).meta(Unrestricted),
    rate_limit_time_window: (z.number().int().nullable().default(null)).meta(Unrestricted),
    rate_limit_max: (z.number().int().nullable().default(null)).meta(Unrestricted),
    request_count: (z.number().int().default(0)).meta({ ...Unrestricted, readOnly: true }),
    remaining: (z.number().int().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    last_request: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    expires_at: (NullableDatetimeField).meta(Unrestricted),
    permissions: (z.string().nullable().default(null)).meta(Unrestricted),
    metadata: (z.string().nullable().default(null)).meta(Unrestricted),
  })
    .meta({ id: 'AuthApiKey', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });

// ── SSO provider (SAML / OIDC federation) ────────────────────────────────────

export const AuthSsoProviderSchema =
  IdField.extend({
    issuer: (z.string().min(1)).meta(Unrestricted),
    oidc_config: (z.string().nullable().default(null)).meta(Unrestricted),
    saml_config: (z.string().nullable().default(null)).meta(Unrestricted),
    user_id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    provider_id: (z.string().min(1)).meta(Unrestricted),
    organization_id: (z.string().nullable().default(null)).meta(Unrestricted),
    domain: (z.string().min(1)).meta(Unrestricted),
  })
    .meta({ id: 'AuthSsoProvider', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal });
