/**
 * ImpressionHistory — records and queries placement impression/interaction history.
 *
 * Wraps an ImpressionHistoryStore backend and provides a clean API for:
 * - Recording impressions and terminal interactions.
 * - Checking whether a placement is retired (should never be shown again).
 * - Querying full history for debugging / analytics.
 *
 * Isomorphic: works with any store backend (in-memory, localStorage, Postgres).
 */

import type {
  ImpressionHistoryStore,
  ImpressionOutcome,
  ImpressionQuery,
  ImpressionRecord,
} from './impression-history-types';
import { TERMINAL_OUTCOMES, DEFAULT_SUPPRESSION_MS } from './impression-history-types';

export interface ImpressionHistoryOptions {
  /** Persistence backend. */
  store: ImpressionHistoryStore;
  /** Current user ID. */
  userId: string;
  /** Default suppression duration in milliseconds. Default: 24 h. */
  defaultSuppressionMs?: number;
}

export class ImpressionHistory {
  private readonly store: ImpressionHistoryStore;
  private userId: string;
  private readonly defaultSuppressionMs: number;
  /**
   * Hot cache of permanently retired placement IDs (dismissed / clicked_thru).
   */
  private retiredCache: Set<string> | null = null;
  /**
   * Hot cache of time-suppressed placement IDs → suppressUntil ISO timestamp.
   */
  private suppressedCache: Map<string, string> | null = null;

  constructor(options: ImpressionHistoryOptions) {
    this.store = options.store;
    this.userId = options.userId;
    this.defaultSuppressionMs = options.defaultSuppressionMs ?? DEFAULT_SUPPRESSION_MS;
  }

  /* ------------------------------------------------------------------ */
  /*  Recording                                                          */
  /* ------------------------------------------------------------------ */

  /**
   * Record an impression — the placement was shown to the user.
   */
  async recordImpression(
    placementId: string,
    payloadId?: string,
    surfaceTemplateId?: string,
    metadata?: Record<string, unknown>,
  ): Promise<void> {
    await this.appendRecord(placementId, 'impressed', payloadId, surfaceTemplateId, metadata);
  }

  /**
   * Record a dismissal — the user explicitly closed the placement.
   * The placement is permanently retired for this user.
   */
  async recordDismissal(
    placementId: string,
    payloadId?: string,
    surfaceTemplateId?: string,
    metadata?: Record<string, unknown>,
  ): Promise<void> {
    await this.appendRecord(placementId, 'dismissed', payloadId, surfaceTemplateId, metadata);
    this.retireInCache(placementId);
  }

  /**
   * Record a click-through — the user engaged with the CTA.
   * The placement is permanently retired for this user.
   */
  async recordClickThru(
    placementId: string,
    payloadId?: string,
    surfaceTemplateId?: string,
    metadata?: Record<string, unknown>,
  ): Promise<void> {
    await this.appendRecord(placementId, 'clicked_thru', payloadId, surfaceTemplateId, metadata);
    this.retireInCache(placementId);
  }

  /**
   * Record a suppression — the system or admin suppressed the placement.
   * The placement is hidden for a configurable duration (not permanent).
   *
   * @param durationMs — suppression window in ms. Falls back to `defaultSuppressionMs`.
   */
  async recordSuppression(
    placementId: string,
    payloadId?: string,
    surfaceTemplateId?: string,
    metadata?: Record<string, unknown>,
    durationMs?: number,
  ): Promise<void> {
    const ms = durationMs ?? this.defaultSuppressionMs;
    const suppressUntil = new Date(Date.now() + ms).toISOString();
    await this.appendRecord(placementId, 'suppressed', payloadId, surfaceTemplateId, {
      ...metadata,
      suppressUntil,
    });
    this.suppressInCache(placementId, suppressUntil);
  }

  /* ------------------------------------------------------------------ */
  /*  Querying                                                           */
  /* ------------------------------------------------------------------ */

  /**
   * Check whether a placement has been permanently retired for this user.
   */
  async isRetired(placementId: string): Promise<boolean> {
    const retired = await this.getRetiredIds();
    return retired.has(placementId);
  }

  /**
   * Return the set of placement IDs retired for this user.
   * Caches the result for synchronous access via `isRetiredSync()`.
   */
  async getRetiredIds(): Promise<Set<string>> {
    if (this.retiredCache) return this.retiredCache;
    const retired = await this.store.getRetiredPlacementIds(this.userId);
    this.retiredCache = retired;
    return retired;
  }

  /**
   * Synchronous check — only valid after `getRetiredIds()` or a recording call
   * has populated the cache. Returns `false` if the cache is cold.
   */
  isRetiredSync(placementId: string): boolean {
    return this.retiredCache?.has(placementId) ?? false;
  }

  /**
   * Synchronous check for time-based suppression.
   * Returns `true` if the placement is within its suppression window.
   */
  isSuppressedSync(placementId: string): boolean {
    if (!this.suppressedCache) return false;
    const until = this.suppressedCache.get(placementId);
    if (!until) return false;
    if (new Date(until).getTime() > Date.now()) return true;
    // Expired — clean up cache entry.
    this.suppressedCache.delete(placementId);
    return false;
  }

  /**
   * Synchronous check: placement should not be shown (retired OR suppressed).
   */
  isHiddenSync(placementId: string): boolean {
    return this.isRetiredSync(placementId) || this.isSuppressedSync(placementId);
  }

  /**
   * Query full history (for debugging, analytics, or inspector panels).
   */
  async queryHistory(query?: ImpressionQuery): Promise<ImpressionRecord[]> {
    return this.store.query(this.userId, query);
  }

  /* ------------------------------------------------------------------ */
  /*  Lifecycle                                                          */
  /* ------------------------------------------------------------------ */

  /**
   * Pre-warm the retired and suppressed caches from the store.
   * Call during SDK initialization for synchronous access.
   */
  async hydrate(): Promise<void> {
    this.retiredCache = await this.store.getRetiredPlacementIds(this.userId);
    this.suppressedCache = await this.store.getSuppressedPlacements(this.userId);
  }

  /**
   * Clear all impression history for this user.
   */
  async reset(): Promise<void> {
    await this.store.clear(this.userId);
    this.retiredCache = new Set();
    this.suppressedCache = new Map();
  }

  /**
   * Switch user identity — clears caches and points at a new user.
   */
  setUserId(userId: string): void {
    this.userId = userId;
    this.retiredCache = null;
    this.suppressedCache = null;
  }

  /* ------------------------------------------------------------------ */
  /*  Internal                                                           */
  /* ------------------------------------------------------------------ */

  private async appendRecord(
    placementId: string,
    outcome: ImpressionOutcome,
    payloadId?: string,
    surfaceTemplateId?: string,
    metadata?: Record<string, unknown>,
  ): Promise<void> {
    const record: ImpressionRecord = {
      placementId,
      outcome,
      occurredAt: new Date().toISOString(),
      ...(payloadId ? { payloadId } : {}),
      ...(surfaceTemplateId ? { surfaceTemplateId } : {}),
      ...(metadata ? { metadata } : {}),
    };
    await this.store.append(this.userId, record);
  }

  private retireInCache(placementId: string): void {
    if (!this.retiredCache) {
      this.retiredCache = new Set();
    }
    this.retiredCache.add(placementId);
  }

  private suppressInCache(placementId: string, suppressUntil: string): void {
    if (!this.suppressedCache) {
      this.suppressedCache = new Map();
    }
    this.suppressedCache.set(placementId, suppressUntil);
  }
}
