/**
 * Environment schemas — ephemeral environments for configuration branching.
 *
 * Environments are analogous to git branches:
 *  • "production" always exists and is the default. It cannot be deleted.
 *  • Developers can create feature/staging environments that clone
 *    a point-in-time snapshot from another environment (like `git checkout -b`).
 *  • Changes in an environment are isolated until explicitly promoted
 *    (merged) into another environment.
 *  • Protected environments can require approval before changes deploy.
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields, NameField, HandleField, DescriptionField, MetadataField, NullableDatetimeField } from '../common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../classification';
import { ErrorEnvelope, ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../openapi/helpers';

const { Unrestricted } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal } = SchemaExposure;

// ── Environment status ───────────────────────────────────────────────────────

export const EnvironmentStatusSchema =
  z.enum(['active', 'archived', 'locked'])
    .meta({ id: 'EnvironmentStatus', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Environment ──────────────────────────────────────────────────────────────

export const EnvironmentSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    name: (NameField).meta(Unrestricted),
    handle: (HandleField).meta(Unrestricted),
    description: (DescriptionField).meta(Unrestricted),
    is_production: (z.boolean().default(false)).meta({ ...Unrestricted, readOnly: true }),
    status: (EnvironmentStatusSchema.default('active')).meta(Unrestricted),
    // Branching lineage
    cloned_from_environment_id: (z.string().nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    cloned_at: (NullableDatetimeField).meta({ ...Unrestricted, readOnly: true }),
    cloned_at_sequence: (z.number().int().min(0).nullable().default(null)).meta({ ...Unrestricted, readOnly: true }),
    // Protection settings (analogous to protected branches)
    requires_approval: (z.boolean().default(false)).meta(Unrestricted),
    auto_deploy_on_approval: (z.boolean().default(false)).meta(Unrestricted),
    // Audit
    created_by: (z.string().optional()).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'Environment', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Promotion request (environment → environment merge) ──────────────────────

export const EnvironmentPromotionRequestSchema =
  z.object({
    source_environment_id: z.string().min(1),
    target_environment_id: z.string().min(1),
    change_set_ids: z.array(z.string()).optional(),
    strategy: z.enum(['all_current', 'selected_changesets']).default('all_current'),
  })
    .meta({ id: 'EnvironmentPromotionRequest', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const environmentPaths: ZodOpenApiPathsObject = {
  '/api/environments': {
    get: operation({
      operationId: 'listEnvironments',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List environments',
      tags: ['environments'],
      responses: { '200': { description: 'Environment list', content: { 'application/json': { schema: ListEnvelope(EnvironmentSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'list' } },
    }),
    post: operation({
      operationId: 'createEnvironment',
      summary: 'Create environment (optionally cloned from another)',
      tags: ['environments'],
      requestBody: { required: true, content: { 'application/json': { schema: z.object({
        name: z.string().min(1).max(200),
        handle: z.string().min(1).max(100),
        description: z.string().max(500).optional(),
        clone_from_environment_id: z.string().optional(),
        requires_approval: z.boolean().optional(),
      }) } } },
      responses: {
        '201': { description: 'Created', content: { 'application/json': { schema: EnvironmentSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'create' } },
    }),
  },
  '/api/environments/{environmentId}': {
    get: operation({
      operationId: 'getEnvironment',
      requestParams: { path: z.object({ environmentId: z.string() }) },
      summary: 'Get environment by ID',
      tags: ['environments'],
      responses: { '200': { description: 'Environment', content: { 'application/json': { schema: EnvironmentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'get' } },
    }),
    patch: operation({
      operationId: 'updateEnvironment',
      requestParams: { path: z.object({ environmentId: z.string() }) },
      summary: 'Update environment settings',
      tags: ['environments'],
      requestBody: { required: true, content: { 'application/json': { schema: EnvironmentSchema.partial() } } },
      responses: { '200': { description: 'Updated', content: { 'application/json': { schema: EnvironmentSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'update' } },
    }),
  },
  '/api/environments/{environmentId}/archive': {
    post: operation({
      operationId: 'archiveEnvironment',
      requestParams: { path: z.object({ environmentId: z.string() }) },
      summary: 'Archive environment (production cannot be archived)',
      tags: ['environments'],
      responses: {
        '200': { description: 'Archived', content: { 'application/json': { schema: EnvironmentSchema } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'update' } },
    }),
  },
  '/api/environments/promote': {
    post: operation({
      operationId: 'promoteEnvironment',
      summary: 'Promote (merge) changes from one environment to another',
      tags: ['environments'],
      requestBody: { required: true, content: { 'application/json': { schema: EnvironmentPromotionRequestSchema } } },
      responses: {
        '200': { description: 'Promotion result', content: { 'application/json': { schema: z.object({
          promoted_count: z.number().int(),
          conflict_count: z.number().int(),
          conflicts: z.array(z.object({
            canonical_id: z.string(),
            resource_type: z.string(),
            source_sequence: z.number().int(),
            target_sequence: z.number().int(),
          })),
        }) } } },
        default: { description: 'Error', content: { 'application/json': { schema: ErrorEnvelope } } },
      },
      'x-revturbine-operation': { exposure: 'internal', resource: 'environments', persistence: { table: 'environments', mode: 'promote' } },
    }),
  },
};
