/**
 * UI schemas — Zod definitions for user-scoped UI preferences and themes.
 */
import { z } from 'zod';
import { IdField, TimestampFields } from '../../core/common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
  toWritableSchema,
} from '../../core/classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../../core/openapi/helpers';

const { Unrestricted, Pii } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal, External } = SchemaExposure;

export const ThemeSchema = 
  z.object({
    id: (z.string().min(1)).meta({ ...Unrestricted, readOnly: true }),
    name: (z.string().min(1).max(120)).meta(Unrestricted),
    mode: (z.enum(['light', 'dark', 'system']).default('system')).meta(Unrestricted),
    tokens: (z.record(z.string(), z.string()).default({})).meta(Unrestricted),
  })
    .meta({
      id: 'Theme',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': External,
    }
);

export const UiPreferenceSchema = 
  IdField.merge(TimestampFields).extend({
    user_id: (z.string().min(1)).meta(Pii),
    scope: (z.string().min(1)).meta(Unrestricted),
    preferences: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
  })
    .meta({
      id: 'UiPreference',
      'x-revturbine-schema-persistence': Persisted,
      'x-revturbine-schema-exposure': Internal,
    }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const uiPreferencePaths: ZodOpenApiPathsObject = {
  '/api/ui-preferences': {
    get: operation({
      operationId: 'listUiPreferences',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List UI preferences',
      tags: ['ui'],
      responses: {
        '200': {
          description: 'UI preferences list response',
          content: { 'application/json': { schema: ListEnvelope(UiPreferenceSchema) } },
        },
      },
      'x-revturbine-operation': {
        exposure: 'internal',
        resource: 'ui-preferences',
        persistence: { table: 'uiPreferences', mode: 'list' },
      },
    }),
    put: operation({
      operationId: 'upsertUiPreferences',
      summary: 'Upsert UI preferences',
      tags: ['ui'],
      requestBody: {
        required: true,
        content: { 'application/json': { schema: z.array(toWritableSchema(UiPreferenceSchema)) } },
      },
      responses: {
        '200': {
          description: 'UI preferences upsert response',
          content: { 'application/json': { schema: z.object({ updated: z.number().int().min(0) }) } },
        },
      },
      'x-revturbine-operation': {
        exposure: 'internal',
        resource: 'ui-preferences',
        persistence: { table: 'uiPreferences', mode: 'upsert', writeSchema: 'UiPreferenceSchema#writable' },
      },
    }),
  },
};
