/**
 * Runtime schemas — UserState, PresentationRecord, decision/entitlement eval logs.
 */
import { z } from 'zod';
import { IdField, TenantIdField, TimestampFields, MetadataField, NullableDatetimeField } from '../common';
import {
    DataClassification,
  SchemaExposure,
  SchemaPersistence,
} from '../classification';
import { ListEnvelope, operation, type ZodOpenApiPathsObject, ListQueryParamsSchema } from '../openapi/helpers';

const { Unrestricted, Pii } = DataClassification;
const { Persisted, Transient } = SchemaPersistence;
const { Internal, External } = SchemaExposure;

// ── User state (resolved at runtime for SDK) ─────────────────────────────────

export const UserStateSchema =
  z.object({
    customer_id: (z.string().min(1)).meta(Pii),
    plan_id: (z.string().nullable().default(null)).meta(Unrestricted),
    plan_handle: (z.string().nullable().default(null)).meta(Unrestricted),
    addon_ids: (z.array(z.string()).default([])).meta(Unrestricted),
    entitlements: (z.record(z.string(), z.unknown()).default({})).meta(Unrestricted),
    segment_values: (z.record(z.string(), z.array(z.string())).default({})).meta(Unrestricted),
    traits: (z.record(z.string(), z.unknown()).default({})).meta(Pii),
    overrides: (z.array(z.object({
      override_id: z.string(),
      override_type: z.string(),
      target_id: z.string(),
    })).default([])).meta(Unrestricted),
    trial: (z.object({
      is_in_trial: z.boolean(),
      rule_type: z.enum(['free_trial', 'reverse_trial']).nullable(),
      expires_at: z.string().datetime().nullable(),
      days_remaining: z.number().int().nullable(),
    }).nullable().default(null)).meta(Unrestricted),
    resolved_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
  })
    .meta({ id: 'UserState', 'x-revturbine-schema-persistence': Transient, 'x-revturbine-schema-exposure': External }
);

// ── Presentation record ──────────────────────────────────────────────────────

export const PresentationRecordSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    customer_id: (z.string().min(1)).meta(Pii),
    placement_id: (z.string().min(1)).meta(Unrestricted),
    payload_id: (z.string().nullable().default(null)).meta(Unrestricted),
    variant_id: (z.string().nullable().default(null)).meta(Unrestricted),
    surface_type: (z.string()).meta(Unrestricted),
    presented_at: (z.string().datetime()).meta({ ...Unrestricted, readOnly: true }),
    dismissed_at: (NullableDatetimeField).meta(Unrestricted),
    cta_clicked_at: (NullableDatetimeField).meta(Unrestricted),
    cta_action_type: (z.string().nullable().default(null)).meta(Unrestricted),
    converted: (z.boolean().default(false)).meta(Unrestricted),
    session_id: (z.string().optional()).meta(Unrestricted),
    metadata: (MetadataField).meta(Unrestricted),
  })
    .meta({ id: 'PresentationRecord', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Decision log ─────────────────────────────────────────────────────────────

export const DecisionLogSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    customer_id: (z.string().min(1)).meta(Pii),
    placement_id: (z.string().min(1)).meta(Unrestricted),
    decision: (z.enum(['show', 'suppress', 'defer'])).meta(Unrestricted),
    reason: (z.string().max(500)).meta(Unrestricted),
    matched_rules: (z.array(z.object({
      rule_id: z.string(),
      rule_type: z.string(),
      matched: z.boolean(),
    })).default([])).meta(Unrestricted),
    experiment_id: (z.string().nullable().default(null)).meta(Unrestricted),
    variant_id: (z.string().nullable().default(null)).meta(Unrestricted),
    latency_ms: (z.number().min(0).optional()).meta(Unrestricted),
  })
    .meta({ id: 'DecisionLog', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Entitlement eval log ─────────────────────────────────────────────────────

export const EntitlementEvalLogSchema =
  IdField.merge(TimestampFields).merge(TenantIdField).extend({
    customer_id: (z.string().min(1)).meta(Pii),
    entitlement_handle: (z.string().min(1)).meta(Unrestricted),
    entitlement_type: (z.string()).meta(Unrestricted),
    result: (z.enum(['granted', 'denied', 'limited', 'metered'])).meta(Unrestricted),
    current_usage: (z.number().nullable().default(null)).meta(Unrestricted),
    limit: (z.number().nullable().default(null)).meta(Unrestricted),
    source: (z.enum(['plan', 'addon', 'override', 'trial'])).meta(Unrestricted),
    source_id: (z.string().min(1)).meta(Unrestricted),
    latency_ms: (z.number().min(0).optional()).meta(Unrestricted),
  })
    .meta({ id: 'EntitlementEvalLog', 'x-revturbine-schema-persistence': Persisted, 'x-revturbine-schema-exposure': Internal }
);

// ── Operations ───────────────────────────────────────────────────────────────

export const runtimePaths: ZodOpenApiPathsObject = {
  '/api/runtime/user-state/{customerId}': {
    get: operation({
      operationId: 'getUserState',
      requestParams: { path: z.object({ customerId: z.string() }) },
      summary: 'Resolve full user state for customer',
      tags: ['runtime'],
      responses: { '200': { description: 'User state', content: { 'application/json': { schema: UserStateSchema } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'user-state', persistence: { table: 'userState', mode: 'get' } },
    }),
  },
  '/api/presentation-records': {
    get: operation({
      operationId: 'listPresentationRecords',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List presentation records',
      tags: ['runtime'],
      responses: { '200': { description: 'Presentation records', content: { 'application/json': { schema: ListEnvelope(PresentationRecordSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'presentation-records', persistence: { table: 'presentationRecords', mode: 'list' } },
    }),
  },
  '/api/decision-logs': {
    get: operation({
      operationId: 'listDecisionLogs',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List decision logs',
      tags: ['runtime'],
      responses: { '200': { description: 'Decision logs', content: { 'application/json': { schema: ListEnvelope(DecisionLogSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'decision-logs', persistence: { table: 'decisionLogs', mode: 'list' } },
    }),
  },
  '/api/entitlement-eval-logs': {
    get: operation({
      operationId: 'listEntitlementEvalLogs',
      requestParams: { query: ListQueryParamsSchema },
      summary: 'List entitlement evaluation logs',
      tags: ['runtime'],
      responses: { '200': { description: 'Entitlement eval logs', content: { 'application/json': { schema: ListEnvelope(EntitlementEvalLogSchema) } } } },
      'x-revturbine-operation': { exposure: 'internal', resource: 'entitlement-eval-logs', persistence: { table: 'entitlementEvalLogs', mode: 'list' } },
    }),
  },
};
