/**
 * Impression history types.
 *
 * Tracks placement impressions and terminal interactions (dismiss, click-through,
 * suppress) so the decision engine can permanently exclude placements the user
 * has already acted on.
 */

/* ------------------------------------------------------------------ */
/*  Interaction outcome                                                */
/* ------------------------------------------------------------------ */

/**
 * Interaction outcomes tracked by the impression history system.
 *
 * - `'impressed'`    — the placement was shown to the user.
 * - `'dismissed'`    — user explicitly closed the placement (permanent).
 * - `'clicked_thru'` — user clicked the CTA (permanent).
 * - `'suppressed'`   — system or admin suppressed the placement (time-based).
 */
export type ImpressionOutcome =
  | 'impressed'
  | 'dismissed'
  | 'clicked_thru'
  | 'suppressed';

/**
 * Outcomes that **permanently** prevent a placement from being shown again.
 * `suppressed` is intentionally excluded — it uses a configurable time window.
 */
export const TERMINAL_OUTCOMES: ReadonlySet<ImpressionOutcome> = new Set([
  'dismissed',
  'clicked_thru',
]);

/** Default suppression duration: 24 hours (in milliseconds). */
export const DEFAULT_SUPPRESSION_MS = 24 * 60 * 60 * 1000;

/* ------------------------------------------------------------------ */
/*  Impression record                                                  */
/* ------------------------------------------------------------------ */

/**
 * A single impression/interaction history record.
 */
export interface ImpressionRecord {
  /** Placement config ID (e.g. `'pl_gate_export'`). */
  placementId: string;
  /** Payload ID that was rendered, if available. */
  payloadId?: string;
  /** Surface template that was rendered (e.g. `'modal_overlay'`). */
  surfaceTemplateId?: string;
  /** What happened. */
  outcome: ImpressionOutcome;
  /** ISO-8601 timestamp of when the interaction occurred. */
  occurredAt: string;
  /** Arbitrary metadata (CTA type, surface slot ID, etc.). */
  metadata?: Record<string, unknown>;
}

/* ------------------------------------------------------------------ */
/*  Query types                                                        */
/* ------------------------------------------------------------------ */

export interface ImpressionQuery {
  /** Filter by placement ID(s). */
  placementIds?: string[];
  /** Filter by outcome(s). */
  outcomes?: ImpressionOutcome[];
  /** Only records after this ISO timestamp. */
  since?: string;
}

/* ------------------------------------------------------------------ */
/*  Store interface                                                    */
/* ------------------------------------------------------------------ */

/**
 * Pluggable persistence backend for impression history.
 *
 * Implementations:
 * - `InMemoryImpressionStore`   — ephemeral, in-process (default).
 * - `StorageImpressionStore`    — backed by RevTurbineStorage (localStorage/session).
 * - `DrizzleImpressionStore`    — Postgres table via Drizzle.
 * - Custom: any object conforming to this interface.
 */
export interface ImpressionHistoryStore {
  /** Append a record. */
  append(userId: string, record: ImpressionRecord): void | Promise<void>;

  /**
   * Query records for a user.
   * Returns records matching the query, most recent first.
   */
  query(userId: string, query?: ImpressionQuery): ImpressionRecord[] | Promise<ImpressionRecord[]>;

  /**
   * Return the set of placement IDs that have a terminal outcome
   * for this user (dismissed / clicked_thru).
   *
   * This is the hot-path check used by the resolver.
   */
  getRetiredPlacementIds(userId: string): Set<string> | Promise<Set<string>>;

  /**
   * Return a map of placement IDs → `suppressUntil` ISO timestamps
   * for placements with active suppression windows.
   */
  getSuppressedPlacements(userId: string): Map<string, string> | Promise<Map<string, string>>;

  /** Remove all records for a user. */
  clear(userId: string): void | Promise<void>;
}
